response:
To set up Route 53 query logging, we need to configure a Route 53 Hosted Zone, a CloudWatch Log Group, and a CloudWatch Logs Resource Policy that allows the Route 53 service to publish logs. 

Note: Route 53 query logging for public hosted zones requires the CloudWatch Log Group to be located in the `us-east-1` (N. Virginia) region.

```hcl
# AWS Provider configuration (Required: us-east-1 for Route 53 Query Logging)
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "example.com"

  tags = {
    Name = "primary-hosted-zone"
  }
}

# 2. Create the CloudWatch Log Group
# The name is set to "aws_route53_example_com" as requested
resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "aws_route53_example_com"
  retention_in_days = 30
}

# 3. Create the CloudWatch Logs Resource Policy
# This allows Route 53 to write log events to CloudWatch
data "aws_iam_policy_document" "route53_query_logging_policy_doc" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["${aws_cloudwatch_log_group.aws_route53_example_com.arn}:*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_document = data.aws_iam_policy_document.route53_query_logging_policy_doc.json
  policy_name     = "route53-query-logging-policy"
}

# 4. Set up the Route 53 Query Logging
# This resource links the hosted zone to the log group
resource "aws_route53_query_log" "primary_query_log" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53_query_logging_policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}
```

