response:
To set up a Route 53 hosted zone association, we need a Private Hosted Zone and at least two VPCs. The `aws_route53_zone` resource creates the zone and associates it with the primary VPC, while the `aws_route53_zone_association` resource is used to link additional VPCs (even those in different regions or accounts) to that same private zone.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Primary VPC
resource "aws_vpc" "primary" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "primary-vpc"
  }
}

# 2. Create a Secondary VPC to associate with the hosted zone
resource "aws_vpc" "secondary" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "secondary-vpc"
  }
}

# 3. Create a Private Route 53 Hosted Zone
# Note: A private zone must be associated with at least one VPC during creation.
resource "aws_route53_zone" "private" {
  name = "internal.example.com"

  vpc {
    vpc_id = aws_vpc.primary.id
  }

  comment = "Private zone for internal infrastructure"
}

# 4. Create the Hosted Zone Association
# This resource associates the secondary VPC with the private zone created above.
resource "aws_route53_zone_association" "secondary_association" {
  zone_id = aws_route53_zone.private.zone_id
  vpc_id  = aws_vpc.secondary.id
}

# Output the Zone ID and Name Servers for reference
output "hosted_zone_id" {
  value       = aws_route53_zone.private.zone_id
  description = "The ID of the Private Hosted Zone"
}

output "associated_vpcs" {
  value       = [aws_vpc.primary.id, aws_vpc.secondary.id]
  description = "The IDs of the VPCs associated with the zone"
}
```

