# Terraform configuration for Split-Horizon DNS with Route 53 and RDS

provider "aws" {
  region = "us-east-1"
}

# --- Network Infrastructure ---

# VPC with DNS support enabled (required for Route 53 Private Hosted Zones)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Subnets in different Availability Zones for the DB Subnet Group
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# DB Subnet Group named "main"
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Main DB Subnet Group"
  }
}

# Security Group to allow database traffic
resource "aws_security_group" "rds_sg" {
  name   = "rds_sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- RDS Instances ---

# Internal RDS Instance (Private)
resource "aws_db_instance" "internal" {
  identifier           = "internal"
  allocated_storage    = 20
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  db_name              = "internaldb"
  username             = "admin"
  password             = "Password123!" # In production, use secrets management
  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible  = false
  skip_final_snapshot  = true
}

# Public RDS Instance (Public)
