response:
To set up a weighted DNS routing configuration using Route 53 for two RDS read replicas, we need to perform the following steps:
1.  **Network Setup**: Define a VPC and DB Subnet Group (required for RDS).
2.  **Primary Database**: Create the source RDS instance named "primary".
3.  **Read Replicas**: Create two read-replica instances named "replica-1" and "replica-2" following the primary.
4.  **Route 53 Hosted Zone**: Create a private hosted zone named "main".
5.  **Weighted Records**: Create two CNAME records sharing the same DNS name (e.g., `read-db.main`), each pointing to a different replica endpoint with a specific weight and unique set identifier.

Here is the complete Terraform configuration:

```hcl
# Terraform Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure for RDS
resource "aws_vpc" "main_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_db_subnet_group" "db_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
}

# 2. Primary DB Instance
resource "aws_db_instance" "primary" {
  identifier           = "primary"
  allocated_storage    = 20
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  username             = "admin"
  password             = "SecurePassword123" # In production, use secrets management
  db_subnet_group_name = aws_db_subnet_group.db_group.name
  skip_final_snapshot  = true
  backup_retention_period = 7 # Required for read replicas
}

# 3. Read Replica Instances
resource "aws_db_instance" "replica_1" {
  identifier          = "replica-1"
  replicate_source_db = aws_db_instance.primary.identifier
  instance_class      = "db.t3.micro"
  skip_final_snapshot = true
}

resource "aws_db_instance" "replica_2" {
  identifier          = "replica-2"
  replicate_source_db = aws_db_instance.primary.identifier
  instance_class      = "db.t3.micro"
  skip_final_snapshot = true
}

# 4. Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  name = "main.local"
  vpc {
    vpc_id = aws_vpc.main_vpc.id
  }
}

# 5. Weighted DNS Routing Records
# This record points to Replica 1 with 50% weight
resource "aws_route53_record" "replica_1_weighted" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "read-db.main.local"
  type    = "CNAME"
  ttl     = "60"

  weighted_routing_policy {
    weight = 50
  }

  set_identifier = "replica-1"
  records        = [aws_db_instance.replica_1.address]
}

# This record points to Replica 2 with 50% weight
resource "aws_route53_record" "replica_2_weighted" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "read-db.main.local"
  type    = "CNAME"
  ttl     = "60"

  weighted_routing_policy {
    weight = 50
  }

