To set up a pair of Elastic Beanstalk environments under a shared application with the specific IAM requirements, we will follow these steps:
1.  **IAM Role & Policy**: Create the `eb_ec2_role` with a trust policy for EC2 and attach the necessary AWS managed policies for Elastic Beanstalk functionality.
2.  **Instance Profile**: Create the `eb_ec2_profile` and associate it with the role.
3.  **Application**: Define the `my_application` Elastic Beanstalk application.
4.  **Environments**: Create two environments (`env-a` and `env-b`) associated with the application, ensuring the `IamInstanceProfile` setting is configured to use the profile we created.

```hcl
# Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for EC2 instances in Elastic Beanstalk
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach standard Elastic Beanstalk policies to the role
resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_worker_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "eb_multicontainer_docker" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

# 2. IAM Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 3. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_application" {
  name        = "my_application"
  description = "Shared application for multiple environments"
}

# 4. Elastic Beanstalk Environments
# Environment A
resource "aws_elastic_beanstalk_environment" "env_a" {
  name                = "my-env-a"
  application         = aws_elastic_beanstalk_application.my_application.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.1 running Docker"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
