# --- Route 53 Geolocation Configuration ---

variable "domain_name" {
  description = "The root domain name for the application"
  type        = string
  default     = "example.com"
}

resource "aws_route53_zone" "main" {
  name = var.domain_name
}

# Record for North America users -> US West
resource "aws_route53_record" "us_geo" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.${var.domain_name}"
  type    = "CNAME"
  ttl     = "300"

  geolocation_routing_policy {
    continent = "NA"
  }

  set_identifier = "us-west-endpoint"
  records        = [aws_elastic_beanstalk_environment.us_west.cname]
}

# Record for Europe users -> EU Central
resource "aws_route53_record" "eu_geo" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.${var.domain_name}"
  type    = "CNAME"
  ttl     = "300"

  geolocation_routing_policy {
    continent = "EU"
  }

  set_identifier = "eu-central-endpoint"
  records        = [aws_elastic_beanstalk_environment.eu_central.cname]
}

# Default Record (Fallback for other regions) -> US West
resource "aws_route53_record" "default_geo" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.${var.domain_name}"
  type    = "CNAME"
  ttl     = "300"

  geolocation_routing_policy {
    country = "*"
  }

  set_identifier = "default-endpoint"
  records        = [aws_elastic_beanstalk_environment.us_west.cname]
}

