# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role and Instance Profile for Elastic Beanstalk
resource "aws_iam_role" "eb_role" {
  name = "ec2_eb_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_worker_tier" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "eb_multicontainer" {
  role       = aws_iam_role.eb_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.eb_role.name
}

# 2. RDS Database Instance
resource "aws_db_instance" "shared_db" {
  identifier           = "eb-blue-green-db"
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "postgres"
  engine_version       = "14"
  instance_class       = "db.t3.micro"
  db_name              = "my_db"
  username             = "dbadmin"
  password             = "SuperSecretPass123" # In production, use secrets manager or variables
  parameter_group_name = "default.postgres14"
  skip_final_snapshot  = true
  publicly_accessible  = false
}

# 3. Database Snapshot (Created before deployment/update)
resource "aws_db_snapshot" "pre_deployment_snapshot" {
  db_instance_identifier = aws_db_instance.shared_db.id
  db_snapshot_identifier = "pre-deploy-snapshot-${formatdate("YYYYMMDDhhmm", timestamp())}"

  lifecycle {
    ignore_changes = [db_snapshot_identifier]
  }
}

# 4. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-blue-green-app"
  description = "Application for Blue-Green Deployment"
}

# Common environment settings for Blue and Green
locals {
  eb_settings = [
    {
      namespace = "aws:autoscaling:launchconfiguration"
      name      = "IamInstanceProfile"
      value     = aws_iam_instance_profile.eb_instance_profile.name
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_HOSTNAME"
      value     = aws_db_instance.shared_db.address
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_NAME"
      value     = "my_db"
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_USERNAME"
      value     = aws_db_instance.shared_db.username
    },
    {
      namespace = "aws:elasticbeanstalk:application:environment"
      name      = "DB_PASSWORD"
      value     = aws_db_instance.shared_db.password
    }
  ]
}

# 5. Elastic Beanstalk Environments
resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "blue-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.5.8 running Python 3.8"

  dynamic "setting" {
    for_each = local.eb_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "green-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.5.8 running Python 3.8"

  dynamic "setting" {
    for_each = local.eb_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }

  # Ensure the Blue environment exists or update order is managed
  depends_on = [aws_db_instance.shared_db]
}

# Output URLs for DNS swap
output "blue_url" {
  value = aws_elastic_beanstalk_environment.blue_env.cname
}

output "green_url" {
  value = aws_elastic_beanstalk_environment.green_env.cname
}

