  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkMulticontainerDocker"
}

resource "aws_iam_instance_profile" "eb_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_role.name
}

# 2. RDS Database Instance
resource "aws_db_instance" "default" {
  allocated_storage    = 20
  identifier           = "eb-rds-database"
  db_name              = "my_db1"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "SecurePassword123!" # In production, use a secret manager or variables
  skip_final_snapshot  = true
  publicly_accessible  = false
}

# 3. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-eb-application"
  description = "Application with Auto Scaling and RDS"
}

# 4. Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "env" {
  name                = "my-eb-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.1 running Python 3.12"

  # Instance Profile Setting
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_profile.name
  }

  # Auto Scaling: Scaling Limits
  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "4"
  }

  # Auto Scaling: Trigger based on CPU Utilization
  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "MeasureName"
    value     = "CPUUtilization"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Statistic"
    value     = "Average"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Unit"
    value     = "Percent"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperThreshold"
    value     = "70" # Scale up if CPU > 70%
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerThreshold"
    value     = "30" # Scale down if CPU < 30%
  }

  # Database Connection Environment Variables
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_HOSTNAME"
    value     = aws_db_instance.default.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_DB_NAME"
    value     = aws_db_instance.default.db_name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_USERNAME"
    value     = aws_db_instance.default.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PASSWORD"
    value     = aws_db_instance.default.password
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "RDS_PORT"
    value     = "5432"
  }

  depends_on = [aws_db_instance.default]
}

# Outputs
output "eb_environment_url" {
  value = aws_elastic_beanstalk_environment.env.cname
}

output "rds_endpoint" {
  value = aws_db_instance.default.endpoint
}

