To set up this infrastructure, we will define the AWS provider, create the VPC and networking components, set up a security group, provision a shared RDS instance, and then configure the Elastic Beanstalk application and two environments with the necessary environment variables to connect to the database.

Here is the complete Terraform configuration:

```hcl
# Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. VPC Configuration
resource "aws_vpc" "eb_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "eb_vpc"
  }
}

# 2. Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.eb_vpc.id

  tags = {
    Name = "eb_igw"
  }
}

# 3. Public Subnets
resource "aws_subnet" "eb_subnet_public_1" {
  vpc_id                  = aws_vpc.eb_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "eb_subnet_public_1"
  }
}

resource "aws_subnet" "eb_subnet_public_2" {
  vpc_id                  = aws_vpc.eb_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "eb_subnet_public_2"
  }
}

# 4. Route Table and Associations
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.eb_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "eb_public_rt"
  }
}

resource "aws_route_table_association" "a1" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "a2" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.public_rt.id
}

# 5. Security Group for EB Environments
resource "aws_security_group" "eb_env_sg" {
  name        = "eb_env_sg"
  description = "Security group for Elastic Beanstalk environments"
  vpc_id      = aws_vpc.eb_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "eb_env_sg"
  }
}

# 6. RDS Shared Instance
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "eb_rds_subnet_group"
  subnet_ids = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]
}

resource "aws_security_group" "rds_sg" {
  name   = "shared_rds_sg"
  vpc_id = aws_vpc.eb_vpc.id

  ingress {
    from_port       = 5432
    to_port         = 5432
    protocol        = "tcp"
    security_groups = [aws_security_group.eb_env_sg.id]
  }
}

resource "aws_db_instance" "shared_rds" {
  identifier           = "shared-rds"
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro"
  db_name              = "shared_db"
  username             = "dbadmin"
  password             = "Password123!" # In production, use secret managers
  db_subnet_group_name = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot  = true
}

# 7. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "eb_shared_app"
  description = "Application for multiple environments"
}

# IAM Role for EB EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "eb_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "eb_instance_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# 8. Elastic Beanstalk Environments
locals {
  eb_settings = [
    { namespace = "aws:ec2:vpc", name = "VPCId", value = aws_vpc.eb_vpc.id },
    { namespace = "aws:ec2:vpc", name = "Subnets", value = join(",", [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]) },
    { namespace = "aws:ec2:vpc", name = "AssociatePublicIpAddress", value = "true" },
    { namespace = "aws:autoscaling:launchconfiguration", name = "SecurityGroups", value = aws_security_group.eb_env_sg.id },
    { namespace = "aws:autoscaling:launchconfiguration", name = "IamInstanceProfile", value = aws_iam_instance_profile.eb_instance_profile.name },
    { namespace = "aws:elasticbeanstalk:application:environment", name = "DB_HOST", value = aws_db_instance.shared_rds.address },
    { namespace = "aws:elasticbeanstalk:application:environment", name = "DB_NAME", value = aws_db_instance.shared_rds.db_name },
    { namespace = "aws:elasticbeanstalk:application:environment", name = "DB_USER", value = aws_db_instance.shared_rds.username },
    { namespace = "aws:elasticbeanstalk:application:environment", name = "DB_PASS", value = "Password123!" }
  ]
}

resource "aws_elastic_beanstalk_environment" "env_1" {
  name                = "eb-env-1"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v6.1.2 running Node.js 20"

  dynamic "setting" {
    for_each = local.eb_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}

resource "aws_elastic_beanstalk_environment" "env_2" {
  name                = "eb-env-2"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v6.1.2 running Node.js 20"

  dynamic "setting" {
    for_each = local.eb_settings
    content {
      namespace = setting.value.namespace
      name      = setting.value.name
      value     = setting.value.value
    }
  }
}
