  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example.com"
  type    = "A"
  ttl     = 300

  # The list of IPv4 addresses to point the domain to
  records = ["1.2.3.4"]
}

# Output the FQDN for verification
