# Terraform configuration to create a Route 53 TXT record for domain verification

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Look up the existing hosted zone by name
# Note: Route 53 zone names usually end with a dot (e.g., example.com.)
data "aws_route53_zone" "selected" {
  name         = "example.com" # Assuming the full domain based on the request "example"
  private_zone = false
}

# 2. Create the TXT record for domain ownership verification
resource "aws_route53_record" "txt_verification" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = data.aws_route53_zone.selected.name
  type    = "TXT"
  ttl     = 300

  # The record value is provided as a list of strings
  records = [
    "passwordpassword"
  ]
}

