To configure a PTR (Pointer) record for reverse DNS in AWS Route 53, we need to create a hosted zone with a name following the `in-addr.arpa` (for IPv4) or `ip6.arpa` (for IPv6) convention. In this example, I will assume a standard private reverse lookup zone for a CIDR block (e.g., `10.0.0.0/24`) and map the specific IP `10.0.0.15` to the hostname provided.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Reverse DNS Hosted Zone
# For IPv4, the zone name follows the [network-prefix].in-addr.arpa format.
# Here we use "0.0.10.in-addr.arpa" for the 10.0.0.x subnet.
resource "aws_route53_zone" "reverse_zone" {
  name          = "0.0.10.in-addr.arpa"
  comment       = "Reverse DNS zone for 10.0.0.0/24"
  force_destroy = false

  tags = {
    Name = "reverse_zone"
  }
}

# 2. Configure the PTR Record
# The record name is the last octet of the IP address (e.g., 15 for 10.0.0.15).
# The value (records) is the FQDN "host.example53.com".
resource "aws_route53_record" "ptr_entry" {
  zone_id = aws_route53_zone.reverse_zone.zone_id
  name    = "15.0.0.10.in-addr.arpa"
  type    = "PTR"
  ttl     = "300"
  records = ["host.example53.com."]
}

# Output the Zone ID and Name for verification
output "reverse_zone_id" {
  value = aws_route53_zone.reverse_zone.zone_id
}

output "ptr_record_fqdn" {
  value = aws_route53_record.ptr_entry.fqdn
}
