# Configure AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Shared Database Layer
resource "aws_db_subnet_group" "db_group" {
  name       = "main-db-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
}

resource "aws_security_group" "db_sg" {
  name   = "db-sg"
  vpc_id = aws_vpc.main.id
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

resource "aws_db_instance" "shared_db" {
  identifier           = "shared-app-db"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  db_name              = "myapp_db"
  username             = "admin"
  password             = "securepassword123"
  db_subnet_group_name = aws_db_subnet_group.db_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  skip_final_snapshot  = true
}

# Instance Profile for EC2
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.app_role.name
}

resource "aws_iam_role" "app_role" {
  name = "app_iam_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}

# Application Instances: Blue Environment
resource "aws_instance" "blue" {
  ami                  = "ami-0c101f26f147fa7fd" # Amazon Linux 2
  instance_type        = "t3.micro"
  subnet_id            = aws_subnet.subnet_a.id
  iam_instance_profile = aws_iam_instance_profile.eb_ec2_profile.name
  tags                 = { Name = "blue-env" }
}

# Application Instances: Green Environment
resource "aws_instance" "green" {
  ami                  = "ami-0c101f26f147fa7fd"
  instance_type        = "t3.micro"
  subnet_id            = aws_subnet.subnet_b.id
  iam_instance_profile = aws_iam_instance_profile.eb_ec2_profile.name
  tags                 = { Name = "green-env" }
}

# Route 53 Health Checks
resource "aws_route53_health_check" "blue_health" {
  ip_address        = aws_instance.blue.public_ip
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = "3"
  request_interval  = "30"
}

resource "aws_route53_health_check" "green_health" {
  ip_address        = aws_instance.green.public_ip
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = "3"
  request_interval  = "30"
}

# Route 53 Zone and DNS Records
resource "aws_route53_zone" "primary" {
  name = "myapp.example.com"
}

# Failover Routing - Primary (Blue)
resource "aws_route53_record" "blue_dns" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.myapp.example.com"
  type    = "A"
  ttl     = "60"

  failover_routing_policy {
    type = "PRIMARY"
  }

  set_identifier   = "blue"
  health_check_id  = aws_route53_health_check.blue_health.id
  records          = [aws_instance.blue.public_ip]
}

# Failover Routing - Secondary (Green)
resource "aws_route53_record" "green_dns" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.myapp.example.com"
  type    = "A"
  ttl     = "60"

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier   = "green"
  health_check_id  = aws_route53_health_check.green_health.id
  records          = [aws_instance.green.public_ip]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "elastic_beanstalk_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "elastic_beanstalk_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Create the RDS database used by both the blue and green environments
resource "aws_db_instance" "myapp_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  username             = "myappuser"
  password             = "mysecurepassword"
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true
}

# Create an Elastic Beanstalk application
resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "my-app"
  description = "My application"
}

# Blue environment
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "my-app-blue"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  # Example setting to connect to the RDS instance
  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.myapp_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.myapp_db.password
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Green environment (new version)
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "my-app-green"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.myapp_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.myapp_db.password
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# DNS setup with Route 53
resource "aws_route53_zone" "myapp_zone" {
  name = "myapp.com"
}

# Health check for blue environment
resource "aws_route53_health_check" "blue" {
  fqdn              = aws_elastic_beanstalk_environment.blue.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
}

# Health check for green environment
resource "aws_route53_health_check" "green" {
  fqdn              = aws_elastic_beanstalk_environment.green.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
}

# Record set for the blue environment
resource "aws_route53_record" "blue" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "blue.myapp.com"
  type    = "CNAME"
  ttl     = "5"
  records = [aws_elastic_beanstalk_environment.blue.cname]
  set_identifier = "BlueEnv"
  failover_routing_policy {
    type = "PRIMARY"
  }
  health_check_id = aws_route53_health_check.blue.id
}

# Record set for the green environment using CNAME
resource "aws_route53_record" "green" {
  zone_id = aws_route53_zone.myapp_zone.zone_id
  name    = "green.myapp.com"
  type    = "CNAME"
  ttl     = "5"
  records = [aws_elastic_beanstalk_environment.green.cname]
  set_identifier = "greenEnv"
  failover_routing_policy {
    type = "SECONDARY"
  }
  health_check_id = aws_route53_health_check.green.id
}

response:
To implement a blue-green deployment with Route 53 failover routing and a shared RDS backend, we need to define the networking, the shared database, the two application environments (blue and green), and the DNS records with health checks.

The following configuration creates a VPC, an RDS instance, two sets of EC2 instances representing the environments, and Route 53 Failover records that route traffic to "Blue" as primary and "Green" as secondary based on health check status.

```hcl
# Configure AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Shared Database Layer
resource "aws_db_subnet_group" "db_group" {
  name       = "main-db-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
}

resource "aws_security_group" "db_sg" {
  name   = "db-sg"
  vpc_id = aws_vpc.main.id
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

resource "aws_db_instance" "shared_db" {
  identifier           = "shared-app-db"
  allocated_storage    = 20
  engine               = "postgres"
  instance_class       = "db.t3.micro"
  db_name              = "myapp_db"
  username             = "admin"
  password             = "securepassword123"
  db_subnet_group_name = aws_db_subnet_group.db_group.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  skip_final_snapshot  = true
}

# Instance Profile for EC2
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.app_role.name
}

resource "aws_iam_role" "app_role" {
  name = "app_iam_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "ec2.amazonaws.com" }
    }]
  })
}

# Application Instances: Blue Environment
resource "aws_instance" "blue" {
  ami                  = "ami-0c101f26f147fa7fd" # Amazon Linux 2
  instance_type        = "t3.micro"
  subnet_id            = aws_subnet.subnet_a.id
  iam_instance_profile = aws_iam_instance_profile.eb_ec2_profile.name
  tags                 = { Name = "blue-env" }
}

# Application Instances: Green Environment
resource "aws_instance" "green" {
  ami                  = "ami-0c101f26f147fa7fd"
  instance_type        = "t3.micro"
  subnet_id            = aws_subnet.subnet_b.id
  iam_instance_profile = aws_iam_instance_profile.eb_ec2_profile.name
  tags                 = { Name = "green-env" }
}

# Route 53 Health Checks
resource "aws_route53_health_check" "blue_health" {
  ip_address        = aws_instance.blue.public_ip
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = "3"
  request_interval  = "30"
}

resource "aws_route53_health_check" "green_health" {
  ip_address        = aws_instance.green.public_ip
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = "3"
  request_interval  = "30"
}

# Route 53 Zone and DNS Records
resource "aws_route53_zone" "primary" {
  name = "myapp.example.com"
}

# Failover Routing - Primary (Blue)
resource "aws_route53_record" "blue_dns" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.myapp.example.com"
  type    = "A"
  ttl     = "60"

  failover_routing_policy {
    type = "PRIMARY"
  }

  set_identifier   = "blue"
  health_check_id  = aws_route53_health_check.blue_health.id
  records          = [aws_instance.blue.public_ip]
}

# Failover Routing - Secondary (Green)
resource "aws_route53_record" "green_dns" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.myapp.example.com"
  type    = "A"
  ttl     = "60"

  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier   = "green"
  health_check_id  = aws_route53_health_check.green_health.id
  records          = [aws_instance.green.public_ip]
}
