  name = "aws-elasticbeanstalk-instance-profile"
  role = aws_iam_role.eb_instance_role.name
}

# 2. Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name        = "my-tf-beanstalk-app"
  description = "A scaffold for a Beanstalk application via Terraform"
}

# 3. Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "env" {
  name                = "my-env-prod"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.10 running Python 3.11" # Example platform

  # 4. Configuration Settings
  # Use namespace "aws:autoscaling:launchconfiguration" for instance settings
  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  # Capacity settings
  setting {
    namespace = "aws:autoscaling:asg"
