response:
To set up an AWS CodeBuild project with a GitHub source and the necessary IAM permissions, we need to create the IAM role, attach a policy that allows logging to CloudWatch and interaction with S3, and then define the `aws_codebuild_project` resource itself.

```hcl
# Configure the GitHub provider or AWS provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "example-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Create IAM Policy for CodeBuild (Logs and S3)
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = ["*"]
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning",
          "s3:PutObject"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# 3. Create the CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-github-project"
  description   = "Terraform managed CodeBuild project with GitHub source"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_TYPE"
      value = "development"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-username/your-repo.git"
    git_clone_depth = 1

    buildspec = <<EOF
version: 0.2
phases:
  install:
    commands:
      - echo Installing dependencies...
  build:
    commands:
      - echo Build started on `date`
      - echo Hello from CodeBuild
  post_build:
    commands:
      - echo Build completed on `date`
EOF
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = "log-group"
      stream_name = "log-stream"
    }
  }

  tags = {
    Environment = "Test"
  }
}
```

