response:
To create an AWS CodeBuild project with the specified requirements, we need to define the CodeBuild project itself, an IAM role with the necessary trust relationships and permissions, and the specific configurations for GitHub source integration, artifacts, and caching.

Steps:
1. **IAM Role**: Create a service role that allows CodeBuild to interact with AWS services (Logs, S3).
2. **IAM Policy**: Attach a policy to the role allowing it to write logs and manage artifact buckets.
3. **S3 Bucket**: Create a bucket to store build artifacts and cache.
4. **CodeBuild Project**: Define the environment (compute type, image), source (GitHub URL), artifacts (S3), and cache (S3).

```hcl
# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild permissions
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = ["*"]
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.build_assets.arn,
          "${aws_s3_bucket.build_assets.arn}/*"
        ]
      }
    ]
  })
}

# S3 Bucket for Artifacts and Cache
resource "aws_s3_bucket" "build_assets" {
  bucket        = "my-terraform-codebuild-assets-bucket"
  force_destroy = true
}

# CodeBuild Project
resource "aws_codebuild_project" "github_project" {
  name          = "sample-github-project"
  description   = "Terraform managed CodeBuild project with GitHub source"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.build_assets.bucket
    name     = "build-output.zip"
    packaging = "ZIP"
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.build_assets.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_TYPE"
      value = "development"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-username/your-repo.git"
    git_clone_depth = 1

    git_submodules_config {
      fetch_submodules = true
    }
  }

  source_version = "main"

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}
