To create an AWS CodeBuild project, we need to define several interconnected resources:
1.  **IAM Role & Policy**: To grant CodeBuild permission to interact with AWS services (like CloudWatch for logs).
2.  **CodeBuild Project**: The core resource defining the environment, buildspec, source (GitHub), and logging configuration.

Here is the complete Terraform configuration:

```hcl
# Define the IAM Role for the CodeBuild Project
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Define the IAM Policy permissions (Logging and Base permissions)
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# Define the CodeBuild Project
resource "aws_codebuild_project" "github_project" {
  name          = "sample-github-project"
  description   = "Terraform managed CodeBuild project with GitHub source"
  build_timeout = 5
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV_TYPE"
      value = "development"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-username/your-repo.git"
    git_clone_depth = 1

    # Optional: Buildspec can be a file in repo or defined inline
    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo "Building project..."
            - date
    EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }

    s3_logs {
      status = "DISABLED"
    }
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}
```

