  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.build_artifacts.bucket
    name      = "primary-output"
    packaging = "ZIP"
  }

  # Defining Secondary Artifacts
  secondary_artifacts {
    artifact_identifier = "docs_output"
    type                = "S3"
    location            = aws_s3_bucket.build_artifacts.bucket
    path                = "documentation/"
    packaging           = "NONE"
  }

  secondary_artifacts {
    artifact_identifier = "test_reports"
    type                = "S3"
    location            = aws_s3_bucket.build_artifacts.bucket
    path                = "reports/"
    packaging           = "ZIP"
  }

