    # Example buildspec that references secondary artifacts
    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo "Building..."
            - mkdir -p build_output docs reports
            - touch build_output/app.js docs/readme.html reports/coverage.xml
      artifacts:
        files:
          - '**/*'
        base-directory: 'build_output'
        secondary-artifacts:
          docs_output:
            files:
              - '**/*'
            base-directory: 'docs'
          test_reports:
            files:
              - '**/*'
            base-directory: 'reports'
    EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Environment = "Dev"
    Project     = "TerraformAI"
  }
}

