response:
To create an AWS CodeBuild project with a service role and secondary artifacts, we need to define three main components: the IAM role with the necessary permissions to log to CloudWatch and access S3, an S3 bucket for artifact storage, and the `aws_codebuild_project` resource itself.

The configuration below ensures that the CodeBuild project is equipped with a primary source and secondary artifact locations, which is often used when a build needs to output files to multiple destinations or formats.

```hcl
# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for Build Artifacts
resource "aws_s3_bucket" "build_artifacts" {
  bucket        = "my-codebuild-artifacts-bucket-unique-12345"
  force_destroy = true
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild (Logging and S3 Access)
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.build_artifacts.arn,
          "${aws_s3_bucket.build_artifacts.arn}/*"
        ]
      }
    ]
  })
}

# CodeBuild Project Configuration
resource "aws_codebuild_project" "example" {
  name          = "my-web-app-build"
  description   = "Example build project with secondary artifacts"
  build_timeout = 5
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type      = "S3"
    location  = aws_s3_bucket.build_artifacts.bucket
    name      = "primary-output"
    packaging = "ZIP"
  }

  # Defining Secondary Artifacts
  secondary_artifacts {
    artifact_identifier = "docs_output"
    type                = "S3"
    location            = aws_s3_bucket.build_artifacts.bucket
    path                = "documentation/"
    packaging           = "NONE"
  }

  secondary_artifacts {
    artifact_identifier = "test_reports"
    type                = "S3"
    location            = aws_s3_bucket.build_artifacts.bucket
    path                = "reports/"
    packaging           = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/my-repo.git"
    git_clone_depth = 1

    # Example buildspec that references secondary artifacts
    buildspec = <<-EOF
      version: 0.2
      phases:
        build:
          commands:
            - echo "Building..."
            - mkdir -p build_output docs reports
            - touch build_output/app.js docs/readme.html reports/coverage.xml
      artifacts:
        files:
          - '**/*'
        base-directory: 'build_output'
        secondary-artifacts:
          docs_output:
            files:
              - '**/*'
            base-directory: 'docs'
          test_reports:
            files:
              - '**/*'
            base-directory: 'reports'
    EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "codebuild-log-stream"
    }
  }

  tags = {
    Environment = "Dev"
    Project     = "TerraformAI"
  }
}
