  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-batch-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# Standard policy for CodeBuild to write logs and manage batch builds
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Resource = ["*"]
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "codebuild:StartBuild",
          "codebuild:StopBuild",
          "codebuild:BatchGetBuilds"
        ]
      }
    ]
  })
}

# CodeBuild Project with Batch Configuration
resource "aws_codebuild_project" "example_batch_project" {
  name          = "example-batch-project"
  description   = "Terraform managed CodeBuild project with batch capabilities"
  build_timeout = "60"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENVIRONMENT"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/repo.git"
    git_clone_depth = 1

    # Ensuring we use a buildspec that supports batching
    buildspec = <<-EOF
      version: 0.2
      batch:
        fast-fail: false
        build-list:
          - identifier: build_one
            env:
              variables:
                BUILD_ID: "1"
          - identifier: build_two
            env:
              variables:
                BUILD_ID: "2"
      phases:
        build:
          commands:
            - echo Building $BUILD_ID
    EOF
  }

  # Batch Configuration Block
  build_batch_config {
    service_role    = aws_iam_role.codebuild_role.arn
    timeout_in_mins = 60

    # Options: BUILD_BATCH_LIST, BUILD_GRAPH, or BUILD_MATRIX
    combine_artifacts = false

    restrictions {
      maximum_builds_allowed = 5
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-log-group"
      stream_name = "batch-stream"
    }
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

