    packaging           = "ZIP"
    name                = "output-one.zip"
  }

  secondary_artifacts {
    artifact_identifier = "artifact_two"
    type                = "S3"
    location            = "my-build-bucket"
    packaging           = "ZIP"
    name                = "output-two.zip"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "PROJECT_ENVIRONMENT"
      value = "production"
    }

    environment_variable {
      name  = "BUILD_VERSION"
      value = "1.0.0"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/user/primary-repo.git"
    git_clone_depth = 1
  }

  # Secondary Sources (Require source_identifier)
  secondary_sources {
    source_identifier = "repo_lib"
    type              = "GITHUB"
