    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1

    sample_utterances = ["I would like to get {FlowerType} flower."]

    value_elicitation_prompt {
      message {
        content             = "What type of flower would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  slot {
    name                     = "PickupDate"
    description              = "Date of flower pickup"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.DATE"
    priority                 = 2

    value_elicitation_prompt {
      message {
        content             = "When would you like to pickup your flower?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, your {FlowerType} will be ready for pickup on {PickupDate}.  Does this sound okay?"
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  rejection_statement {
    message {
      content      = "Okay, I will not place your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "order_flowers" {
  name     = "OrderFlowers"
  description = "Bot to order flowers on the behalf of a user"
  locale   = "en-US"
  process_behavior = "BUILD"
  voice_id = "Salli"
  child_directed = false
  create_version = false
  detect_sentiment            = false
  idle_session_ttl_in_seconds = 600

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I am not able to assist at this time"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I didn't understand you, what would you like to do?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_flowers.name
    intent_version = aws_lex_intent.order_flowers.version
  }
}

response:
To build an AWS Lex (V2) chatbot using Terraform, we need to define several interconnected resources: the **Bot** itself, a **Locale** (language), **Intents**, **Slot Types**, and a **Bot Version**. 

The following configuration creates a basic "OrderFlowers" chatbot. It includes:
1.  An IAM role allowing Lex to log to CloudWatch.
2.  The Lex V2 Bot resource.
3.  A English (US) Locale.
4.  A "WelcomeIntent" with sample utterances.
5.  A "FulfillmentCodeHook" configuration (set to inactive for this basic example).

```hcl
# AWS Lex V2 Bot Configuration

# 1. IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-v2-flower-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_cloudwatch" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexFullAccess"
}

# 2. Lex V2 Bot
resource "aws_lexv2models_bot" "flower_bot" {
  name                        = "OrderFlowersBot"
  description                 = "A bot to help users order flowers"
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_bot_role.arn

  data_privacy {
    child_directed = false
  }
}

# 3. Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.flower_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40

  description = "English locale for OrderFlowers bot"
}

# 4. Intent: Welcome Intent
resource "aws_lexv2models_intent" "welcome_intent" {
  bot_id      = aws_lexv2models_bot.flower_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "WelcomeIntent"

  sample_utterance {
    utterance = "Hi"
  }
  sample_utterance {
    utterance = "Hello"
  }
  sample_utterance {
    utterance = "I want to order flowers"
  }

  initial_response_setting {
    initial_response {
      message_group {
        message {
          plain_text_message {
            value = "Welcome to the Flower Shop! How can I help you today?"
          }
        }
      }
    }
  }
}

# 5. Intent: Fallback Intent (Required for Lex V2)
resource "aws_lexv2models_intent" "fallback_intent" {
  bot_id      = aws_lexv2models_bot.flower_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"
}

# 6. Bot Version (Builds the bot)
resource "aws_lexv2models_bot_version" "flower_bot_v1" {
  bot_id      = aws_lexv2models_bot.flower_bot.id
  description = "Version 1 of the flower bot"

  # Ensure the intents are created before versioning
  depends_on = [
    aws_lexv2models_intent.welcome_intent,
    aws_lexv2models_intent.fallback_intent
  ]
}

# 7. Alias for the Bot
resource "aws_lexv2models_bot_alias" "prod_alias" {
  name        = "Production"
  bot_id      = aws_lexv2models_bot.flower_bot.id
  bot_version = aws_lexv2models_bot_version.flower_bot_v1.bot_version

  sentiment_analysis_settings {
    detect_sentiment = false
  }
}

output "bot_id" {
  value = aws_lexv2models_bot.flower_bot.id
}

output "bot_alias_id" {
  value = aws_lexv2models_bot_alias.prod_alias.bot_alias_id
}
```

