To build an AWS Lex (V2) bot, we need to define several components: the bot itself, a data locale (e.g., English US), an intent, and several slots within that intent. We also need an IAM role that allows Lex to execute.

The following configuration creates a "FlowerOrderingBot" with slots for "FlowerType" and "PickupDate".

```hcl
# Define the provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lex Bot
resource "aws_iam_role" "lex_role" {
  name = "lex-v2-flower-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# 2. The Lex V2 Bot
resource "aws_lexv2models_bot" "flower_bot" {
  name                        = "FlowerOrderingBot"
  description                 = "A bot to help users order flowers"
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_role.arn

  # Initial version/draft
  lifecycle {
    ignore_changes = [version]
  }
}

# 3. Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.flower_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# 4. Custom Slot Type (Flower Varieties)
resource "aws_lexv2models_slot_type" "flower_type" {
  bot_id      = aws_lexv2models_bot.flower_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
