provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_role" {
  name = "pizza_bot_lex_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# The Lex V2 Bot
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_role.arn
  data_privacy {
    child_directed = false
  }
}

# Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# Intent: OrderPizza
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want to order a pizza" }
  sample_utterance { utterance = "Can I get a {PizzaSize} pizza with {PizzaTopping}" }

  # Follow-up Prompt Logic (Confirmation Setting)
  confirmation_setting {
    active = true
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "Okay, I have a {PizzaSize} {PizzaTopping} pizza. Should I place the order?"
          }
        }
      }
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "No problem. Your order has been cancelled."
          }
        }
      }
    }
  }

  intent_closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Great! Your pizza is on the way."
          }
        }
      }
    }
  }
}

# Slot 1: Pizza Size
resource "aws_lexv2models_slot" "pizza_size" {
  name        = "PizzaSize"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id

  # Using built-in Amazon type
  slot_type_id = "AMAZON.AlphaNumeric" 

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What size pizza would you like? (Small, Medium, Large)"
          }
        }
      }
    }
  }
}

# Slot 2: Pizza Topping
resource "aws_lexv2models_slot" "pizza_topping" {
  name        = "PizzaTopping"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id

  slot_type_id = "AMAZON.AlphaNumeric"

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What topping would you like on your pizza?"
          }
        }
      }
    }
  }
}

# Fallback Intent (Required for a functional bot)
resource "aws_lexv2models_intent" "fallback" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"
}

