resource "aws_lex_intent" "OrderPizzaIntent" {
  name = "OrderPizzaIntent"
  create_version = true

  sample_utterances = [
    "I would like to pick up a pizza",
    "I would like to order some pizzas",
  ]

  slot {
    name = "PizzaType"
    description = "Type of pizza to order"
    priority = 1  # must be in [1, 100]
    slot_type = aws_lex_slot_type.PizzaType.name
    slot_type_version = aws_lex_slot_type.PizzaType.version
    slot_constraint = "Required"

    sample_utterances = ["I want a {PizzaType} pizza.", "A {PizzaType} pizza please."]

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content = "What type of pizza would you like to order?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content = "So, you would like to order a pizza. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
        content = "Sorry, I don't know how to help then"
        content_type = "PlainText"
      }
    }

  follow_up_prompt {
    prompt {
      max_attempts = 2
      message {
        content = "Would you like anything else with your order?"
        content_type = "PlainText"
      }
    }
    rejection_statement {
      message {
        content = "OK, Your pizza is on its way."
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

resource "aws_lex_slot_type" "PizzaType" {
  create_version = true
  description = "Types of pizza available to order"
  name = "PizzaTypes"
  enumeration_value {
    value = "Margherita"
  }
  enumeration_value {
    value = "Pepperoni"
  }
}

response:
To create an AWS Lex V2 Bot for pizza ordering with a follow-up prompt, we need to define the Bot, a Locale (en_US), an Intent (OrderPizza), Slots (PizzaSize, PizzaTopping), and the Slot Priorities. We also include a "Confirmation Setting" which acts as the follow-up prompt logic before closing the intent.

```hcl
# Configure AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_role" {
  name = "pizza_bot_lex_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# The Lex V2 Bot
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  idle_session_ttl_in_seconds = 300
  role_arn                    = aws_iam_role.lex_role.arn
  data_privacy {
    child_directed = false
  }
}

# Bot Locale (English US)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# Intent: OrderPizza
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want to order a pizza" }
  sample_utterance { utterance = "Can I get a {PizzaSize} pizza with {PizzaTopping}" }

  # Follow-up Prompt Logic (Confirmation Setting)
  confirmation_setting {
    active = true
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "Okay, I have a {PizzaSize} {PizzaTopping} pizza. Should I place the order?"
          }
        }
      }
    }
    declination_response {
      message_group {
        message {
          plain_text_message {
            value = "No problem. Your order has been cancelled."
          }
        }
      }
    }
  }

  intent_closing_setting {
    closing_response {
      message_group {
        message {
          plain_text_message {
            value = "Great! Your pizza is on the way."
          }
        }
      }
    }
  }
}

# Slot 1: Pizza Size
resource "aws_lexv2models_slot" "pizza_size" {
  name        = "PizzaSize"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id

  # Using built-in Amazon type
  slot_type_id = "AMAZON.AlphaNumeric" 

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What size pizza would you like? (Small, Medium, Large)"
          }
        }
      }
    }
  }
}

# Slot 2: Pizza Topping
resource "aws_lexv2models_slot" "pizza_topping" {
  name        = "PizzaTopping"
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id

  slot_type_id = "AMAZON.AlphaNumeric"

  value_elicitation_setting {
    slot_constraint = "Required"
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What topping would you like on your pizza?"
          }
        }
      }
    }
  }
}

# Fallback Intent (Required for a functional bot)
resource "aws_lexv2models_intent" "fallback" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"
}
```

