The following configuration uses the `aws_lexv2models_bot` resource, which is the current standard for Lex V2.

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM Role for Lex Bot
resource "aws_iam_role" "lex_role" {
  name = "PizzaBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# The Lex V2 Bot
resource "aws_lexv2models_bot" "pizza_bot" {
  name                        = "KidsPizzaBot"
  description                 = "A simple pizza ordering bot for children"
  role_arn                    = aws_iam_role.lex_role.arn
  data_privacy {
    child_directed = true # Critical setting for children's apps
  }
  idle_session_ttl_in_seconds = 300
}

# English US Locale
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.pizza_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40
}

# Custom Slot Type for Toppings
resource "aws_lexv2models_slot_type" "topping" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "ToppingType"

  slot_type_values {
    sample_value { value = "Cheese" }
  }
  slot_type_values {
    sample_value { value = "Pepperoni" }
  }
  slot_type_values {
    sample_value { value = "Sausage" }
  }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# Order Pizza Intent
resource "aws_lexv2models_intent" "order_pizza" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderPizza"

  sample_utterance { utterance = "I want a pizza" }
  sample_utterance { utterance = "Can I have a {Topping} pizza" }
  sample_utterance { utterance = "Hungry for pizza" }

  initial_response_setting {
    code_hook {
      active = false
    }
  }
}

# Slot for Topping selection
resource "aws_lexv2models_slot" "topping_slot" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_pizza.intent_id
  name        = "Topping"
  slot_type_id = aws_lexv2models_slot_type.topping.slot_type_id

  value_elicitation_setting {
    prompt_specification {
      max_retries = 2
      message_group {
        message {
          plain_text_message {
            value = "What kind of yummy topping do you want on your pizza?"
          }
        }
      }
    }
    slot_constraint = "Required"
  }
}

# Fallback Intent (Required)
resource "aws_lexv2models_intent" "fallback" {
  bot_id      = aws_lexv2models_bot.pizza_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "FallbackIntent"
  parent_intent_signature = "AMAZON.FallbackIntent"
}
```

