# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lex Bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-bot-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Define the Intent for Ordering Pizza
resource "aws_lex_intent" "order_pizza_intent" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  sample_utterances = [
    "I would like to order a pizza",
    "Buy a pizza",
    "Can I get a {PizzaSize} pizza"
  ]

  slot {
    name        = "PizzaSize"
    description = "The size of the pizza"
    priority    = 1
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric" # Or a custom slot type

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size pizza would you like? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

# 3. Define the Lex Bot
resource "aws_lex_bot" "pizza_bot" {
  name                        = "PizzaOrderingBot"
  description                 = "Bot created by Terraform for ordering pizza"
  locale                      = "en-US"
  child_directed              = false
  idle_session_ttl_in_seconds = 300

  # Configure NLU Intent Confidence Threshold
  nlu_intent_confidence_threshold = 0.5

  abort_statement {
    message {
      content      = "I am sorry, I could not understand you. Goodbye."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't catch that. Can you repeat?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza_intent.name
    intent_version = "1"
  }

  # Ensure the bot waits for the intent to be created
  depends_on = [aws_lex_intent.order_pizza_intent]
}

