# 1. Lambda Function for Fulfillment
resource "aws_iam_role" "pizza_lambda_role" {
  name = "pizza_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "lambda.amazonaws.com" }
    }]
  })
}

resource "aws_lambda_function" "pizza_order_handler" {
  filename      = "lambda_function_payload.zip" # Ensure this file exists or use dummy code
  function_name = "pizza_order_handler"
  role          = aws_iam_role.pizza_lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  source_code_hash = filebase64sha256("lambda_function_payload.zip")
}

# 2. Grant Lex Permission to Invoke Lambda
resource "aws_lambda_permission" "allow_lex" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order_handler.function_name
  principal     = "lex.amazonaws.com"
}

# 3. Define Lex Intent
resource "aws_lex_intent" "order_pizza_intent" {
  name = "OrderPizza"

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "Should I go ahead and order your {PizzaSize} {PizzaType} pizza?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your order."
      content_type = "PlainText"
    }
  }

  slot {
    name        = "PizzaType"
    description = "The kind of pizza (e.g., cheese, pepperoni)"
    priority    = 1
    slot_constraint = "Required"
    slot_type   = "AMAZON.Food" # Using a built-in slot type

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What kind of pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaSize"
    description = "The size of the pizza"
    priority    = 2
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  sample_utterances = [
    "I would like to order a pizza",
    "Can I get a {PizzaSize} {PizzaType} pizza",
    "Order a pizza"
  ]

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri                = aws_lambda_function.pizza_order_handler.arn
      message_version    = "1.0"
    }
  }
}

# 4. Define Lex Bot
resource "aws_lex_bot" "pizza_bot" {
  name        = "PizzaOrderingBot"
  description = "Bot to handle pizza orders"
  locale      = "en-US"
  child_directed = false

  abort_statement {
    message {
      content      = "I'm sorry, I cannot help with that right now."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't quite catch that. Can you repeat?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_pizza_intent.name
    intent_version = "$LATEST"
  }

  process_behavior = "BUILD"
  idle_session_ttl_in_seconds = 300
}

