# Shared variables for naming
locals {
  bot_name = "OrderFlowersBot"
}

# 1. IAM Role for Lex V2
resource "aws_iam_role" "lex_role" {
  name = "LexV2BotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Lex V2 Bot Definition
resource "aws_lexv2models_bot" "flower_bot" {
  name                        = local.bot_name
  role_arn                    = aws_iam_role.lex_role.arn
  data_privacy {
    child_directed = false
  }
  idle_session_ttl_in_seconds = 300
  description                 = "A bot to order flowers"

  # Basic tags
  tags = {
    Environment = "dev"
  }
}

# 3. Bot Locale (Lex V2 requires at least one locale setup)
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                           = aws_lexv2models_bot.flower_bot.id
  bot_version                      = "DRAFT"
  locale_id                        = "en_US"
  nlu_intent_confidence_threshold = 0.40

  description = "English locale for Order Flowers bot"
}

# 4. Intent within the Locale
resource "aws_lexv2models_intent" "order_flowers_intent" {
  bot_id      = aws_lexv2models_bot.flower_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "OrderFlowers"

  sample_utterance {
    utterance = "I would like to order flowers"
  }
  sample_utterance {
    utterance = "Buy some flowers"
  }

  initial_response_setting {
    code_hook {
      active = false
    }
  }
}

# 5. Slot Type (e.g., Flower Types)
resource "aws_lexv2models_slot_type" "flower_types" {
  bot_id      = aws_lexv2models_bot.flower_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  name        = "FlowerTypes"

  slot_type_values {
    sample_value {
      value = "lilies"
    }
  }
  slot_type_values {
    sample_value {
      value = "roses"
    }
  }
  slot_type_values {
    sample_value {
      value = "tulips"
    }
  }

  value_selection_setting {
    resolution_strategy = "OriginalValue"
  }
}

# 6. Slot within the Intent
resource "aws_lexv2models_slot" "flower_type_slot" {
  bot_id      = aws_lexv2models_bot.flower_bot.id
  bot_version = aws_lexv2models_bot_locale.en_us.bot_version
  locale_id   = aws_lexv2models_bot_locale.en_us.locale_id
  intent_id   = aws_lexv2models_intent.order_flowers_intent.intent_id
  name        = "FlowerType"

  slot_constraint = "Required"
  slot_type_id    = aws_lexv2models_slot_type.flower_types.slot_type_id

  value_elicitation_setting {
    prompt_specification {
      max_retries = 3
      message_group {
        message {
          plain_text_message {
            value = "What type of flowers would you like to order?"
          }
        }
      }
    }
  }
}

# 7. Bot Version (Immutable snapshot of the DRAFT)
# Note: Creating a version requires the Bot and Locale to be in a consistent state.
resource "aws_lexv2models_bot_version" "v1" {
