resource "aws_connect_instance" "example" {
  identity_management_type = "CONNECT_MANAGED"
  inbound_calls_enabled    = true
  outbound_calls_enabled   = true
  instance_alias           = "terraformed-connect-instance"
}

# 2. Define the Lex Bot Association
# This associates a Lex V2 bot with the Amazon Connect instance.
# Note: The lex_bot must already exist or be managed via aws_lexv2models_bot.
resource "aws_connect_bot_association" "example" {
  instance_id = aws_connect_instance.example.id

  lex_bot {
    name     = "ChildrensEducationalBot" # Name of your Lex V1 bot OR the Lex V2 Bot ARN/ID setup
    lex_region = "us-east-1"
  }
}

# 3. Grant Amazon Connect permission to invoke the Lex Bot
# This is a critical step; without the resource-based policy, the association
# will exist but the contact flow will fail to trigger the bot.
resource "aws_lambda_permission" "allow_connect_lex" {
  statement_id  = "AllowConnectToInvokeLexBot"
  action        = "lex:PostText"
  function_name = "ChildrensEducationalBot"
  principal     = "connect.amazonaws.com"
