# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Input Kinesis Data Stream
resource "aws_kinesis_stream" "input_stream" {
  name             = "input-data-stream"
  shard_count      = 1
  retention_period = 24

  tags = {
    Environment = "Dev"
  }
}

# 2. IAM Role for Kinesis Data Analytics Application
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-app-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      },
    ]
  })
}

# 3. IAM Policy to allow reading from Stream and writing to CloudWatch
resource "aws_iam_role_policy" "analytics_policy" {
  name = "analytics-permissions"
  role = bill_aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:DescribeStream",
          "kinesis:ListShards"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.input_stream.arn
      },
      {
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogStream"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# 4. CloudWatch Log Group for Application monitoring
resource "aws_cloudwatch_log_group" "analytics_logs" {
  name = "/aws/kinesis-analytics/my-app"
}

resource "aws_cloudwatch_log_stream" "analytics_log_stream" {
  name           = "kinesis-analytics-log-stream"
  log_group_name = aws_cloudwatch_log_group.analytics_logs.name
}

# 5. Kinesis Data Analytics Application (SQL or Flink based)
resource "aws_kinesisanalyticsv2_application" "example" {
  name                   = "example-sql-application"
  runtime_environment    = "FLINK-1_15"
  service_execution_role = aws_iam_role.analytics_role.arn

  application_configuration {
    # Application code configuration (This example uses a placeholder dummy zip)
    # In a real scenario, you would upload your jar/code to S3
    application_code_configuration {
      code_content {
        text_content = "SELECT * FROM SOURCE_STREAM_001"
      }
      code_content_type = "PLAINTEXT"
    }

    # Connect the Kinesis Stream as an input
    # Note: For Flink, inputs are often defined within the code, 
    # but for SQL applications, they are defined via the API here.
    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }
      parallelism_configuration {
        auto_scaling_enabled = true
        configuration_type   = "CUSTOM"
        parallelism          = 1
        parallelism_per_kpu  = 1
      }
    }

    cloudwatch_logging_options {
      log_stream_arn = aws_cloudwatch_log_stream.analytics_log_stream.arn
    }
  }

  tags = {
    Name = "KinesisAnalyticsApp"
  }
}

