          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Firehose to access S3 and CloudWatch
resource "aws_iam_role_policy" "firehose_s3_policy" {
  name   = "firehose_s3_policy"
  role   = aws_iam_role.firehose_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.bucket.arn,
          "${aws_s3_bucket.bucket.arn}/*"
        ]
      },
      {
        Action = [
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = ["*"]
      }
    ]
  })
}

# 4. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "dynamic_partitioning_stream" {
  name        = "terraform-dynamic-partitioning-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.bucket.arn

    # Buffer settings
    buffer_size = 64
    buffer_interval = 60

    # Dynamic Partitioning Configuration
    dynamic_partitioning_configuration {
      enabled = true
    }

    # The prefix uses JQ expressions to reference the metadata keys defined in the processing_configuration
    # Format: customer_id=!{partitionKeyFromQuery:customer_id}/year=!{partitionKeyFromQuery:year}/
    prefix              = "data/customer_id=!{partitionKeyFromQuery:customer_id}/year=!{partitionKeyFromQuery:year}/"
    error_output_prefix = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/!{firehose:error-output-type}/"

    processing_configuration {
      enabled = true

      # Metadata extraction from the JSON payload
      processors {
        type = "MetadataExtraction"
        parameters {
          parameter_name  = "MetadataExtractionQuery"
          parameter_value = "{customer_id: .customer_id, year: .year}"
        }
        parameters {
          parameter_name  = "JsonParsingEngine"
          parameter_value = "JQ-1.6"
        }
      }

      # Append a newline to records
      processors {
        type = "AppendDelimiterToRecord"
      }
    }
  }

  # Required for Dynamic Partitioning to handle potential throughput spikes
  tags = {
    Environment = "Dev"
  }
}

