To create a Kinesis Data Firehose delivery stream targeting Amazon Redshift, we need several components: a Redshift cluster, an S3 bucket (for intermediate storage), and the necessary IAM roles to allow Firehose to access these resources and perform the COPY command into Redshift.

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Intermediate S3 Bucket (Required by Firehose for Redshift destinations)
resource "aws_s3_bucket" "firehose_redshift_temp" {
  bucket = "tf-firehose-redshift-intermediate-storage"
}

# 2. Redshift Cluster
resource "aws_redshift_cluster" "destination" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "dev"
  master_username    = "adminuser"
  master_password    = "MustBeComplex123!"
  node_type          = "dc2.large"
  cluster_type       = "single-node"
  skip_final_snapshot = true
}

# 3. IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_redshift_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 4. IAM Policy for Firehose (Access to S3 and Redshift permissions)
resource "aws_iam_role_policy" "firehose_policy" {
  role = aws_iam_role.firehose_role.id
  name = "firehose_delivery_policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.firehose_redshift_temp.arn,
          "${aws_s3_bucket.firehose_redshift_temp.arn}/*"
        ]
      },
      {
        Effect   = "Allow"
        Action   = ["redshift:DescribeClusters", "redshift:GetClusterCredentials"]
        Resource = [aws_redshift_cluster.destination.arn]
      }
    ]
  })
}

# 5. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "redshift_stream" {
  name        = "firehose-to-redshift-stream"
  destination = "redshift"

  redshift_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    cluster_jdbcurl    = "jdbc:redshift://${aws_redshift_cluster.destination.endpoint}/${aws_redshift_cluster.destination.database_name}"
    username           = "adminuser"
    password           = "MustBeComplex123!"
