response:
To create a Kinesis Data Firehose delivery stream targeting an Amazon OpenSearch (formerly Elasticsearch) Service domain, we need several components:
1.  **S3 Bucket**: Acts as the backup for failed documents or all source records.
2.  **IAM Role & Policies**: Grants Firehose permission to write to S3 and interact with the OpenSearch domain.
3.  **Kinesis Firehose**: The delivery stream itself configured with the `elasticsearch_configuration` block.

Note: This configuration assumes you have an existing OpenSearch/Elasticsearch domain ARN. If not, the `domain_arn` parameter should be replaced with your specific resource.

```hcl
# Configure the Provider
provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Firehose backups
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "my-firehose-es-backup-bucket-unique-id"
}

resource "aws_s3_bucket_public_access_block" "firehose_backup_block" {
  bucket                  = aws_s3_bucket.firehose_backup.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_elasticsearch_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Firehose to access S3 and ES
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_delivery_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = ["*"] # In production, scope this to your specific Domain ARN
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# 4. Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "es_delivery_stream" {
  name        = "terraform-firehose-to-es"
  destination = "elasticsearch"

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "GZIP"
  }

  elasticsearch_configuration {
    domain_arn     = "arn:aws:es:us-east-1:123456789012:domain/my-domain" # Replace with your Domain ARN
    role_arn       = aws_iam_role.firehose_role.arn
    index_name     = "logs"
    index_rotation_period = "OneDay"
    retry_duration = 300

    # Optional: CloudWatch logging to monitor delivery errors
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/terraform-firehose-to-es"
      log_stream_name = "ElasticsearchDelivery"
    }

    # Backup mode for all records or failed only
    s3_backup_mode = "FailedDocumentsOnly"
  }
}
```

