# Terraform configuration for Kinesis Data Firehose to Splunk

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for backup (Required by Firehose for failed events)
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "splunk-firehose-backup-bucket-unique-id"
}

# 2. IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_splunk_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Firehose (S3 and Logging permissions)
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_splunk_policy"
  role = role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      }
    ]
  })
}

# 4. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "splunk_stream" {
  name        = "terraform-firehose-to-splunk"
  destination = "splunk"

  splunk_configuration {
    hec_endpoint               = "https://http-inputs-customer.splunkcloud.com:443" # Replace with your Splunk HEC Endpoint
    hec_token                  = "00000000-0000-0000-0000-000000000000"           # Replace with your HEC Token
    hec_acknowledgment_timeout = 600
    hec_endpoint_type          = "Raw"
    retry_duration             = 300

    s3_backup_mode = "FailedEventsOnly"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/splunk-stream"
      log_stream_name = "SplunkDelivery"
    }
  }
}

# CloudWatch Log Group for monitoring
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesisfirehose/splunk-stream"
  retention_in_days = 7
}

resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "SplunkDelivery"
  log_group_name = aws_cloudwatch_log_group.firehose_log_group.name
}

