provider "aws" {
  region = "us-east-1"
}

data "aws_caller_identity" "current" {}

# 1. S3 Bucket for Backup/Failed Records
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-os-backup-${data.aws_caller_identity.current.account_id}"
}

# 2. OpenSearch Serverless Collection Configuration
resource "aws_opensearchserverless_security_policy" "network_policy" {
  name = "firehose-network-policy"
  type = "network"
  description = "Public access for simplicity in this example"
  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "collection",
          Resource     = ["collection/firehose-dest"]
        },
        {
          ResourceType = "dashboard",
          Resource     = ["collection/firehose-dest"]
        }
      ],
      AllowFromPublic = true
    }
  ])
}

resource "aws_opensearchserverless_security_policy" "encryption_policy" {
  name = "firehose-encryption-policy"
  type = "encryption"
  policy = jsonencode({
    Rules = [
      {
        ResourceType = "collection",
        Resource     = ["collection/firehose-dest"]
      }
    ],
    AWSOwnedKey = true
  })
}

resource "aws_opensearchserverless_collection" "dest" {
  name       = "firehose-dest"
  type       = "TIMESERIES"
  depends_on = [aws_opensearchserverless_security_policy.encryption_policy, aws_opensearchserverless_security_policy.network_policy]
}

# 3. IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_os_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "aoss:APIAccessAll"
        ]
        Resource = [aws_opensearchserverless_collection.dest.arn]
      }
    ]
  })
}

# 4. OpenSearch Serverless Data Access Policy
# This grants the Firehose IAM role permission to ingest data into the collection
resource "aws_opensearchserverless_access_policy" "data_access" {
  name        = "firehose-access-policy"
  type        = "data"
  description = "Allow Firehose to write to collection"
  policy = jsonencode([
    {
      Rules = [
        {
          ResourceType = "index",
          Resource     = ["index/firehose-dest/*"],
          Permission   = ["indices:CreateIndex", "indices:Write", "indices:DescribeIndex"]
        },
        {
          ResourceType = "collection",
          Resource     = ["collection/firehose-dest"],
          Permission   = ["aoss:CreateCollectionItems"]
        }
      ],
      Principal = [aws_iam_role.firehose_role.arn]
    }
  ])
}

# 5. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "os_stream" {
  name        = "kinesis-firehose-to-opensearch-serverless"
  destination = "opensearchserverless"

  opensearchserverless_configuration {
    role_arn       = aws_iam_role.firehose_role.arn
    collection_endpoint = aws_opensearchserverless_collection.dest.collection_endpoint
    index_name     = "logs"

    s3_configuration {
      role_arn           = aws_iam_role.firehose_role.arn
      bucket_arn         = aws_s3_bucket.firehose_backup.arn
      buffering_size     = 5
      buffering_interval = 300
      compression_format = "GZIP"
    }

    cloudwatch_logging_options {
      enabled         = false
    }
  }

  depends_on = [aws_opensearchserverless_access_policy.data_access]
}

