# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an S3 Bucket for data backup (required for Firehose)
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-http-backup-bucket-${random_id.id.hex}"
}

resource "random_id" "id" {
  byte_length = 4
}

# 2. IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_to_http_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Firehose to access S3 and CloudWatch
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_delivery_policy"
  role = license_aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
