# 5. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "terraform-firehose-to-opensearch"
  destination = "elasticsearch" # 'elasticsearch' is used for OpenSearch as well

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
