# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a Kinesis Stream to serve as the data source
resource "aws_kinesis_stream" "example_source" {
  name             = "example-input-stream"
  shard_count      = 1
  retention_period = 24
}

# 2. Create an S3 Bucket to store the application code (jar/zip)
resource "aws_s3_bucket" "app_code_bucket" {
  bucket        = "kinesis-analytics-code-bucket-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# Upload a placeholder application file (in a real scenario, you'd upload your Flink jar)
resource "aws_s3_object" "app_code" {
  bucket = aws_s3_bucket.app_code_bucket.id
  key    = "flink-app.jar"
  source = "path/to/your/flink-app.jar" # Path to your local Flink jar
}

# 3. IAM Role for the Kinesis Analytics Application
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      },
    ]
  })
}

# Policy to allow reading from the S3 bucket and Kinesis stream
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.app_code_bucket.arn}/*"
      },
      {
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Effect   = "Allow"
        Resource = aws_kinesis_stream.example_source.arn
      },
      {
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogStream"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# 4. Kinesis Data Analytics Application (v2)
resource "aws_kinesisanalyticsv2_application" "example_app" {
  name                   = "example-flink-application"
  runtime_environment    = "FLINK-1_15" # Specify the Flink version
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    application_code_configuration {
      code_content {
        s3_content_location {
          bucket_arn = aws_s3_bucket.app_code_bucket.arn
          file_key   = aws_s3_object.app_code.key
        }
      }
      code_content_strategy = "PLAINTEXT"
    }

    flink_application_configuration {
      checkpoint_configuration {
        configuration_type = "DEFAULT"
      }

      monitoring_configuration {
        configuration_type = "CUSTOM"
        log_level          = "INFO"
        metrics_level      = "APPLICATION"
      }

      parallelism_configuration {
        auto_scaling_enabled = true
        configuration_type   = "CUSTOM"
        parallelism          = 1
        parallelism_per_kpu  = 1
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

