# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a Kinesis Stream for Input
resource "aws_kinesis_stream" "input_stream" {
  name             = "input-data-stream"
  shard_count      = 1
  retention_period = 24
}

# 2. Create a Kinesis Stream for Output
resource "aws_kinesis_stream" "output_stream" {
  name             = "output-data-stream"
  shard_count      = 1
  retention_period = 24
}

# 3. IAM Role for Kinesis Analytics
resource "aws_iam_role" "analytics_role" {
  name = "kinesis-analytics-sql-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# 4. IAM Policy for the Role to access Streams
resource "aws_iam_role_policy" "analytics_policy" {
  name = "kinesis-analytics-sql-policy"
  role = aws_iam_role.analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kinesis:Get*",
          "kinesis:DescribeStream",
          "kinesis:ListStreams",
          "kinesis:PutRecord",
          "kinesis:PutRecords"
        ]
        Effect   = "Allow"
        Resource = [
          aws_kinesis_stream.input_stream.arn,
          aws_kinesis_stream.output_stream.arn
        ]
      }
    ]
  })
}

# 5. Kinesis Data Analytics V2 SQL Application
resource "aws_kinesisanalyticsv2_application" "sql_app" {
  name                   = "my-sql-analytics-app"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.analytics_role.arn

  application_configuration {
    sql_application_configuration {
      input {
        name_prefix = "SOURCE_SQL_STREAM"

        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.input_stream.arn
        }

        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json {
                record_row_path = "$"
              }
            }
          }

          record_columns {
            name     = "sensor_id"
            sql_type = "VARCHAR(16)"
            mapping  = "$.sensor_id"
          }
          record_columns {
            name     = "temperature"
            sql_type = "DOUBLE"
            mapping  = "$.temperature"
          }
        }
      }

      output {
        name = "DESTINATION_SQL_STREAM"

        kinesis_streams_output {
          resource_arn = aws_kinesis_stream.output_stream.arn
        }

        destination_schema {
          record_format_type = "JSON"
        }
      }
    }

    application_code_configuration {
      code_content {
        text_content = <<EOF
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (sensor_id VARCHAR(16), temperature DOUBLE);
CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"
SELECT STREAM "sensor_id", "temperature"
FROM "SOURCE_SQL_STREAM_001"
WHERE "temperature" > 25;
EOF
      }
      code_content_type = "PLAINTEXT"
    }
  }

  tags = {
    Environment = "Development"
  }
}

