        ]
        Effect   = "Allow"
        Resource = [
          "${aws_cloudwatch_log_group.analytics_log_group.arn}:*"
        ]
      }
    ]
  })
}

# 4. Kinesis Data Analytics v2 Application (SQL Runtime example)
resource "aws_kinesisanalyticsv2_application" "example_app" {
  name                   = "my-analytics-application"
  runtime_environment    = "SQL-1_0"
