# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# IAM Role for Kendra Index
resource "aws_iam_role" "kendra_index_role" {
  name = "kendra-index-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "kendra.amazonaws.com" }
    }]
  })
}

# IAM Role for Kendra Data Source
resource "aws_iam_role" "kendra_ds_role" {
  name = "kendra-data-source-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "kendra.amazonaws.com" }
    }]
  })
}

# Kendra Index
resource "aws_kendra_index" "example" {
  name     = "example-index"
  role_arn = aws_iam_role.kendra_index_role.arn
  edition  = "DEVELOPER_EDITION"
}

# Kendra Data Source with Proxy Settings (Web Crawler example)
resource "aws_kendra_data_source" "web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-data-source-with-proxy"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_ds_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        site_maps_configuration {
          site_maps = ["https://example.com/sitemap.xml"]
        }
      }

      # Proxy configuration block
      proxy_configuration {
        host = "proxy.example.com"
        port = 8080
        # Optional: credentials stored in Secrets Manager if needed
        # credentials = aws_secretsmanager_secret.proxy_creds.arn
      }
    }
  }
}

