# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an IAM Role for the Kendra Data Source
resource "aws_iam_role" "kendra_role" {
  name = "kendra-web-crawler-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Create a Kendra Index (Required for the Data Source)
resource "aws_kendra_index" "example" {
  name     = "example-index"
  role_arn = aws_iam_role.kendra_role.arn
  edition  = "DEVELOPER_EDITION"
}

# 3. Create the Kendra Web Crawler Data Source with URL patterns
resource "aws_kendra_data_source" "web_crawler" {
  index_id = aws_kendra_index.example.id
  name     = "example-web-crawler"
  type     = "WEBCRAWLER"
  role_arn = aws_iam_role.kendra_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_urls = ["https://aws.amazon.com"]
          web_crawler_mode = "HOST_ONLY"
        }
      }

      # URL Inclusion and Exclusion Patterns
      # These use regular expressions to filter which pages are crawled
      url_filter_configuration {
        inclusion_patterns = [
          "https://aws.amazon.com/sagemaker/.*",
          "https://aws.amazon.com/ec2/.*"
        ]
        exclusion_patterns = [
          ".*\.pdf",
          ".*support/.*",
          "https://aws.amazon.com/private/.*"
        ]
      }

      crawl_depth = 2
    }
  }

  tags = {
    Environment = "Project-Alpha"
  }
}

# Output the Data Source ID
output "kendra_data_source_id" {
  value = aws_kendra_data_source.web_crawler.data_source_id
}

