# Standard CloudWatch feedback policy for Kendra
resource "aws_iam_role_policy" "kendra_policy" {
  name = "kendra-logging-policy"
  role = tf_aws_iam_role.kendra_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "cloudwatch:PutMetricData",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
