resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  description = "A simple Kendra index with metadata configuration"
  edition     = "DEVELOPER_EDITION"
  role_arn    = aws_iam_role.kendra_role.arn

  # Document Metadata Configuration
  # This section defines how metadata fields are indexed, searched, and displayed
  document_metadata_configuration_updates {
    name = "ProjectName"
    type = "STRING_VALUE"
    search {
      facetable = true
      searchable = true
      displayable = true
      sortable    = false
    }
  }

  document_metadata_configuration_updates {
    name = "DocumentVersion"
    type = "NUMBER_VALUE"
    search {
      facetable = false
      searchable = false
      displayable = true
      sortable    = true
    }
  }

