    name = "LastUpdated"
    type = "DATE_VALUE"
    search {
      facetable = true
      searchable = false
      displayable = true
      sortable    = true
    }
  }

  tags = {
    Environment = "Dev"
  }
}

output "kendra_index_id" {
  value = aws_kendra_index.example.id
}

output "kendra_index_arn" {
  value = aws_kendra_index.example.arn
}

