# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Reference the existing Hosted Zone
data "aws_route53_zone" "primary" {
  name         = "example.com."
  private_zone = false
}

# 1. Create the Health Check for the Primary Endpoint
resource "aws_route53_health_check" "primary_health_check" {
  fqdn              = "primary.example.com"
  port              = 443
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Name = "primary-health-check"
  }
}

# 2. Primary Record (Active)
resource "aws_route53_record" "primary" {
  zone_id = data.aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"

  # Failover configuration
  failover_routing_policy {
    type = "PRIMARY"
  }

  # Health check association
  health_check_id = aws_route53_health_check.primary_health_check.id
  set_identifier  = "primary-endpoint"

  alias {
    name                   = "primary-lb.us-east-1.elb.amazonaws.com"
    zone_id                = "Z35SXDOTRQ7X7K" # Example ELB Zone ID
    evaluate_target_health = true
  }
}

# 3. Secondary Record (Passive/Failover)
resource "aws_route53_record" "secondary" {
  zone_id = data.aws_route53_zone.primary.zone_id
  name    = "app.example.com"
  type    = "A"

  # Failover configuration
  failover_routing_policy {
    type = "SECONDARY"
  }

  set_identifier = "secondary-endpoint"

  alias {
    name                   = "backup-lb.us-west-2.elb.amazonaws.com"
