# Shared Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define the Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "primary.com"
}

# 2. Health Checks for endpoints in both regions
resource "aws_route53_health_check" "us_east_1" {
  fqdn              = "us-east-1-api.primary.com"
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = "3"
  request_interval  = "30"
}

resource "aws_route53_health_check" "eu_central_1" {
  fqdn              = "eu-central-1-api.primary.com"
  port              = 80
  type              = "HTTP"
  resource_path     = "/health"
  failure_threshold = "3"
  request_interval  = "30"
}

# 3. Route 53 Traffic Policy
# This policy uses weighted routing (50/50 split) to distribute load equally
# between regions, effectively acting as a simple load balancer.
resource "aws_route53_traffic_policy" "load_balancer_policy" {
  name     = "low-load-distribution-policy"
  comment  = "Directs traffic to endpoints in us-east-1 and eu-central-1"
  document = <<EOF
{
  "AWSPolicyFormatVersion": "2015-11-01",
  "RecordType": "A",
  "Endpoints": {
    "us-endpoint": {
      "Type": "value",
      "Value": "1.2.3.4"
    },
    "eu-endpoint": {
      "Type": "value",
      "Value": "5.6.7.8"
    }
  },
  "Rules": {
    "weighted-rule": {
      "RuleType": "weighted",
      "Items": [
        {
          "EndpointReference": "us-endpoint",
          "Weight": "50",
          "HealthCheck": "${aws_route53_health_check.us_east_1.id}"
        },
        {
          "EndpointReference": "eu-endpoint",
          "Weight": "50",
          "HealthCheck": "${aws_route53_health_check.eu_central_1.id}"
        }
      ]
    }
  },
  "StartRule": "weighted-rule"
}
EOF
}

# 4. Traffic Policy Instance
# This applies the policy to the actual DNS name in the hosted zone.
resource "aws_route53_traffic_policy_instance" "primary_endpoint" {
  name                   = "api"
  traffic_policy_id      = aws_route53_traffic_policy.load_balancer_policy.id
  traffic_policy_version = 1
  hosted_zone_id         = aws_route53_zone.primary.id
  ttl                    = 60
}

