response:
To implement a Route 53 Geolocation traffic policy, we need to define the hosted zone, the traffic policy document (JSON), and the traffic policy resource itself. The policy will logic-map North American users to one endpoint and European users to another, with a default fallback.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Route 53 Hosted Zone named "primary"
resource "aws_route53_zone" "primary" {
  name = "example.com" # Replace with your actual domain
  comment = "Primary zone for geographic routing"
}

# 2. Define the Traffic Policy
# This policy directs traffic from the US and EU to specific endpoints
resource "aws_route53_traffic_policy" "geo_policy" {
  name    = "geo-location-policy"
  comment = "Directs US and EU users to regional endpoints"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-11-01"
    RecordType             = "A"
    StartRule              = "geoproximity_rule"
    Endpoints = {
      us_endpoint = {
        Type  = "value"
        Value = "1.1.1.1" # Replace with your US server IP or ELB DNS
      }
      eu_endpoint = {
        Type  = "value"
        Value = "2.2.2.2" # Replace with your EU server IP or ELB DNS
      }
      fallback_endpoint = {
        Type  = "value"
        Value = "3.3.3.3" # Global fallback
      }
    }
    Rules = {
      geoproximity_rule = {
        RuleType = "geo"
        Locations = [
          {
            ContinentCode = "NA" # North America (Includes US)
            EndpointReference = "us_endpoint"
          },
          {
            ContinentCode = "EU" # Europe
            EndpointReference = "eu_endpoint"
          }
        ]
        DefaultEndpointByGeo = "fallback_endpoint"
      }
    }
  })
}

# 3. Create a Traffic Policy Instance
# This applies the policy to a specific DNS record within the hosted zone
resource "aws_route53_traffic_policy_instance" "geo_instance" {
  name                   = "geo"
  traffic_policy_id      = aws_route53_traffic_policy.geo_policy.id
  traffic_policy_version = 1
  hosted_zone_id         = aws_route53_zone.primary.id
  ttl                    = 300
}
```

