  name = "eks-fargate-pod-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks-fargate-pods.amazonaws.com"
      }
    }]
  })
}

# Attach the standard AWS managed policy for Fargate Pod Execution
resource "aws_iam_role_policy_attachment" "fargate_pod_execution_policy_attach" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
  role       = aws_iam_role.fargate_pod_execution_role.name
}

# 2. EKS Fargate Profile
# Note: Ensure variables "cluster_name" and "private_subnet_ids" are defined or replaced
resource "aws_eks_fargate_profile" "kube_system" {
  cluster_name           = var.cluster_name
  fargate_profile_name   = "fp-kube-system"
  pod_execution_role_arn = aws_iam_role.fargate_pod_execution_role.arn

  # Subnets must be private and tagged with "kubernetes.io/cluster/<cluster-name> = shared/owned"
  subnet_ids = var.private_subnet_ids

  selector {
    namespace = "kube-system"
  }

  depends_on = [aws_iam_role_policy_attachment.fargate_pod_execution_policy_attach]
}

# 3. Provider Configuration for Kubernetes Operations
data "aws_eks_cluster" "cluster" {
  name = var.cluster_name
}

data "aws_eks_cluster_auth" "cluster" {
  name = var.cluster_name
}

provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

# 4. Patch CoreDNS to run on Fargate
