response:
To create an AWS EKS access entry with the specified parameters, we need to use the `aws_eks_access_entry` resource. This resource associates an IAM principal (User or Role) with an EKS cluster and assigns it to specific Kubernetes groups.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Define variables for reusability
variable "cluster_name" {
  description = "The name of the EKS cluster"
  type        = string
  default     = "example-cluster"
}

variable "principal_arn" {
  description = "The IAM Principal ARN (User or Role) to be added"
  type        = string
  default     = "arn:aws:iam::123456789012:role/example-role"
}

# Create the EKS Access Entry
resource "aws_eks_access_entry" "example" {
  cluster_name      = var.cluster_name
  principal_arn     = var.principal_arn
  kubernetes_groups = ["group-1", "group-2"]
  type              = "STANDARD"

  tags = {
    Name        = "example-access-entry"
    Environment = "production"
  }
}

# Example of how to associate an EKS Access Policy to the entry (Optional but common)
# This grants specific permissions (like AmazonEKSClusterAdminPolicy) to the principal
resource "aws_eks_access_policy_association" "example_policy" {
  cluster_name  = var.cluster_name
  policy_arn    = "arn:aws:eks::aws:cluster-access-policy/AmazonEKSClusterAdminPolicy"
  principal_arn = var.principal_arn

  access_scope {
    type = "cluster"
  }

  depends_on = [aws_eks_access_entry.example]
}
