resource "aws_eks_access_entry" "example" {
  cluster_name      = var.cluster_name
  principal_arn     = var.principal_arn
  type              = "STANDARD" # Use STANDARD for IAM users/roles
}

# 2. Attach the Access Policy with Namespace Scope
# This associates the "AmazonEKSAdminPolicy" (or similar) to the principal
# and restricts it to the specified namespace.
resource "aws_eks_access_policy_association" "example" {
  cluster_name  = var.cluster_name
