To create an AWS EKS add-on for the VPC CNI, we need to define the `aws_eks_addon` resource. This resource requires the `cluster_name` and the `addon_name`. It is also best practice to manage the configuration version and conflict resolution settings.

```hcl
# Configure the GitHub provider or AWS provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Variable to allow dynamic cluster naming
variable "eks_cluster_name" {
  description = "The name of the EKS cluster"
  type        = string
}

# Resource definition for the VPC CNI EKS Add-on
resource "aws_eks_addon" "vpc_cni" {
  cluster_name                = var.eks_cluster_name
  addon_name                  = "vpc-cni"

  # Optional: It is recommended to use "OVERWRITE" to ensure Terraform handles 
  # the management of the default CNI installed during cluster creation.
  resolve_conflicts_on_create = "OVERWRITE"
  resolve_conflicts_on_update = "PRESERVE"

  tags = {
    Environment = "managed-by-terraform"
  }
}

# Output the ARN of the addon
output "eks_addon_arn" {
  value = aws_eks_addon.vpc_cni.arn
}
```

