# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Reference the existing EKS Cluster by name
data "aws_eks_cluster" "example" {
  name = "example"
}

# 2. Fetch the TLS certificate for the EKS OIDC provider (required for the IAM OIDC Provider)
data "tls_certificate" "eks" {
  url = data.aws_eks_cluster.example.identity[0].oidc[0].issuer
}

# 3. Create the IAM OIDC Identity Provider
# This enables IAM roles for service accounts (IRSA)
resource "aws_iam_openid_connect_provider" "oidc_provider" {
  client_id_list  = ["sts.amazonaws.com"]
  thumbprint_list = [data.tls_certificate.eks.certificates[0].sha1_fingerprint]
  url             = data.aws_eks_cluster.example.identity[0].oidc[0].issuer
}

# 4. Associate an external Identity Provider configuration with the EKS cluster
# This allows the cluster to authenticate users via an external OIDC provider
resource "aws_eks_identity_provider_config" "example_oidc_config" {
  cluster_name = data.aws_eks_cluster.example.name

  oidc {
    client_id                     = "your-oidc-client-id"
    identity_provider_config_name = "example-oidc-provider"
    issuer_url                    = "https://oidc.eks.us-east-1.amazonaws.com/id/EXAMPLE" # Replace with your specific OIDC issuer URL
    groups_claim                  = "groups"
    username_claim                = "email"
  }
}

# Outputs for verification
output "eks_oidc_issuer_url" {
  value = data.aws_eks_cluster.example.identity[0].oidc[0].issuer
}

output "iam_oidc_provider_arn" {
  value = aws_iam_openid_connect_provider.oidc_provider.arn
}

