To provision an Amazon EKS cluster with the required IAM role and policies in AWS using Terraform, we need to define the provider, the IAM role with its trust relationship, the policy attachment, and finally the EKS cluster resource with a dependency on that attachment to ensure the role is fully authorized before the cluster begins provisioning.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define the IAM Role for the EKS Cluster
resource "aws_iam_role" "eks_demo_role" {
  name = "eks-cluster-demo"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach the AmazonEKSClusterPolicy to the Role
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_demo_role.name
}

# 3. Define the EKS Cluster
resource "aws_eks_cluster" "demo" {
  name     = "demo"
  role_arn = aws_iam_role.eks_demo_role.arn

  vpc_config {
    # Replace these with your actual VPC Subnet IDs
    subnet_ids = [
      "subnet-0123456789abcdef0",
      "subnet-0123456789abcdef1"
    ]
  }

  # Ensure that IAM Role permissions are created before and deleted after EKS Cluster handling.
  # Otherwise, EKS will not be able to properly delete EKS managed EC2 infrastructure such as Security Groups.
  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy
  ]
}
