response:
To fulfill your request, we first define the IAM role with the correct trust relationship for Amazon EKS. We then attach the required AWS managed policy `AmazonEKSClusterPolicy`. Finally, we define the EKS cluster itself, ensuring it references the IAM role and utilizes an explicit `depends_on` block to guarantee the policy is attached before the cluster begins provisioning to avoid authorization failures.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define the IAM Role for the EKS Cluster
resource "aws_iam_role" "example" {
  name = "example"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "eks.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach the AmazonEKSClusterPolicy managed policy to the role
resource "aws_iam_role_policy_attachment" "example_AmazonEKSClusterPolicy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.example.name
}

# 3. Create the AWS EKS Cluster
resource "aws_eks_cluster" "example" {
  name     = "example"
  role_arn = aws_iam_role.example.arn

  vpc_config {
    # Ensure these subnets are spread across at least two Availability Zones
    subnet_ids              = ["subnet-12345678", "subnet-87654321"]
    endpoint_private_access = false
    endpoint_public_access  = true
  }

  # Ensure that IAM Role permissions are created before and deleted after EKS Cluster handling.
  # Otherwise, EKS will not be able to properly delete EKS managed EC2 infrastructure such as Security Groups.
  depends_on = [
    aws_iam_role_policy_attachment.example_AmazonEKSClusterPolicy
  ]
}
```

