# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Define the S3 Bucket
resource "aws_s3_bucket" "my_bucket" {
  bucket = "my-unique-bucket-name-terraform-ai" # S3 buckets must have globally unique names

  tags = {
    Name        = "My Bucket"
    Environment = "Dev"
  }
}

# Define the IP Address to block
variable "blocked_ip" {
  type    = string
  default = "192.168.1.1/32"
}

# Apply the Bucket Policy using jsonencode
resource "aws_s3_bucket_policy" "block_ip_policy" {
  bucket = aws_s3_bucket.my_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Id      = "IPBlockPolicy"
    Statement = [
      {
        Sid       = "DenySpecificIP"
        Effect    = "Deny"
        Principal = "*"
        Action    = "s3:*"
        Resource = [
          aws_s3_bucket.my_bucket.arn,
          "${aws_s3_bucket.my_bucket.arn}/*"
        ]
        Condition = {
          IpAddress = {
            "aws:SourceIp" = [var.blocked_ip]
          }
        }
      }
    ]
  })
}

# Output the bucket name
output "bucket_name" {
  value = aws_s3_bucket.my_bucket.id
}

