provider "aws" {
    region = "us-west-1"
}

resource "aws_s3_bucket" "a" {
  bucket = "test_bucket"
}

resource "aws_s3_bucket_policy" "b" {
  bucket = aws_s3_bucket.a.id
  policy = jsonencode({
    "Version" : "2012-10-17",
    "Id"      : "my_policy",
    "Statement" : [
      {
        "Sid"       : "IPAllow",
        "Effect"    : "Deny",
        "Principal" : "*",
        "Action"    : "s3:*",
        "Resource"  : "arn:aws:s3:::test_bucket/*",
        "Condition" : {
          "IpAddress" : { "aws:SourceIp" : "1.2.3.4/32" }
        }
      }
    ]
  })
}

response:
To provision an AWS S3 bucket with a specific IP-based deny policy using the `jsonencode` function, we first define the S3 bucket resource and then apply the `aws_s3_bucket_policy` resource using a conditional statement in the policy document.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Define the S3 Bucket
resource "aws_s3_bucket" "my_bucket" {
  bucket = "my-unique-bucket-name-terraform-ai" # S3 buckets must have globally unique names

  tags = {
    Name        = "My Bucket"
    Environment = "Dev"
  }
}

# Define the IP Address to block
variable "blocked_ip" {
  type    = string
  default = "192.168.1.1/32"
}

# Apply the Bucket Policy using jsonencode
resource "aws_s3_bucket_policy" "block_ip_policy" {
  bucket = aws_s3_bucket.my_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Id      = "IPBlockPolicy"
    Statement = [
      {
        Sid       = "DenySpecificIP"
        Effect    = "Deny"
        Principal = "*"
        Action    = "s3:*"
        Resource = [
          aws_s3_bucket.my_bucket.arn,
          "${aws_s3_bucket.my_bucket.arn}/*"
        ]
        Condition = {
          IpAddress = {
            "aws:SourceIp" = [var.blocked_ip]
          }
        }
      }
    ]
  })
}

# Output the bucket name
output "bucket_name" {
  value = aws_s3_bucket.my_bucket.id
}
```

