The following Terraform configuration achieves this:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Provide the S3 Bucket resource
resource "aws_s3_bucket" "test_bucket" {
  bucket = "test-bucket"

  # Note: In modern AWS environments, it is recommended to manage ACLs and 
  # Public Access Blocks as separate resources to avoid conflicts.
}

# 2. Prevent accidental deletion by enabling versioning
resource "aws_s3_bucket_versioning" "test_bucket_versioning" {
  bucket = aws_s3_bucket.test_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 3. Use a private ACL
resource "aws_s3_bucket_ownership_controls" "test_bucket_oc" {
  bucket = aws_s3_bucket.test_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "test_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.test_bucket_oc]

  bucket = aws_s3_bucket.test_bucket.id
  acl    = "private"
}

# 4. Enable AES256 default server-side encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "test_bucket_encryption" {
  bucket = aws_s3_bucket.test_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# 5. Apply Public Access Block to block all public access
resource "aws_s3_bucket_public_access_block" "test_bucket_pab" {
  bucket = aws_s3_bucket.test_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}
