# Terraform configuration for AWS S3 Bucket Infrastructure

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "eu-west-1" # Adjust region as necessary
}

# 1. Define the S3 Bucket
resource "aws_s3_bucket" "infra_bucket" {
  bucket = "wellcomecollection-platform-infra"

  # Safeguard against accidental deletion via Terraform
  # This prevents 'terraform destroy' from succeeding if the bucket is not empty
  force_destroy = false

  tags = {
    Name        = "wellcomecollection-platform-infra"
    Environment = "Infrastructure"
  }
}

# 2. Assign Private ACL
# Note: AWS now recommends using Bucket Ownership Controls and disabling ACLs,
# but to strictly follow the "private ACL" requirement:
resource "aws_s3_bucket_ownership_controls" "infra_bucket_oc" {
  bucket = aws_s3_bucket.infra_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "infra_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.infra_bucket_oc]
  bucket     = aws_s3_bucket.infra_bucket.id
  acl        = "private"
}

# 3. Enable Versioning (Requirement: safeguards against accidental deletion)
resource "aws_s3_bucket_versioning" "infra_bucket_versioning" {
  bucket = aws_s3_bucket.infra_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 4. Lifecycle Rules
resource "aws_s3_bucket_lifecycle_configuration" "infra_bucket_lifecycle" {
  bucket = aws_s3_bucket.infra_bucket.id

  # Rule for tmp/ prefix: Remove objects after 30 days
  rule {
    id     = "tmp-cleanup"
    status = "Enabled"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }
  }

  # Rule for versioning and transitions: 
  # Transition previous versions to STANDARD_IA after 30 days
  # Expire noncurrent versions after 90 days
  rule {
    id     = "versioning-policy"
    status = "Enabled"

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

# 5. Public Access Block (Security Best Practice for Private Buckets)
resource "aws_s3_bucket_public_access_block" "infra_bucket_pab" {
  bucket = aws_s3_bucket.infra_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

