response:
To set up an Amazon S3 bucket with Object Lock enabled and a default retention policy, we need to perform the following steps:
1. Define the S3 bucket resource with the `object_lock_enabled` attribute set to `true`.
2. Configure the `aws_s3_bucket_object_lock_configuration` resource.
3. Within the configuration, specify the `rule` which includes `default_retention`.
4. Set the `mode` to `GOVERNANCE` and `days` to `90`.

```hcl
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket with Object Lock enabled at the bucket level
resource "aws_s3_bucket" "example" {
  bucket         = "example-bucket"
  force_destroy  = false

  # Object Lock must be enabled during bucket creation
  object_lock_enabled = true
}

# 2. Configure the Object Lock default retention settings
resource "aws_s3_bucket_object_lock_configuration" "example_lock" {
  bucket = aws_s3_bucket.example.id

  rule {
    default_retention {
      mode = "GOVERNANCE"
      days = 90
    }
  }
}

# 3. Best Practice: Enable Versioning (Required for Object Lock)
resource "aws_s3_bucket_versioning" "example_versioning" {
  bucket = aws_s3_bucket.example.id
  versioning_configuration {
    status = "Enabled"
  }
}
```

