To provision an Amazon S3 bucket with Object Lock and a default retention policy in Compliance mode, we need to follow these steps:
1. Define the S3 bucket resource with the `object_lock_enabled` attribute set to `true`.
2. Configure the `aws_s3_bucket_object_lock_configuration_v2` resource to establish the default retention rule (Compliance mode for 30 days).
3. Ensure the bucket has versioning enabled, as Object Lock requires versioning.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket with Object Lock enabled
resource "aws_s3_bucket" "example" {
  bucket              = "example-bucket"
  object_lock_enabled = true

  tags = {
    Name        = "example-bucket"
    Environment = "Production"
  }
}

# 2. Enable Versioning (Required for Object Lock)
resource "aws_s3_bucket_versioning" "example" {
  bucket = aws_s3_bucket.example.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 3. Configure the Object Lock Default Retention
resource "aws_s3_bucket_object_lock_configuration_v2" "example" {
  bucket = aws_s3_bucket.example.id

  rule {
    default_retention {
      mode = "COMPLIANCE"
      days = 30
    }
  }
}
