response:
To implement this infrastructure, we will use the `aws_s3_bucket` resource along with its associated management resources (`aws_s3_bucket_ownership_controls`, `aws_s3_bucket_public_access_block`, and `aws_s3_bucket_policy`). 

Note: Modern AWS S3 best practices require explicit configuration to allow public policies, and ACLs now require ownership controls to be defined.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create the S3 Bucket
resource "aws_s3_bucket" "my_bucket" {
  bucket = "my-unique-bucket-name-${random_id.suffix.hex}"

  tags = {
    Name        = "Referer Condition Bucket"
    Environment = "Dev"
  }
}

# Generate a random suffix for uniqueness
resource "random_id" "suffix" {
  byte_length = 4
}

# Set Ownership Controls (Required for ACLs in modern S3)
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.my_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Configure Public Access Block
# Since we are using a public-facing policy, we must disable these restrictions
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.my_bucket.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# Apply the Bucket ACL
resource "aws_s3_bucket_acl_v2" "example" {
  depends_on = [aws_s3_bucket_ownership_controls.example]

  bucket = aws_s3_bucket.my_bucket.id
  acl    = "private"
}

# Apply the Bucket Policy with Referer Condition
resource "aws_s3_bucket_policy" "allow_access_from_referer" {
  bucket = aws_s3_bucket.my_bucket.id

  # Ensure public access block is updated before applying policy
  depends_on = [aws_s3_bucket_public_access_block.example]

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowGetObjectByReferer"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.my_bucket.arn}/*"
        Condition = {
          StringLike = {
            "aws:Referer" = [
              "https://www.example.com/*",
              "https://example.com/*"
            ]
          }
        }
      }
    ]
  })
}

# Output the bucket name
output "bucket_name" {
  value = aws_s3_bucket.my_bucket.id
}
```

