response:
To implement this infrastructure, we will define the AWS provider, create the S3 bucket, initialize the SNS topic, and configure the IAM policy that allows S3 to publish to SNS. Finally, we link them together using the `aws_s3_bucket_notification` resource.

```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the SNS Topic
resource "aws_sns_topic" "s3_notification_topic" {
  name = "s3-event-notification-topic"
}

# 2. Create the S3 Bucket
resource "aws_s3_bucket" "bucket" {
  bucket = "your-bucket-name"
}

# 3. Create the IAM Policy Document for SNS
data "aws_iam_policy_document" "sns_topic_policy" {
  statement {
    effect  = "Allow"
    actions = ["SNS:Publish"]

    principals {
      type        = "Service"
      identifiers = ["s3.amazonaws.com"]
    }

    resources = [aws_sns_topic.s3_notification_topic.arn]

    condition {
      test     = "ArnLike"
      variable = "aws:SourceArn"
      values   = [aws_s3_bucket.bucket.arn]
    }
  }
}

# 4. Attach the Policy to the SNS Topic
resource "aws_sns_topic_policy" "default" {
  arn    = aws_sns_topic.s3_notification_topic.arn
  policy = data.aws_iam_policy_document.sns_topic_policy.json
}

# 5. Configure S3 Event Notifications
resource "aws_s3_bucket_notification" "bucket_notification" {
  bucket = aws_s3_bucket.bucket.id

  topic {
    topic_arn     = aws_sns_topic.s3_notification_topic.arn
    events        = ["s3:ObjectCreated:*"]
    filter_suffix = ".log"
  }

  # Ensure SNS policy is applied before S3 attempts to validate the notification
  depends_on = [aws_sns_topic_policy.default]
}
```

