extracted_code:
# --- Provider Configuration ---
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "terraform-vpc" }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = { Name = "private-subnet-${count.index}" }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# --- Security Groups ---
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-common-sg"
  description = "Allow internal traffic"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "efs_sg" {
  name        = "efs-sg"
  description = "Allow NFS traffic from EC2"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 2049
    to_port         = 2049
    protocol        = "tcp"
    security_groups = [aws_security_group.ec2_sg.id]
  }
}

# --- Storage (EFS) ---
resource "aws_efs_file_system" "shared_storage" {
  creation_token = "shared-storage"
  encrypted      = true

  tags = { Name = "SharedAppStorage" }
}

resource "aws_efs_mount_target" "mount" {
  count           = 2
  file_system_id  = aws_efs_file_system.shared_storage.id
  subnet_id       = aws_subnet.private[count.index].id
  security_groups = [aws_security_group.efs_sg.id]
}

# --- Compute (EC2) ---
data "aws_ssm_parameter" "amzn2_ami" {
  name = "/aws/service/ami-amazon-linux-latest/amzn2-ami-hvm-x86_64-gp2"
}

resource "aws_instance" "app_server" {
  count                  = 2
  ami                    = data.aws_ssm_parameter.amzn2_ami.value
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private[count.index].id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  # User data to mount EFS on boot
  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils
              mkdir -p /mnt/efs
              mount -t efs -o tls ${aws_efs_file_system.shared_storage.id}:/ /mnt/efs
              echo "${aws_efs_file_system.shared_storage.id}:/ /mnt/efs efs _netdev,tls 0 0" >> /etc/fstab
              EOF

  tags = {
    Name = "App-Server-${count.index + 1}"
  }

  depends_on = [aws_efs_mount_target.mount]
}

# --- Outputs ---
output "efs_dns_name" {
  value = aws_efs_file_system.shared_storage.dns_name
}

output "instance_private_ips" {
  value = aws_instance.app_server.*.private_ip
}

