# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the cluster
resource "aws_vpc" "memcached_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "memcached-vpc"
  }
}

# 2. Create private subnets in different AZs for high availability
resource "aws_subnet" "memcached_subnets" {
  count             = 2
  vpc_id            = aws_vpc.memcached_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)
  tags = {
    Name = "memcached-subnet-${count.index}"
  }
}

# 3. Create an ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "memcached_subnet_group" {
  name       = "memcached-subnet-group"
  subnet_ids = aws_subnet.memcached_subnets[*].id
}

# 4. Create a Security Group to allow access to Memcached (Default port 11211)
resource "aws_security_group" "memcached_sg" {
  name        = "memcached-sg"
  description = "Allow inbound traffic to Memcached"
  vpc_id      = aws_vpc.memcached_vpc.id

  ingress {
    from_port   = 11211
    to_port     = 11211
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Define a Parameter Group for custom Memcached settings
resource "aws_elasticache_parameter_group" "memcached_params" {
  name   = "memcached-params"
  family = "memcached1.6"

  parameter {
    name  = "max_item_size"
    value = "10485760" # Example: 10MB
  }
}

# 6. Deploy the ElastiCache Memcached Cluster
resource "aws_elasticache_cluster" "memcached_cluster" {
  cluster_id           = "terraform-memcached-cluster"
  engine               = "memcached"
  node_type            = "cache.t3.medium"
  num_cache_nodes      = 2
  parameter_group_name = aws_elasticache_parameter_group.memcached_params.name
  port                 = 11211
  subnet_group_name    = aws_elasticache_subnet_group.memcached_subnet_group.name
  security_group_ids   = [aws_security_group.memcached_sg.id]
  az_mode             = "cross-az" # Distributes nodes across availability zones

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Outputs
output "configuration_endpoint" {
  description = "The DNS name of the cache cluster without the port appended."
  value       = aws_elasticache_cluster.memcached_cluster.configuration_endpoint
}

