  # Passwords are not required for this mode
  authentication_mode {
    type = "iam"
  }

  # Access string defines what commands/keys the user can access within Redis
  # "on" enables the user, "~*" allows all keys, "+@all" allows all commands
  access_string = "on ~* +@all"

  tags = {
    Environment = "production"
    ManagedBy   = "Terraform"
  }
}

# Example of a User Group to associate the user with
resource "aws_elasticache_user_group" "example" {
  engine        = "REDIS"
  user_group_id = "iam-enabled-group"
  user_ids      = ["default", aws_elasticache_user.iam_user.user_id]
}

# Output the User ID for reference
output "elasticache_user_arn" {
  value       = aws_elasticache_user.iam_user.arn
  description = "The ARN of the ElastiCache user. Use this in IAM policies to grant access."
}

