  }
}

# 2. Subnets in us-east-1a and us-east-1b
resource "aws_subnet" "subnet_1a" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redshift-subnet-1a"
  }
}

resource "aws_subnet" "subnet_1b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "redshift-subnet-1b"
  }
}

# 3. Redshift Subnet Group (Critical for multi-AZ availability)
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-multi-az-subnet-group"
  subnet_ids = [aws_subnet.subnet_1a.id, aws_subnet.subnet_1b.id]

  tags = {
    Environment = "Production"
  }
}

# 4. Security Group
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow Redshift traffic"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Redshift Cluster
# Note: For production fault tolerance, multi-node clusters are recommended.
resource "aws_redshift_cluster" "fault_tolerant_cluster" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8Characters1!" # Use Secret Manager in production
