# Primary Region Provider
provider "aws" {
  region = "us-east-1"
}

# Secondary Region Provider for Replication
provider "aws" {
  alias  = "secondary"
  region = "us-east-2"
}

# --- PRIMARY REGION RESOURCES (us-east-1) ---

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id]
}

resource "aws_redshift_cluster" "primary" {
  cluster_identifier = "redshift-primary-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8Characters1!" # Use Secret Manager in production
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  skip_final_snapshot       = true

  # Enable Snapshot Copy to destination region
  snapshot_copy {
    destination_region = "us-east-2"
    retention_period   = 7
    grant_name         = aws_redshift_snapshot_copy_grant.secondary.snapshot_copy_grant_name
  }

  depends_on = [aws_redshift_snapshot_copy_grant.secondary]
}

# --- SECONDARY REGION RESOURCES (us-east-2) ---

# A snapshot copy grant is required in the destination region 
# if the snapshots are encrypted or if specified by policy.
resource "aws_redshift_snapshot_copy_grant" "secondary" {
  provider                  = aws.secondary
  snapshot_copy_grant_name  = "redshift-copy-grant-east-2"
}

# Output the cluster endpoint
output "redshift_endpoint" {
  value = aws_redshift_cluster.primary.endpoint
}

