To provision a Redshift cluster with an associated IAM role, we need to:
1.  Define the AWS provider.
2.  Create an IAM Role with a trust policy allowing Redshift to assume it.
3.  Attach a policy (e.g., `AmazonS3ReadOnlyAccess`) to the role so Redshift can access other services.
4.  Create a Redshift Subnet Group (required for VPC deployment).
5.  Provision the Redshift cluster and associate the IAM role ARN.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the IAM Role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "my-redshift-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach a policy to the role (e.g., S3 Read Only)
resource "aws_iam_role_policy_attachment" "redshift_s3_read" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# 3. Create a Redshift Subnet Group (Assumes default VPC subnets for this example)
# In a production environment, specify your private subnet IDs here.
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = data.aws_subnets.default.ids
}

# 4. Provision the Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8Characters1!" # Use secrets management in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Attach the IAM Role created above
  iam_roles = [aws_iam_role.redshift_role.arn]

  cluster_subnet_group_name    = aws_redshift_subnet_group.main.name
  skip_final_snapshot          = true
  publicly_accessible          = true
}

# Output the Cluster Endpoint
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}
