  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet.id]
}

# --- Redshift Cluster ---
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8Characters123!" # In production, use secrets manager
  node_type          = "dc2.large"
  cluster_type       = "multi-node"
  number_of_nodes    = 2

  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  skip_final_snapshot       = true
}

# --- Redshift Resource Policy ---
# This policy grants specific permissions to another AWS Account/Principal 
# for resources like 'Data Shares' or 'Namespaces' within the cluster.
resource "aws_redshift_resource_policy" "example" {
  resource_arn = aws_redshift_cluster.example.arn
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "EnableRedshiftDataApi"
        Effect = "Allow"
        Principal = {
          AWS = "*" # Provide a specific IAM ARN or Account ID in production
        }
        Action   = "redshift:GetClusterCredentials"
        Resource = aws_redshift_cluster.example.arn
      }
    ]
  })
}

# --- Outputs ---
output "cluster_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

output "cluster_arn" {
  value = aws_redshift_cluster.example.arn
}
