response:
To fulfill your request, we need to define four main components in Terraform:
1.  **The Archive File**: To zip the `lambda.js` file into a deployment package.
2.  **The IAM Role**: To provide the Lambda function with an execution identity.
3.  **The Trust Policy**: Attached to the role to allow the AWS Lambda service to assume it.
4.  **The Lambda Function**: Configured with Node.js 18, the specified handler, and the zipped source code.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a ZIP archive of the lambda.js file
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function_payload.zip"
}

# 2. Define the IAM Role for the Lambda Function
resource "aws_iam_role" "iam_for_lambda" {
  name = "my_lambda_role"

  # 3. Define the Trust Policy (Assume Role Policy)
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# 4. Define the AWS Lambda Resource
resource "aws_lambda_function" "test_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "my_node18_lambda"
  role          = aws_iam_role.iam_for_lambda.arn

  # Specify the handler (file_name.export_function_name)
  handler       = "lambda.handler"

  # Source code hash ensures the function updates when the JS file changes
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "nodejs18.x"

  environment {
    variables = {
      ENV = "production"
    }
  }
}

# Optional: Add CloudWatch Logs permissions to the IAM Role
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}
