# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an IAM Role for the Lambda Function
resource "aws_iam_role" "iam_for_lambda" {
  name = "example_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action    = "sts:AssumeRole"
        Effect    = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach the basic execution policy to the role
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Create a ZIP archive containing the Lambda code
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function_payload.zip"

  source {
    content  = <<EOF
def lambda_handler(event, context):
    print("Lambda invoked by Terraform!")
    return {
        'statusCode': 200,
        'body': 'Hello from example_lambda!'
    }
EOF
    filename = "index.py"
  }
}

# 4. Create the Lambda Function resource
resource "aws_lambda_function" "example_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "example_lambda"
  role          = aws_iam_role.iam_for_lambda.arn
  handler       = "index.lambda_handler"

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime          = "python3.9"

  depends_on = [aws_iam_role_policy_attachment.lambda_logs]
}

# 5. Invoke the Lambda Function
resource "aws_lambda_invocation" "example_lambda_invocation" {
  function_name = aws_lambda_function.example_lambda.function_name

  input = jsonencode({
    key1 = "value1"
    key2 = "value2"
  })

  # Note: By default, this invokes the function during every 'terraform apply'.
}

# 6. Output the result of the invocation
output "lambda_response" {
  description = "The result of the lambda function invocation"
  value       = jsondecode(aws_lambda_invocation.example_lambda_invocation.result)
}

