  name = "lambda_interval_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# 2. Attach basic execution policy (logging) to the role
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Create a deployment package (Python Example)
# This assumes you have a file named 'lambda_function.py' in the same directory
resource "archive_file" "lambda_zip" {
  type        = "zip"
  source_content = "def lambda_handler(event, context):
    print('Hello from Terraform!')"
  source_path = "index.py"
  output_path = "lambda_function_payload.zip"
}

# 4. Create the Lambda Function
resource "aws_lambda_function" "interval_lambda" {
  filename      = "lambda_function_payload.zip"
  function_name = "scheduled_15min_task"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.lambda_handler"
  runtime       = "python3.9"

  source_code_hash = archive_file.lambda_zip.output_base64sha256
}

# 5. Create the CloudWatch Event Rule (EventBridge)
resource "aws_cloudwatch_event_rule" "every_15_minutes" {
  name                = "run-every-15-minutes"
  description         = "Triggers every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# 6. Set the Lambda as the Target for the Rule
resource "aws_cloudwatch_event_target" "check_lambda_every_15_minutes" {
  rule      = aws_cloudwatch_event_rule.every_15_minutes.name
  target_id = "lambda"
  arn       = aws_lambda_function.interval_lambda.arn
}

# 7. Grant Permission for EventBridge to Call Lambda
resource "aws_lambda_permission" "allow_cloudwatch_to_call_lambda" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.interval_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.every_15_minutes.arn
}

