To achieve this, we need to use **Amazon EventBridge** (formerly CloudWatch Events). We will create a rule that triggers on the `EC2 AMI State Change` event when the state becomes `available`. We will then create a permission for the Lambda function to allow EventBridge to invoke it, and finally, set the Lambda function as the target for the event rule.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Reference the existing Lambda Function (assuming it exists, or defining a skeleton)
resource "aws_lambda_function" "test_lambda" {
  function_name    = "test_lambda"
  role             = aws_iam_role.iam_for_lambda.arn
  handler          = "index.handler"
  runtime          = "nodejs18.x"
  filename         = "lambda_function_payload.zip" # Ensure this file exists or use a dummy
}

# 2. Create the EventBridge Rule to detect new AMIs
resource "aws_cloudwatch_event_rule" "ami_creation_rule" {
  name        = "capture-new-ec2-ami"
  description = "Triggers when a new EC2 AMI is created and becomes available"

  event_pattern = jsonencode({
    "source": ["aws.ec2"],
    "detail-type": ["EC2 AMI State Change"],
    "detail": {
      "state": ["available"]
    }
  })
}

# 3. Set the Lambda Function as the Target for the EventBridge Rule
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.ami_creation_rule.name
  target_id = "SendToLambda"
  arn       = aws_lambda_function.test_lambda.arn
}

# 4. Grant EventBridge Permission to invoke the Lambda Function
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.test_lambda.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.ami_creation_rule.arn
}

# Required IAM Role for the Lambda to exist
resource "aws_iam_role" "iam_for_lambda" {
  name = "iam_for_lambda_ami_trigger"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}
```

