response:
To build an AWS Lambda function that executes a local file named `lambda.js`, we need to define several resources:
1.  **IAM Role**: To give the Lambda function permission to run and log to CloudWatch.
2.  **Archive File**: To package the `lambda.js` file into a ZIP archive required by AWS.
3.  **Lambda Function**: The compute resource itself, configured with the Node.js runtime.
4.  **CloudWatch Log Group**: For monitoring the function's output.

The following HCL configuration implements these steps:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the IAM Role for the Lambda function
resource "aws_iam_role" "iam_for_lambda" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach the basic execution policy to allow logging to CloudWatch
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Create a ZIP archive containing the lambda.js file
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function_payload.zip"
}

# 4. Define the Lambda Function
resource "aws_lambda_function" "my_lambda" {
  filename      = data.archive_file.lambda_zip.output_path
  function_name = "my_javascript_lambda"
  role          = aws_iam_role.iam_for_lambda.arn

  # "lambda.handler" assumes your lambda.js exports a function named "handler"
  handler       = "lambda.handler" 

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "nodejs18.x"

  environment {
    variables = {
      NODE_ENV = "production"
    }
  }
}

# 5. Create a Log Group for the Lambda function output
resource "aws_cloudwatch_log_group" "lambda_log_group" {
  name              = "/aws/lambda/${aws_lambda_function.my_lambda.function_name}"
  retention_in_days = 14
}

# Output the Lambda ARN
output "lambda_arn" {
  value = aws_lambda_function.my_lambda.arn
}
```

