  comparison_operator       = "GreaterThanOrEqualToThreshold"
  evaluation_periods        = "2"
  metric_name               = "CPUUtilization"
  namespace                 = "AWS/EC2"
  period                    = "120"
  statistic                 = "Average"
  threshold                = "80"
  alarm_description         = "This metric monitors ec2 cpu utilization"

  # Ensure no actions occur if data is insufficient
  treat_missing_data        = "notBreaching"
  insufficient_data_actions = []

  # Example dimensions filter - identifying which instance to monitor
  dimensions = {
    InstanceId = "i-0123456789abcdef0"
  }

  # Ensure the alarm doesn't try to trigger actions if none are defined
  actions_enabled = true
}

# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the DynamoDB Table
resource "aws_dynamodb_table" "main_table" {
  name           = "UserActivityLogs"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "UserId"
  range_key      = "Timestamp"

  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  attribute {
    name = "ActionType"
    type = "S"
  }

  # Add a Global Secondary Index (GSI)
  global_secondary_index {
    name               = "ActionTypeIndex"
    hash_key           = "ActionType"
    range_key          = "Timestamp"
    projection_type    = "ALL"
  }

  tags = {
    Environment = "Production"
    Project     = "TerraformAI-Demo"
  }
}

# 2. Enable Contributor Insights for the base table
resource "aws_dynamodb_table_contributor_insights" "table_insights" {
  table_name = aws_dynamodb_table.main_table.name
}

# 3. Enable Contributor Insights specifically for the Global Secondary Index
resource "aws_dynamodb_table_contributor_insights" "gsi_insights" {
  table_name = aws_dynamodb_table.main_table.name
  index_name = "ActionTypeIndex"

  # Ensure the table insights are processed in order if needed, 
  # though they can usually be created in parallel.
  depends_on = [aws_dynamodb_table.main_table]
}

# Output the table name and status
output "dynamodb_table_name" {
  value = aws_dynamodb_table.main_table.name
}

output "contributor_insights_status" {
  value = aws_dynamodb_table_contributor_insights.table_insights.id
}

response:
To set up AWS DynamoDB Contributor Insights, we need to define the primary DynamoDB table and then associate the `aws_dynamodb_table_contributor_insights` resource with it. Contributor Insights can be enabled for the base table and/or its Global Secondary Indexes (GSIs).

The following configuration creates a DynamoDB table with a Global Secondary Index and enables Contributor Insights for both the base table and the GSI.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the DynamoDB Table
resource "aws_dynamodb_table" "main_table" {
  name           = "UserActivityLogs"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "UserId"
  range_key      = "Timestamp"

  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  attribute {
    name = "ActionType"
    type = "S"
  }

  # Add a Global Secondary Index (GSI)
  global_secondary_index {
    name               = "ActionTypeIndex"
    hash_key           = "ActionType"
    range_key          = "Timestamp"
    projection_type    = "ALL"
  }

  tags = {
    Environment = "Production"
    Project     = "TerraformAI-Demo"
  }
}

# 2. Enable Contributor Insights for the base table
resource "aws_dynamodb_table_contributor_insights" "table_insights" {
  table_name = aws_dynamodb_table.main_table.name
}

# 3. Enable Contributor Insights specifically for the Global Secondary Index
resource "aws_dynamodb_table_contributor_insights" "gsi_insights" {
  table_name = aws_dynamodb_table.main_table.name
  index_name = "ActionTypeIndex"

  # Ensure the table insights are processed in order if needed, 
  # though they can usually be created in parallel.
  depends_on = [aws_dynamodb_table.main_table]
}

# Output the table name and status
output "dynamodb_table_name" {
  value = aws_dynamodb_table.main_table.name
}

output "contributor_insights_status" {
  value = aws_dynamodb_table_contributor_insights.table_insights.id
}
```

