response:
To set up a DynamoDB global table across multiple regions, we must define providers for each region and use the `aws_dynamodb_table` resource with a `replica` configuration. 

Note: DynamoDB Global Tables (version 2019.11.21) require Pay-Per-Request (On-Demand) billing or specific autoscaling settings, and Streams must be enabled.

```hcl
# Configure the AWS Providers for each required region
provider "aws" {
  alias  = "us_east_1"
  region = "us-east-1"
}

provider "aws" {
  alias  = "us_west_1"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us_west_2"
  region = "us-west-2"
}

# Define the DynamoDB Global Table
# The resource is created in the primary region with replicas defined for the others
resource "aws_dynamodb_table" "global_table" {
  provider         = aws.us_east_1
  name             = "GlobalMultiRegionTable"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "id"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "id"
    type = "S"
  }

  # Replica in us-west-1
  replica {
    region_name = "us-west-1"
  }

  # Replica in us-west-2
  replica {
    region_name = "us-west-2"
  }

  tags = {
    Environment = "Production"
    Terraform   = "true"
  }
}

# Output the ARNs for verification
output "table_arn" {
  value       = aws_dynamodb_table.global_table.arn
  description = "The ARN of the DynamoDB table"
}

output "table_stream_arn" {
  value       = aws_dynamodb_table.global_table.stream_arn
  description = "The ARN of the Table Stream"
}
```

