To set up a DynamoDB global table with a replica, we need to define a resource that specifies the primary region and a `replica` block for each additional region. Note that for a Global Table (v2), the provider must be configured for the primary region, and the table must have `billing_mode` set to `PAY_PER_REQUEST` or have `provisioned_capacity` configured with auto-scaling to ensure consistency across regions.

Here is the complete configuration:

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# The primary region provider
provider "aws" {
  region = "us-east-1"
}

# A secondary provider for the replica region (required for internal validation)
provider "aws" {
  alias  = "replica"
  region = "us-west-2"
}

# DynamoDB Global Table (Standard V2)
resource "aws_dynamodb_table" "global_example" {
  name             = "GlobalUserTable"
  billing_mode     = "PAY_PER_REQUEST" # Recommended for Global Tables
  hash_key         = "UserId"
  range_key        = "Timestamp"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  # Add a replica in the us-west-2 region
  # Terraform will handle the creation of the table in the secondary region
  replica {
    region_name = "us-west-2"
    # Point cleanup or deletion protection settings if needed
    point_in_time_recovery = true
    propagate_tags          = true
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Output the ARN of the primary table
output "table_arn" {
  value       = aws_dynamodb_table.global_example.arn
  description = "The ARN of the DynamoDB Global Table"
}
```

