    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      },
    ]
  })
}

# 2. IAM Policy to allow DAX to access DynamoDB
resource "aws_iam_role_policy" "dax_policy" {
  name = "DAXAccessPolicy"
  role = aws_iam_role.dax_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "dynamodb:*"
        Effect   = "Allow"
        Resource = "*"
      },
    ]
  })
}

# 3. DAX Subnet Group (Requires existing subnet IDs)
# Replace subnet_ids with your specific VPC subnet IDs
resource "aws_dax_subnet_group" "example" {
  name       = "example-dax-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"]
}

# 4. Security Group for DAX
