  name        = "dax-cluster-sg"
  description = "Allow inbound traffic to DAX"

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"] # Adjust to your VPC CIDR
  }
}

# 5. DAX Cluster Provisioning
resource "aws_dax_cluster" "example" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  node_type          = "dax.r4.large"
