provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the DAX Cluster
resource "aws_vpc" "dax_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dax-vpc"
  }
}

# 2. Create Subnets in different Availability Zones
resource "aws_subnet" "dax_subnet_1" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "dax-subnet-1"
  }
}

resource "aws_subnet" "dax_subnet_2" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "dax-subnet-2"
  }
}

# 3. Create the DAX Subnet Group
# This groups the subnets where the DAX nodes will be provisioned
resource "aws_dax_subnet_group" "example" {
  name        = "my-dax-subnet-group"
  description = "A user-defined subnet group for the DAX cluster"

  # Reference the IDs of the subnets created above
  subnet_ids = [
    aws_subnet.dax_subnet_1.id,
    aws_subnet.dax_subnet_2.id
  ]
}

# Output the Subnet Group ID
output "dax_subnet_group_id" {
  value       = aws_dax_subnet_group.example.id
  description = "The ID of the DAX Subnet Group"
}

