# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a Workable VPC for SageMaker
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "sagemaker-vpc"
  }
}

resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "sagemaker-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "sagemaker-subnet-2"
  }
}

# 2. Create IAM Role for SageMaker Domain Execution
resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-domain-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "sagemaker.amazonaws.com"
      }
    }]
  })
}

# Attach the standard SageMaker FullAccess policy
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. Create the SageMaker Domain
resource "aws_sagemaker_domain" "example" {
  domain_name = "my-sagemaker-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "system"
      }
    }

    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }
  }

  # Configures how users access the internet (PublicInternetOnly or VpcOnly)
  app_network_access_type = "PublicInternetOnly"

  tags = {
    Environment = "Dev"
  }
}

# 4. Create an example User Profile within the Domain
resource "aws_sagemaker_user_profile" "example_user" {
  domain_id         = aws_sagemaker_domain.example.id
  user_profile_name = "data-scientist-1"

  user_settings {
    execution_role = aws_iam_role.sagemaker_execution_role.arn
  }
}

# Output the Domain ID and URL
output "sagemaker_domain_id" {
  value = aws_sagemaker_domain.example.id
}

output "sagemaker_domain_url" {
  value = aws_sagemaker_domain.example.url
}

