  }
}

resource "aws_subnet" "sagemaker_subnet" {
  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "sagemaker-subnet"
  }
}

# 2. IAM Role for the SageMaker User
resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker-user-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. Create the SageMaker Domain (Prerequisite for a User Profile)
resource "aws_sagemaker_domain" "example_domain" {
  domain_name = "example-sagemaker-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = [aws_subnet.sagemaker_subnet.id]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_role.arn

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "system"
      }
    }
  }
}

# 4. Create the SageMaker User Profile
resource "aws_sagemaker_user_profile" "example_user" {
  domain_id         = aws_sagemaker_domain.example_domain.id
  user_profile_name = "data-scientist-alice"

  user_settings {
    execution_role = aws_iam_role.sagemaker_role.arn

    kernel_gateway_app_settings {
      default_resource_spec {
        instance_type       = "ml.t3.medium"
        sagemaker_image_arn = "arn:aws:sagemaker:us-east-1:081325390128:image/jupyter-server-3" # Example AWS managed image ARN
      }
    }

    jupyter_server_app_settings {
      default_resource_spec {
        instance_type = "ml.t3.medium"
      }
    }
  }

  tags = {
    Environment = "Development"
    User        = "Alice"
  }
}

# Output the URL for the user to access SageMaker Studio
output "sagemaker_studio_url" {
  value = aws_sagemaker_domain.example_domain.url
}

output "user_profile_arn" {
  value = aws_sagemaker_user_profile.example_user.arn
}

