# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
}

resource "aws_subnet" "sagemaker_subnet" {
  vpc_id     = aws_vpc.sagemaker_vpc.id
  cidr_block = "10.0.1.0/24"
}

# 2. IAM Role for SageMaker
resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker-space-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "sagemaker.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. SageMaker Domain
resource "aws_sagemaker_domain" "example" {
  domain_name = "example-domain"
  auth_mode   = "IAM"
  vpc_id      = aws_vpc.sagemaker_vpc.id
  subnet_ids  = [aws_subnet.sagemaker_subnet.id]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_role.arn
  }
}

# 4. SageMaker Space
# This creates a shared space for JupyterLab or Code Editor
resource "aws_sagemaker_space" "example_space" {
  domain_id  = aws_sagemaker_domain.example.id
  space_name = "ml-collaboration-space"

  space_settings {
    app_type = "JupyterLab" # Options include JupyterLab or CodeEditor

    jupyter_lab_app_settings {
      default_resource_spec {
        instance_type       = "ml.t3.medium"
        sagemaker_image_arn = "arn:aws:sagemaker:us-east-1:081325390128:image/sagemaker-distribution-cpu" # Standard Amazon Linux SageMaker image
      }
    }
  }

  space_sharing_settings {
    sharing_type = "Private" # Can be Private or Shared
  }
}

output "sagemaker_space_id" {
  value       = aws_sagemaker_space.example_space.id
  description = "The ID of the SageMaker Space"
}

output "sagemaker_space_arn" {
  value       = aws_sagemaker_space.example_space.arn
  description = "The ARN of the SageMaker Space"
}

