# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an IAM Role for SageMaker to use the image
resource "aws_iam_role" "sagemaker_image_role" {
  name = "sagemaker-image-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach the basic SageMaker execution policy
resource "aws_iam_role_policy_attachment" "sagemaker_policy" {
  role       = aws_iam_role.sagemaker_image_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. Define the SageMaker Image
# This acts as a container/logical grouping for image versions
resource "aws_sagemaker_image" "example" {
  image_name   = "custom-data-science-image"
  role_arn     = aws_iam_role.sagemaker_image_role.arn
  display_name = "Custom Data Science Environment"
  description  = "A custom environment for JupyterLab"

  tags = {
    Environment = "Development"
  }
}

# 4. Create a SageMaker Image Version
# This points to the actual Docker image URI in ECR
resource "aws_sagemaker_image_version" "example_v1" {
  image_name = aws_sagemaker_image.example.image_name
  base_image = "123456789012.dkr.ecr.us-east-1.amazonaws.com/my-custom-repo:latest"

  # Ensure the image exists before creating the version
  depends_on = [aws_sagemaker_image.example]
}

# 5. Optional: Define App Image Config 
# This tells SageMaker how to run the image (Kernel specs, UID/GID)
resource "aws_sagemaker_app_image_config" "example" {
  app_image_config_name = "custom-kernel-config"

  kernel_gateway_image_config {
    kernel_spec {
      name         = "python3"
      display_name = "Python 3 (Custom)"
    }

    file_system_config {
      mount_path = "/home/sagemaker-user"
      default_uid = 1000
      default_gid = 100
    }
  }
}

