  role       = aws_iam_role.sagemaker_image_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 3. Define the SageMaker Image
# This acts as a container/logical grouping for image versions
resource "aws_sagemaker_image" "example" {
  image_name   = "custom-data-science-image"
  role_arn     = aws_iam_role.sagemaker_image_role.arn
  display_name = "Custom Data Science Environment"
