# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Get the AWS Partition, Region, and Account ID for dynamic ARN construction
data "aws_partition" "current" {}
data "aws_region" "current" {}
data "aws_caller_identity" "current" {}

# 2. Identify the KMeans built-in algorithm container URI
# SageMaker built-in algorithms use specific registry IDs per region.
# Registry ID for us-east-1 is 382416733822
locals {
  # Format: {account_id}.dkr.ecr.{region}.amazonaws.com/{repository_name}:{tag}
  # For kmeans, the repo name is "kmeans" and tag is "1" or "latest"
  kmeans_image_uri = "382416733822.dkr.ecr.${data.aws_region.current.name}.${data.aws_partition.current.dns_suffix}/kmeans:1"
}

# 3. Create an IAM Role for SageMaker execution
resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker-kmeans-model-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach the AmazonSageMakerFullAccess policy (for demonstration; scope down for production)
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 4. Provision the SageMaker Model
resource "aws_sagemaker_model" "kmeans_model" {
  name               = "kmeans-model-v1"
  execution_role_arn = aws_iam_role.sagemaker_role.arn

  primary_container {
    image = local.kmeans_image_uri

    # Example: Reference a model artifact (S3 path where your trained model.tar.gz is stored)
    # This is required if you are hosting a trained model.
    model_data_url = "s3://my-sagemaker-bucket-${data.aws_caller_identity.current.account_id}/output/kmeans/model.tar.gz"

    environment = {
      "SAGEMAKER_PROGRAM" = "kmeans"
    }
  }

  tags = {
    Environment = "Development"
    Algorithm   = "KMeans"
  }
}

# Output the Model ARN
output "sagemaker_model_arn" {
  value       = aws_sagemaker_model.kmeans_model.arn
  description = "The ARN of the created SageMaker Model"
}

