  kmeans_image_uri = "382416733822.dkr.ecr.${data.aws_region.current.name}.${data.aws_partition.current.dns_suffix}/kmeans:1"
}

# 3. Create an IAM Role for SageMaker execution
resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker-kmeans-model-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
