response:
To generate a SageMaker endpoint configuration for an existing model, we need to define two main resources:
1.  **`aws_sagemaker_endpoint_configuration`**: This resource defines how the model should be hosted, including the instance type, count, and the model name to be used.
2.  **`aws_sagemaker_endpoint`**: This resource actually deploys the configuration to a web-accessible URL.

Below is the complete Terraform configuration.

```hcl
# Terraform Configuration for SageMaker Endpoint

provider "aws" {
  region = "us-east-1"
}

# 1. Define the SageMaker Endpoint Configuration
# This links to an existing model (replace 'existing-model-name' with your model's name)
resource "aws_sagemaker_endpoint_configuration" "this" {
  name = "my-model-endpoint-config"

  production_variants {
    variant_name           = "AllTraffic"
    model_name            = "existing-model-name" # The name of your pre-existing SageMaker Model
    initial_instance_count = 1
    instance_type          = "ml.t2.medium"
    initial_variant_weight = 1.0
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# 2. Deploy the SageMaker Endpoint
# This creates the physical infrastructure based on the configuration above
resource "aws_sagemaker_endpoint" "this" {
  name                 = "my-model-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.this.name

  tags = {
    Name = "SageMaker-Model-Endpoint"
  }
}

# Output the Endpoint ARN for reference
output "sagemaker_endpoint_arn" {
  value       = aws_sagemaker_endpoint.this.arn
  description = "The Amazon Resource Name of the SageMaker endpoint."
}
```

