response:
To set up an Amazon SageMaker endpoint, we need to define three primary resources:
1.  **SageMaker Model**: This points to the S3 artifacts and the Docker container image used for inference.
2.  **SageMaker Endpoint Configuration**: This defines the hardware requirements (instance type and count) and the variant weights.
3.  **SageMaker Endpoint**: This is the actual RESTful HTTPS endpoint that serves the model.

We also need an IAM role that allows SageMaker to access S3 buckets and CloudWatch logs.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for SageMaker
resource "aws_iam_role" "sagemaker_role" {
  name = "sagemaker_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      },
    ]
  })
}

# Attach SageMaker Full Access Policy (For production, use more restrictive policies)
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# 2. SageMaker Model
# Note: You must replace the image and model_data_url with your actual values
resource "aws_sagemaker_model" "example_model" {
  name               = "example-model"
  execution_role_arn = aws_iam_role.sagemaker_role.arn

  primary_container {
    # Example using a pre-built Scikit-learn image from AWS
    image          = "683313684715.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"
    model_data_url = "s3://my-sagemaker-bucket/model-artifacts/model.tar.gz"
  }
}

# 3. SageMaker Endpoint Configuration
resource "aws_sagemaker_endpoint_configuration" "example_config" {
  name = "example-endpoint-config"

  production_variants {
    variant_name           = "all-traffic"
    model_name             = aws_sagemaker_model.example_model.name
    initial_instance_count = 1
    instance_type          = "ml.t2.medium"
    initial_variant_weight = 1
