To provision an AWS Lambda function with the specified requirements, we need to define several resources:
1.  **IAM Role**: To give the Lambda service permission to execute.
2.  **IAM Policy Attachment**: To allow the Lambda to write logs to CloudWatch (standard practice).
3.  **Archive File**: A data source to zip the `lambda.js` file into a deployment package.
4.  **Lambda Function**: The main resource using the Node.js 18 runtime and identifying the handler.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define the IAM Role for the Lambda function
resource "aws_iam_role" "iam_for_lambda" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Sid    = ""
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

# 2. Attach basic execution policy for CloudWatch Logs
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.iam_for_lambda.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 3. Create a zip archive of the lambda.js source file
# Note: The 'source_file' points to your local lambda.js
data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_function_payload.zip"
}

# 4. Provision the Lambda Function
resource "aws_lambda_function" "nodejs_lambda" {
  filename      = "lambda_function_payload.zip"
  function_name = "my_nodejs18_lambda"
  role          = aws_iam_role.iam_for_lambda.arn

  # index.js is the filename, handler is the exported function name
  handler       = "index.handler" 

  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  runtime = "nodejs18.x"

  environment {
    variables = {
      NODE_ENV = "production"
    }
  }
}
