provider "aws" {
  region = "us-east-1"
}

# 1. Create VPC and Network Infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "terraform-vpc"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

# 2. Create Subnets in us-east-1a and us-east-1b
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "Subnet-1a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "Subnet-1b"
  }
}

# 3. Fetch the most recent Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

# 4. Define local variables for dry iteration
locals {
  instances = {
    "instance_a" = aws_subnet.subnet_a.id
    "instance_b" = aws_subnet.subnet_b.id
  }
}

# 5. Launch EC2 Instances
resource "aws_instance" "app_server" {
  for_each      = local.instances
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = each.value

  tags = {
    Name = "EC2-${each.key}"
  }
}

# 6. Create 50 GB EBS Volumes
resource "aws_ebs_volume" "extra_storage" {
  for_each          = local.instances
  availability_zone = aws_instance.app_server[each.key].availability_zone
  size             = 50
  type             = "gp2"

  tags = {
    Name = "Storage-${each.key}"
  }
}

# 7. Attach Volumes to Instances
resource "aws_volume_attachment" "ebs_att" {
  for_each    = local.instances
  device_name = "/dev/sdh"
  volume_id   = aws_ebs_volume.extra_storage[each.key].id
  instance_id = aws_instance.app_server[each.key].id
}

