extracted_code:
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Network Configuration
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "efs-demo-vpc" }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = { Name = "private-subnet-${count.index}" }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# 2. Security Groups
resource "aws_security_group" "ec2_sg" {
  name        = "ec2-efs-sg"
  description = "Allow SSH and EFS outbound"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "efs_sg" {
  name        = "efs-mount-sg"
  description = "Allow NFS traffic from EC2"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 2049
    to_port         = 2049
    protocol        = "tcp"
    security_groups = [aws_security_group.ec2_sg.id]
  }
}

# 3. Amazon EFS File System
resource "aws_efs_file_system" "shared_storage" {
  creation_token = "my-shared-storage"
  encrypted      = true

  tags = { Name = "SharedEFS" }
}

resource "aws_efs_mount_target" "mount" {
  count           = 2
  file_system_id  = aws_efs_file_system.shared_storage.id
  subnet_id       = aws_subnet.private[count.index].id
  security_groups = [aws_security_group.efs_sg.id]
}

# 4. EC2 Instances
data "aws_ssm_parameter" "amazon_linux_2023" {
  name = "/aws/service/ami-amazon-linux-latest/al2023-ami-kernel-6.1-x86_64"
}

resource "aws_instance" "app_server" {
  count                  = 2
  ami                    = data.aws_ssm_parameter.amazon_linux_2023.value
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private[count.index].id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  # User data to install efs-utils and mount the drive
  user_data = <<-EOF
              #!/bin/bash
              dnf install -y amazon-efs-utils
              mkdir -p /mnt/efs
              echo "${aws_efs_file_system.shared_storage.id}:/ /mnt/efs efs _netdev,tls 0 0" >> /etc/fstab
              mount -a
              EOF

  tags = {
    Name = "EFS-Client-${count.index}"
  }

  # Ensure mount targets exist before instances try to mount them
  depends_on = [aws_efs_mount_target.mount]
}

