# 1. Define the Provider
provider "aws" {
  region = "us-east-1"
}

# 2. Create the ElastiCache User with IAM Authentication
# The user_id must be unique, and authentication_mode must be 'iam'
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-authenticated-user"
  user_name     = "iam_user_name"
  access_string = "on ~* +@all" # Adjust access permissions as needed
  engine        = "REDIS"

  authentication_mode {
    type = "iam"
  }
}

# 3. Create a User Group and assign the IAM user to it
resource "aws_elasticache_user_group" "iam_user_group" {
  engine        = "REDIS"
  user_group_id = "iam-user-group"
  user_ids      = [aws_elasticache_user.iam_user.user_id]
}

# 4. Create the ElastiCache Replication Group (Redis)
# IAM Auth requires Transit Encryption (transit_encryption_enabled = true)
resource "aws_elasticache_replication_group" "redis_cluster" {
  replication_group_id       = "iam-enabled-redis"
  description                = "Redis cluster with IAM Authentication"
  node_type                  = "cache.t3.medium"
  num_cache_clusters         = 1
  port                       = 6379
  engine                     = "redis"
  engine_version             = "7.0"
  parameter_group_name       = "default.redis7"

  transit_encryption_enabled = true
  at_rest_encryption_enabled = true

  # Link the User Group to the cluster
  user_group_ids = [aws_elasticache_user_group.iam_user_group.user_group_id]
}

# 5. Create an IAM Policy to allow a client (EC2/Lambda) to connect
# The Resource ARN follows: arn:aws:elasticache:<region>:<account>:user:<user_id>
resource "aws_iam_policy" "elasticache_connect" {
  name        = "ElastiCacheConnectPolicy"
  description = "Allows connection to ElastiCache using IAM"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "elasticache:Connect"
        Effect   = "Allow"
        Resource = [aws_elasticache_user.iam_user.arn]
      }
    ]
  })
}

# 6. Create an IAM Role for the Application (e.g., EC2 or Lambda)
resource "aws_iam_role" "app_role" {
  name = "app-elasticache-iam-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the connect policy to the role
resource "aws_iam_role_policy_attachment" "attach_connect_policy" {
  role       = aws_iam_role.app_role.name
  policy_arn = aws_iam_policy.elasticache_connect.arn
}

# Output the Replication Group Primary Endpoint
output "redis_endpoint" {
  value = aws_elasticache_replication_group.redis_cluster.primary_endpoint_address
}

