response:
To set up an Amazon MSK (Managed Streaming for Apache Kafka) cluster in the `us-east-1` region, we need to configure several dependencies: a VPC with at least three subnets (best practice for highly available MSK), a security group to allow Kafka traffic, and the MSK cluster resource itself.

The following configuration defines:
1.  **VPC and Subnets**: Three subnets in different Availability Zones.
2.  **Security Group**: Permitting the default Kafka client port (9092).
3.  **MSK Cluster**: Configured with 3 broker nodes across the subnets using `kafka.m5.large` instances.

```hcl
# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure
data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

# 2. Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name        = "msk-broker-sg"
  description = "Allow Kafka traffic"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Amazon MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster-demo"
  kafka_version          = "3.2.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnets[0].id,
      aws_subnet.msk_subnets[1].id,
      aws_subnet.msk_subnets[2].id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
      in_cluster    = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# 4. CloudWatch Log Group for MSK logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "msk-broker-logs"
}

# Outputs
output "zookeeper_connect_string" {
  value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
  value = aws_msk_cluster.example.bootstrap_brokers_tls
}
