provider "aws" {
  region = "us-east-1"
}

# 1. Networking Infrastructure
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags                 = { Name = "msk-vpc" }
}

resource "aws_subnet" "msk_subnets" {
  count             = 2
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = count.index == 0 ? "us-east-1a" : "us-east-1b"
  tags              = { Name = "msk-subnet-${count.index}" }
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-sg"
  vpc_id      = aws_vpc.msk_vpc.id
  description = "Allow inbound traffic for MSK"

  ingress {
    from_port   = 9092
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

# 2. Firehose Destination (S3 Bucket)
resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket        = "msk-broker-logs-destination-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 3. Kinesis Data Firehose IAM Roles
resource "aws_iam_role" "firehose_role" {
  name = "firehose-msk-logs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose-s3-access"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = [
        "s3:AbortMultipartUpload",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:ListBucket",
        "s3:ListBucketMultipartUploads",
        "s3:PutObject"
      ]
      Effect   = "Allow"
      Resource = [
        aws_s3_bucket.msk_logs_bucket.arn,
        "${aws_s3_bucket.msk_logs_bucket.arn}/*"
      ]
    }]
  })
}

# 4. Kinesis Data Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_logs_stream" {
  name        = "msk-broker-logs-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn
  }
}

# 5. MSK Cluster Configuration
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-msk-cluster"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 2

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnets[0].id,
      aws_subnet.msk_subnets[1].id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  logging_info {
    broker_logs {
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs_stream.name
      }
    }
  }

  tags = {
    Environment = "production"
  }
}

output "zookeeper_connect_string" {
  value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
  value = aws_msk_cluster.example.bootstrap_brokers_tls
}

