response:
To provision an Amazon MSK (Managed Streaming for Apache Kafka) cluster with encryption at rest, we need to define several resources:
1.  **VPC and Subnets**: MSK requires at least two subnets in different Availability Zones.
2.  **Security Group**: To control traffic to the Kafka brokers.
3.  **KMS Key**: To handle encryption at rest (though MSK can use the default service key, creating a customer-managed key is best practice).
4.  **MSK Cluster**: The core resource, where we specify the broker nodes, Kafka version, and encryption settings.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the MSK Cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "msk-vpc"
  }
}

# 2. Create subnets in two different AZs (Requirement for MSK)
resource "aws_subnet" "msk_subnet_az1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "msk_subnet_az2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 3. Security Group for the MSK Cluster
resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Security group for MSK cluster"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. KMS Key for Encryption at Rest
resource "aws_kms_key" "msk_kms_key" {
  description             = "KMS key for MSK cluster encryption"
  deletion_window_in_days = 7
}

# 5. MSK Cluster Configuration
resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 2

  broker_node_group_info {
    instance_type = "kafka.t3.small"
    client_subnets = [
      aws_subnet.msk_subnet_az1.id,
      aws_subnet.msk_subnet_az2.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 10
      }
    }
  }

  # Encryption Configuration
  encryption_info {
    # Data at rest encryption using the KMS key created above
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_kms_key.arn

    # Encryption in transit (TLS)
    encryption_in_transit {
      client_broker = "TLS"
      in_cluster    = true
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# CloudWatch Log Group for MSK Logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "msk-cluster-logs"
}

# Output the Bootstrap Brokers for connectivity
output "bootstrap_brokers_tls" {
  description = "TLS connection host:port pairs"
  value       = aws_msk_cluster.example.bootstrap_brokers_tls
}
