extracted_code:
# Shared variables for the setup
variable "region" {
  default = "us-east-1"
}

provider "aws" {
  region = var.region
}

# 1. Network Infrastructure
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "msk_subnet_az1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${var.region}a"
}

resource "aws_subnet" "msk_subnet_az2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${var.region}b"
}

# 2. Security Group
resource "aws_security_group" "msk_sg" {
  name        = "msk-monitoring-sg"
  description = "Allow Kafka and Exporter traffic"
  vpc_id      = aws_vpc.msk_vpc.id

  # Kafka Plaintext/TLS ports
  ingress {
    from_port   = 9092
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # JMX Exporter port
  ingress {
    from_port   = 11001
    to_port     = 11001
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  # Node Exporter port
  ingress {
    from_port   = 11002
    to_port     = 11002
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. MSK Configuration
resource "aws_msk_configuration" "msk_config" {
  kafka_versions = ["3.5.1"]
  name           = "msk-config-standard"

  server_properties = <<PROPERTIES
auto.create.topics.enable = true
delete.topic.enable = true
PROPERTIES
}

# 4. MSK Cluster with Prometheus Exporters enabled
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "monitored-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 2

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.msk_subnet_az1.id,
      aws_subnet.msk_subnet_az2.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  # Enabling Open Monitoring (Prometheus)
  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  configuration_info {
    arn      = aws_msk_configuration.msk_config.arn
    revision = aws_msk_configuration.msk_config.latest_revision
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  tags = {
    Environment = "Dev"
    Monitoring  = "Enabled"
  }
}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/monitored-cluster"
  retention_in_days = 7
}

output "zookeeper_connect_string" {
  value = aws_msk_cluster.msk_cluster.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
  value = aws_msk_cluster.msk_cluster.bootstrap_brokers_tls
}

