```hcl
# Terraform configuration for Amazon MSK Serverless in us-east-1

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. VPC and Networking setup for MSK
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-serverless-vpc"
  }
}

resource "aws_subnet" "subnet_az1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-subnet-1"
  }
}

resource "aws_subnet" "subnet_az2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-subnet-2"
  }
}

# 2. Security Group to allow traffic within the VPC
resource "aws_security_group" "msk_sg" {
  name        = "msk-serverless-sg"
  description = "Allow access to MSK Serverless"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.msk_vpc.cidr_block]
    description = "IAM authenticated access for MSK Serverless"
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Amazon MSK Serverless Cluster
resource "aws_msk_serverless_cluster" "example" {
  cluster_name = "msk-serverless-cluster"

  vpc_config {
    subnet_ids         = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id]
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  client_authentication {
    sasl {
