    sasl {
      iam {
        enabled = true
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

# Outputs
output "msk_cluster_arn" {
  value = aws_msk_serverless_cluster.example.arn
}

output "msk_bootstrap_brokers" {
  value       = "IAM access only: cluster-endpoint:9098"
  description = "MSK Serverless uses a single endpoint for bootstrap brokers."
}

