# Provider configuration
provider "aws" {
  region = "us-east-1"
}

# --- VPC Infrastructure ---
data "aws_availability_zones" "available" {}

resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "msk_subnets" {
  count             = 3
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]
}

resource "aws_security_group" "msk_sg" {
  name        = "msk-security-group"
  description = "Allow inbound traffic for MSK"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 0
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- Logging Destinations ---

# 1. CloudWatch Logs
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/cluster-logs"
  retention_in_days = 7
}

# 2. S3 Bucket
resource "aws_s3_bucket" "msk_log_bucket" {
  bucket        = "msk-logs-storage-xyz-123"
  force_destroy = true
}

# 3. Kinesis Firehose (requires IAM Role and S3 destination for the Firehose itself)
resource "aws_iam_role" "firehose_role" {
  name = "msk_firehose_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-log-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_log_bucket.arn
  }
}

# --- MSK Cluster Configuration ---

resource "aws_kms_key" "msk_key" {
  description = "KMS key for MSK encryption at rest"
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_log_bucket.id
        prefix  = "logs/msk-"
      }
    }
  }

  tags = {
    Environment = "Dev"
  }
}

output "zookeeper_connect_string" {
  value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
  value = aws_msk_cluster.example.bootstrap_brokers_tls
}

