To provision an Amazon MSK cluster with the specified logging, monitoring, and MSK Connect resources, we need to define the VPC infrastructure, the MSK cluster itself, the logging destinations, and the MSK Connect components.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_subnet" "subnet_c" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
}

resource "aws_security_group" "msk_sg" {
  name   = "msk-sg"
  vpc_id = aws_vpc.msk_vpc.id
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    self        = true
  }
}

# 2. Logging Destinations
resource "aws_cloudwatch_log_group" "msk_log_group" {
  name = "msk-broker-logs"
}

resource "aws_s3_bucket" "msk_log_bucket" {
  bucket = "msk-broker-logs-bucket-unique-id"
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "terraform-msk-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_log_bucket.arn
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_msk_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "firehose.amazonaws.com" }
    }]
  })
}

# 3. Amazon MSK Cluster
resource "aws_msk_cluster" "example" {
  cluster_name           = "example-cluster"
  kafka_version          = "3.2.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id, aws_subnet.subnet_c.id]
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
      node_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_log_group.name
      }
      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_log_bucket.id
        prefix  = "logs/msk-"
      }
    }
  }
}

resource "aws_kms_key" "msk_key" {
  description = "KMS Key for MSK encryption"
}

# 4. MSK Connect Custom Plugin
resource "aws_s3_object" "debezium_zip" {
  bucket = aws_s3_bucket.msk_log_bucket.id
  key    = "plugins/debezium.zip"
  source = "debezium.zip" # Assumes file exists locally
}

resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name         = "debezium-plugin"
  content_type = "ZIP"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_log_bucket.arn
      file_key   = aws_s3_object.debezium_zip.key
    }
  }
}

# 5. MSK Connect Connector
resource "aws_mskconnect_connector" "example_connector" {
  name = "example-connector"

  kafkaconnect_version = "2.7.1"

  capacity {
    autoscaling {
      mcu_count        = 1
      min_worker_count = 1
      max_worker_count = 2
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }

  connector_configuration = {
    "connector.class"                = "io.debezium.connector.postgresql.PostgresConnector"
    "tasks.max"                      = "1"
    "database.hostname"              = "change-me"
    "database.port"                  = "5432"
    "database.user"                  = "postgres"
    "database.password"              = "password"
    "database.dbname"                = "postgres"
    "database.server.name"           = "dbserver1"
    "topic.prefix"                   = "dbserver1"
    "kafka.bootstrap.servers"        = aws_msk_cluster.example.bootstrap_brokers_tls
  }

  kafka_cluster {
    apache_kafka_cluster {
      bootstrap_servers = aws_msk_cluster.example.bootstrap_brokers_tls
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id, aws_subnet.subnet_c.id]
      }
    }
  }

  kafka_cluster_client_authentication {
    authentication_type = "NONE"
  }

  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS"
  }

  plugin {
    custom_plugin {
      arn      = aws_mskconnect_custom_plugin.debezium_plugin.arn
      revision = aws_mskconnect_custom_plugin.debezium_plugin.latest_revision
    }
  }

  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}

resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-execution-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "kafkaconnect.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "msk_connect_policy" {
  role = aws_iam_role.msk_connect_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:DescribeCluster",
          "kafka-cluster:WriteData",
          "kafka-cluster:ReadData"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}
