To set up a DynamoDB table, we need to define the AWS provider, specify the table name, define the billing mode (on-demand or provisioned), and declare the attribute definitions for the primary keys (Partition Key and an optional Sort Key).

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a DynamoDB Table
resource "aws_dynamodb_table" "example_table" {
  name            = "UserOrders"
  billing_mode   = "PAY_PER_REQUEST" # On-demand pricing
  hash_key       = "UserId"          # Partition Key
  range_key      = "OrderId"         # Sort Key

  # Attribute definitions must match the keys defined above
  attribute {
    name = "UserId"
    type = "S" # S = String, N = Number, B = Binary
  }

  attribute {
    name = "OrderId"
    type = "S"
  }

  # Enable Point-in-time Recovery (Best practice)
  point_in_time_recovery {
    enabled = true
  }

  # Server-side encryption using AWS Managed CMK
  server_side_encryption {
    enabled = true
  }

  tags = {
    Environment = "Dev"
    Project     = "TerraformAI-Demo"
  }
}

# Output the ARN and ID of the table
output "table_arn" {
  value       = aws_dynamodb_table.example_table.arn
  description = "The ARN of the DynamoDB table"
}

output "table_name" {
  value       = aws_dynamodb_table.example_table.id
}
```

