}

response:
To set up a DynamoDB global table replicated across two regions, we must use the `aws_dynamodb_table` resource with `billing_mode = "PAY_PER_REQUEST"` or provisioned capacity with `autoscaling` (as global tables require specific capacity management). We also need to define two provider instances for the respective regions and ensure `hash_key` and `attribute` definitions are consistent.

```hcl
# Configure the Primary Provider (us-west-1)
provider "aws" {
  region = "us-west-1"
}

# Configure the Secondary Provider (us-west-2)
provider "aws" {
  alias  = "us_west_2"
  region = "us-west-2"
}

# Define the DynamoDB Global Table
resource "aws_dynamodb_table" "replicated_table" {
  name             = "replicated-global-table"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "PK"
  range_key        = "SK"
  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "PK"
    type = "S"
  }

  attribute {
    name = "SK"
    type = "S"
  }

  # First replica in the primary region (implied)
  # Second replica in us-west-2
  replica {
    region_name = "us-west-2"
    # Optional: point_in_time_recovery = true
    # Optional: kms_key_arn           = "..."
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Output the Table ARN
output "dynamodb_table_arn" {
  value       = aws_dynamodb_table.replicated_table.arn
  description = "The ARN of the DynamoDB table"
}
```

