# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a DynamoDB table with a TTL (Time to Live) configuration
resource "aws_dynamodb_table" "ttl_managed_table" {
  name           = "UserSessions"
  billing_mode   = "PAY_PER_REQUEST" # On-demand scaling
  hash_key       = "SessionId"

  attribute {
    name = "SessionId"
    type = "S"
  }

  # Enable TTL on a specific attribute
  # Items where this attribute value (as a Unix timestamp) is less than 
  # current time will be automatically deleted by AWS.
  ttl {
    attribute_name = "ExpirationTime"
    enabled        = true
  }

  tags = {
    Environment = "Dev"
    ManagedBy   = "TerraformAI"
  }
}

# Example of an item with a TTL set (requires the aws_dynamodb_table_item resource)
# Note: The ExpirationTime must be a number representing seconds since the Unix epoch.
resource "aws_dynamodb_table_item" "sample_item" {
  table_name = aws_dynamodb_table.ttl_managed_table.name
  hash_key   = aws_dynamodb_table.ttl_managed_table.hash_key

  item = <<ITEM
{
  "SessionId": {"S": "user-abc-123"},
  "UserName": {"S": "JohnDoe"},
  "ExpirationTime": {"N": "1735689600"} 
}
ITEM
}

# Output the Table Name and TTL Status
output "dynamodb_table_name" {
  value = aws_dynamodb_table.ttl_managed_table.name
}

output "ttl_attribute" {
  value = aws_dynamodb_table.ttl_managed_table.ttl[0].attribute_name
}

