# Create a Customer Managed Key (CMK) for DynamoDB Encryption
resource "aws_kms_key" "dynamo_key" {
  description             = "KMS key for DynamoDB server-side encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name = "dynamodb-encryption-key"
  }
}

# Create a KMS Alias for easier identification
