  name          = "alias/dynamodb-app-table-key"
  target_key_id = aws_kms_key.dynamo_key.key_id
}

# Set up the DynamoDB Table with Encryption Enabled
resource "aws_dynamodb_table" "secure_table" {
  name           = "SecureApplicationData"
