response:
To set up a DynamoDB table with server-side encryption enabled, we will define an `aws_dynamodb_table` resource. By default, AWS provides encryption at rest with an AWS-owned customer master key (CMK). To follow best practices for enhanced security and control, we will configure the table to use **AWS KMS (KMS-Managed CMK)**.

The configuration includes:
1.  **aws_kms_key**: A customer-managed key used specifically for encrypting the DynamoDB table.
2.  **aws_dynamodb_table**: The table definition with `attribute` and `hash_key`.
3.  **server_side_encryption**: A block within the table resource where we enable encryption and point to the KMS key ARN.

```hcl
# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a Customer Managed Key (CMK) for DynamoDB Encryption
resource "aws_kms_key" "dynamo_key" {
  description             = "KMS key for DynamoDB server-side encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name = "dynamodb-encryption-key"
  }
}

# Create a KMS Alias for easier identification
resource "aws_kms_alias" "dynamo_key_alias" {
  name          = "alias/dynamodb-app-table-key"
  target_key_id = aws_kms_key.dynamo_key.key_id
}

# Set up the DynamoDB Table with Encryption Enabled
resource "aws_dynamodb_table" "secure_table" {
  name           = "SecureApplicationData"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "UserId"
  range_key      = "Timestamp"

  attribute {
    name = "UserId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  # Enable Server-Side Encryption
  server_side_encryption {
    enabled     = true
    kms_key_arn = aws_kms_key.dynamo_key.arn
  }

  point_in_time_recovery {
    enabled = true
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}
```

extracted_code:
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC with IPv4 CIDR and IPv6 enabled
resource "aws_vpc" "main" {
  cidr_block                       = "10.0.0.0/16"
  assign_generated_ipv6_cidr_block = true
  enable_dns_support               = true
  enable_dns_hostnames             = true

  tags = {
    Name = "terraform-ipv6-vpc"
  }
}

# 2. Create a Subnet with an IPv6 CIDR block assigned
# Note: IPv6 subnets in AWS must be a /64 prefix
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  ipv6_cidr_block         = cidrsubnet(aws_vpc.main.ipv6_cidr_block, 8, 1)
  map_public_ip_on_launch = true
  assign_ipv6_address_on_creation = true

  tags = {
    Name = "ipv6-public-subnet"
  }
}

# 3. Create an Internet Gateway
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# 4. Create a Route Table with IPv6 routing to the Internet Gateway
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  # IPv4 default route
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  # IPv6 default route (::/0)
  route {
    ipv6_cidr_block = "::/0"
    gateway_id      = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# 5. Associate the Route Table with the Subnet
resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public_rt.id
}

# Outputs to verify the CIDR blocks
output "vpc_id" {
  value = aws_vpc.main.id
}

output "vpc_ipv6_cidr_block" {
  value = aws_vpc.main.ipv6_cidr_block
}

output "subnet_ipv6_cidr_block" {
  value = aws_subnet.public.ipv6_cidr_block
}

