# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC
# Note: assign_generated_ipv6_cidr_block must be true because Egress-Only 
# Internet Gateways are used for IPv6 traffic.
resource "aws_vpc" "main" {
  cidr_block                       = "10.0.0.0/16"
  assign_generated_ipv6_cidr_block = true
  enable_dns_support               = true
  enable_dns_hostnames             = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Egress-Only Internet Gateway
# This allows egress communication over IPv6 from instances in the VPC 
# to the Internet, but prevents the Internet from initiating connections.
resource "aws_egress_only_internet_gateway" "eoigw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-eoigw"
  }
}

# 3. Create a Private Subnet
resource "aws_subnet" "private" {
  vpc_id                          = aws_vpc.main.id
  cidr_block                      = "10.0.1.0/24"
  ipv6_cidr_block                 = cidrsubnet(aws_vpc.main.ipv6_cidr_block, 8, 1)
  assign_ipv6_address_on_creation = true

  tags = {
    Name = "private-subnet"
  }
}

# 4. Create a Route Table
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.main.id

  # Route all IPv6 traffic (::/0) to the Egress-Only Internet Gateway
  route {
    ipv6_cidr_block        = "::/0"
    egress_only_gateway_id = aws_egress_only_internet_gateway.eoigw.id
  }

  tags = {
    Name = "private-route-table"
  }
}

# 5. Associate the Subnet with the Route Table
resource "aws_route_table_association" "private_assoc" {
  subnet_id      = aws_subnet.private.id
  route_table_id = aws_route_table.private_rt.id
}

