# AWS Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Virtual Private Cloud (VPC)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create a Subnet within the VPC
resource "aws_subnet" "public_subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1  a"

  tags = {
    Name = "main-subnet"
  }
}

# 3. Create a Network ACL (NACL)
resource "aws_network_acl" "main_nacl" {
  vpc_id     = aws_vpc.main.id
  subnet_ids = [aws_subnet.public_subnet.id]

  # Inbound Rule: Allow HTTP (Port 80) from anywhere
  ingress {
    protocol   = "tcp"
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 80
    to_port    = 80
  }

  # Inbound Rule: Allow SSH (Port 22) from a specific IP (Example: Admin IP)
  ingress {
    protocol   = "tcp"
    rule_no    = 110
    action     = "allow"
    cidr_block = "0.0.0.0/0" # In production, replace with a specific IP range
    from_port  = 22
    to_port    = 22
  }

  # Inbound Rule: Allow Ephemeral Ports (Required for return traffic from outbound requests)
  ingress {
    protocol   = "tcp"
    rule_no    = 120
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 1024
    to_port    = 65535
  }

  # Outbound Rule: Allow All Traffic (Standard for general internet access/updates)
  egress {
    protocol   = "-1" # -1 means all protocols
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 0
  }

  tags = {
    Name = "main-nacl"
  }
}

# Output the IDs for reference
output "vpc_id" {
  value = aws_vpc.main.id
}

output "subnet_id" {
  value = aws_subnet.public_subnet.id
}

output "nacl_id" {
  value = aws_network_acl.main_nacl.id
}

