resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Internet Gateway and attach it to the VPC
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# 3. Create a custom Route Table
resource "aws_route_table" "custom_rt" {
  vpc_id = aws_vpc.main.id

  # 4. Create a route within the Route Table
  # This sends traffic for the designated CIDR (e.g., 0.0.0.0/0 for Internet) 
  # through the Internet Gateway.
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "custom-route-table"
  }
}

# Optional: Create a Subnet and associate it with the Route Table
