response:
To create a simple Amazon Neptune cluster with a customized parameter group, we need to define several resources:
1.  **VPC and Subnets**: Neptune must run in a VPC. We will define a DB subnet group.
2.  **Security Group**: To allow traffic (default port 8182) to the cluster.
3.  **Cluster Parameter Group**: To handle cluster-level settings (like enabling audit logs).
4.  **DB Parameter Group**: To handle instance-level settings.
5.  **Neptune Cluster**: The primary logical unit for the database.
6.  **Neptune Instance**: The actual compute resource within the cluster.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the Neptune Cluster (Simplified for this example)
resource "aws_vpc" "neptune_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "neptune_subnet_a" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "neptune_subnet_b" {
  vpc_id            = aws_vpc.neptune_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 2. Neptune Subnet Group
resource "aws_neptune_subnet_group" "default" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_subnet_a.id, aws_subnet.neptune_subnet_b.id]

  tags = {
    Name = "Neptune Subnet Group"
  }
}

# 3. Security Group to allow Neptune traffic (Port 8182)
resource "aws_security_group" "neptune_sg" {
  name        = "neptune-sg"
  description = "Allow Neptune traffic"
  vpc_id      = aws_vpc.neptune_vpc.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to your application's source CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. Customized Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom_cluster_params" {
  family      = "neptune1.2"
  name        = "custom-cluster-params"
  description = "Customized cluster parameter group for Neptune"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# 5. Customized DB Parameter Group (Instance Level)
resource "aws_neptune_parameter_group" "custom_db_params" {
  family      = "neptune1.2"
  name        = "custom-db-params"
  description = "Customized DB instance parameter group"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000" # 2 minutes in milliseconds
  }
}

# 6. Neptune Cluster
resource "aws_neptune_cluster" "default" {
  cluster_identifier                  = "neptune-cluster-demo"
  engine                              = "neptune"
  backup_retention_period             = 5
  preferred_backup_window             = "07:00-09:00"
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = false
  apply_immediately                   = true

  neptune_subnet_group_name           = aws_neptune_subnet_group.default.name
  vpc_security_group_ids               = [aws_security_group.neptune_sg.id]
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom_cluster_params.name
}

# 7. Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "example" {
  count              = 1
  cluster_identifier = aws_neptune_cluster.default.id
  engine             = "neptune"
  instance_class     = "db.t3.medium"
