response:
To create a Neptune cluster with custom parameter groups, we need to define four main components: the Neptune cluster itself, a cluster parameter group for cluster-level settings (like audit logging), a Neptune instance, and an instance parameter group for instance-specific settings (like query timeouts).

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define a Custom Neptune Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "example" {
  family      = "neptune1.2"
  name        = "example-cluster-params"
  description = "Custom cluster parameter group for Neptune"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }
}

# 2. Define a Custom Neptune Instance Parameter Group
resource "aws_neptune_parameter_group" "example" {
  family      = "neptune1.2"
  name        = "example-instance-params"
  description = "Custom instance parameter group for Neptune"

  parameter {
    name  = "neptune_query_timeout"
    value = "120000"
  }
}

# 3. Create the Neptune Cluster
resource "aws_neptune_cluster" "example" {
  cluster_identifier                  = "example-neptune-cluster"
  engine                              = "neptune"
  engine_version                      = "1.2.1.0"
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.example.name
  skip_final_snapshot                 = true
  iam_database_authentication_enabled = true
  apply_immediately                   = true
}

# 4. Create the Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "example" {
  count              = 1
  identifier         = "example-neptune-instance-${count.index}"
  cluster_identifier = aws_neptune_cluster.example.id
  engine             = "neptune"
  instance_class     = "db.t3.medium" # Minimum supported class for many regions
  apply_immediately  = true

  # Reference the custom instance parameter group
  neptune_parameter_group_name = aws_neptune_parameter_group.example.name
}

# Output the endpoint for connectivity
output "neptune_endpoint" {
  value       = aws_neptune_cluster.example.endpoint
  description = "The DNS address of the Neptune instance"
}
```

