To provision a pair of encrypted AWS Chime Voice Connectors and group them with specific priorities, we follow these steps:
1. Define the AWS provider and specify the region (Chime Voice Connectors are typically managed in `us-east-1` or `us-west-2`).
2. Create two `aws_chime_voice_connector` resources, ensuring the `require_encryption` attribute is set to `true`.
3. Create an `aws_chime_voice_connector_group` resource.
4. Within the group, define `connector` blocks that reference the IDs of the created connectors, assigning the requested priorities (1 and 3).

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create the first encrypted Chime Voice Connector
resource "aws_chime_voice_connector" "primary" {
  name               = "primary-connector"
  require_encryption = true
  aws_region         = "us-east-1"
}

# Create the second encrypted Chime Voice Connector
resource "aws_chime_voice_connector" "secondary" {
  name               = "secondary-connector"
  require_encryption = true
  aws_region         = "us-east-1"
}

# Define the Voice Connector Group and assign priorities
resource "aws_chime_voice_connector_group" "main_group" {
  name = "main-voice-connector-group"

  connector {
    voice_connector_id = aws_chime_voice_connector.primary.id
    priority           = 1
  }

  connector {
    voice_connector_id = aws_chime_voice_connector.secondary.id
    priority           = 3
  }
}

# Outputs for reference
output "voice_connector_group_id" {
  value = aws_chime_voice_connector_group.main_group.id
}
```

