# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# 2. Create two Subnets in different Availability Zones
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# 3. Create a Redshift Subnet Group
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Environment = "Dev"
  }
}

# 4. Create a Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Provision the Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "dbadmin"
  master_password    = "MustBe8Characters1!" # Securely handle passwords in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  cluster_subnet_group_name = aws_redshift_subnet_group.main.name
  vpc_security_group_ids    = [aws_security_group.redshift_sg.id]

  skip_final_snapshot = true
}

# 6. Create Redshift Endpoint Access
# This enables access to the cluster from another VPC or via a private link
resource "aws_redshift_endpoint_access" "example" {
  endpoint_name      = "redshift-endpoint"
  cluster_identifier = aws_redshift_cluster.example.cluster_identifier
  subnet_group_name  = aws_redshift_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]
}

# Output the endpoint address
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

output "managed_endpoint_address" {
  value = aws_redshift_endpoint_access.example.address
}

