resource "aws_redshift_subnet_group" "redshift_sg" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Environment = "Production"
  }
}

# 4. Create a Security Group to allow access to Redshift (Port 5439)
resource "aws_security_group" "redshift_access" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to specific source CIDRs for security
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Provision the Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8To64Chars1!" # Use secrets management in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Link the subnet group and security group
  cluster_subnet_group_name    = aws_redshift_subnet_group.redshift_sg.name
  vpc_security_group_ids       = [aws_security_group.redshift_access.id]

  # Ensure the cluster is not deleted logic
  skip_final_snapshot = true
}

# Outputs for connectivity
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

