response:
To provision an Amazon Redshift cluster accessible from multiple subnets, we must define a Virtual Private Cloud (VPC), specify a Redshift Subnet Group containing the desired subnets, and configure the Redshift cluster to use that group. We also need a Security Group to allow traffic to the default Redshift port (5439).

```hcl
# Terraform configuration for an Amazon Redshift cluster across two subnets

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Provide a VPC for the infrastructure
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# 2. Define two separate subnets in different Availability Zones
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-1"
  }
}

resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-2"
  }
}

# 3. Create a Redshift Subnet Group incorporating both subnets
resource "aws_redshift_subnet_group" "redshift_sg" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  tags = {
    Environment = "Production"
  }
}

# 4. Create a Security Group to allow access to Redshift (Port 5439)
resource "aws_security_group" "redshift_access" {
  name        = "redshift-sg"
  description = "Allow inbound traffic to Redshift"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust to specific source CIDRs for security
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Provision the Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8To64Chars1!" # Use secrets management in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Link the subnet group and security group
  cluster_subnet_group_name    = aws_redshift_subnet_group.redshift_sg.name
  vpc_security_group_ids       = [aws_security_group.redshift_access.id]

  # Ensure the cluster is not deleted logic
  skip_final_snapshot = true
}

# Outputs for connectivity
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}
```

