To set up an Amazon Redshift cluster with event notifications, we need to define the networking (VPC/Subnet Group), the Redshift cluster itself, an SNS topic for notifications, and the Redshift Event Subscription.

Step-by-step logic:
1. **SNS Topic**: Create an Amazon SNS topic that will receive the cluster events.
2. **Subnet Group**: Define which subnets the Redshift cluster will reside in.
3. **Redshift Cluster**: Provision the cluster with specified node types and credentials.
4. **Event Subscription**: Link specific event categories (like "management" or "configuration") from the Redshift cluster to the SNS topic.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an SNS Topic for Redshift Notifications
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-event-notifications"
}

# SNS Topic Policy to allow Redshift to publish events
resource "aws_sns_topic_policy" "default" {
  arn = aws_sns_topic.redshift_events.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowRedshiftToPublish"
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
        Action   = "sns:Publish"
        Resource = aws_sns_topic.redshift_events.arn
      }
    ]
  })
}

# 2. Create a Redshift Subnet Group (Assuming existing subnets)
# Replace subnet IDs with your actual VPC subnet IDs
resource "aws_redshift_subnet_group" "main" {
  name       = "redshift-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"]

  tags = {
    Environment = "Production"
  }
}

# 3. Provision the Amazon Redshift Cluster
resource "aws_redshift_cluster" "primary_cluster" {
  cluster_identifier = "terraform-redshift-cluster"
  database_name      = "dev"
  master_username    = "adminuser"
  master_password    = "MustBeComplex123!" # Use env vars or secrets manager in production
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  cluster_subnet_group_name    = aws_redshift_subnet_group.main.name
  skip_final_snapshot          = true
  publicly_accessible          = false

  tags = {
    Name = "RedshiftCluster"
  }
}

# 4. Configure Redshift Event Subscription
resource "aws_redshift_event_subscription" "cluster_alerts" {
  name             = "redshift-cluster-event-subscription"
  sns_topic_arn    = aws_sns_topic.redshift_events.arn
  source_type      = "cluster"
  source_ids       = [aws_redshift_cluster.primary_cluster.id]

  # Categories include: configuration, management, monitoring, security
  event_categories = [
    "configuration",
    "management",
    "monitoring",
    "security"
  ]

  severity = "INFO"
  enabled  = true
}

# Output the SNS Topic ARN for subscription setup
output "sns_topic_arn" {
  value = aws_sns_topic.redshift_events.arn
}

output "redshift_endpoint" {
  value = aws_redshift_cluster.primary_cluster.endpoint
}
