resource "aws_sns_topic_policy" "default" {
  arn = aws_sns_topic.redshift_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid      = "AllowRedshiftPublish"
        Effect   = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
        Action   = "sns:Publish"
        Resource = aws_sns_topic.redshift_notifications.arn
      }
    ]
  })
}

# 3. Create a Redshift Cluster
# Note: In production, use sensitive variables for credentials
resource "aws_redshift_cluster" "main" {
  cluster_identifier = "tf-redshift-cluster"
  database_name      = "mydb"
  master_username    = "adminuser"
  master_password    = "MustBe8CharactersMin!" # Use a secure password or secrets manager
  node_type          = "dc2.large"
  cluster_type       = "single-node"

  # Skip final snapshot for easy cleanup in this example
  skip_final_snapshot = true
}

# 4. Create the Redshift Event Subscription
resource "aws_redshift_event_subscription" "main" {
  name             = "redshift-event-sub"
  sns_topic_arn    = aws_sns_topic.redshift_notifications.arn
  source_type      = "cluster"
  source_ids       = [aws_redshift_cluster.main.id]

  # Filter for specific event categories (optional)
  # Possible values: configuration, management, monitoring, security, etc.
  event_categories = [
    "management",
    "monitoring",
    "security"
  ]

  severity = "INFO"
  enabled  = true
}

# Outputs
output "redshift_endpoint" {
  value = aws_redshift_cluster.main.endpoint
}

output "sns_topic_arn" {
  value = aws_sns_topic.redshift_notifications.arn
}
