1.  **Redshift Parameter Group**: To manage cluster configurations.
2.  **Redshift Cluster**: The core data warehouse resource using sample settings (e.g., `dc2.large`).
3.  **SNS Topic**: To serve as the destination for event notifications.
4.  **Redshift Event Subscription**: To link the parameter group events to the SNS topic.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a Redshift Parameter Group
resource "aws_redshift_parameter_group" "example" {
  name   = "example-params"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }
}

# 2. Create an SNS Topic for notifications
resource "aws_sns_topic" "redshift_updates" {
  name = "redshift-event-notifications"
}

# 3. Create the Redshift Cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier        = "example-cluster"
  database_name             = "dev"
  master_username           = "adminuser"
  master_password           = "MustBe8CharactersMin1" # Use secrets management for production
  node_type                 = "dc2.large"
  cluster_type              = "single-node"
  cluster_parameter_group_name = aws_redshift_parameter_group.example.name

  # Sample settings
  skip_final_snapshot       = true
  publicly_accessible       = true
}

# 4. Configure Redshift Event Subscription
# This monitors the parameter group for changes and sends alerts to SNS
resource "aws_redshift_event_subscription" "example" {
  name             = "redshift-parameter-event-sub"
  sns_topic_arn    = aws_sns_topic.redshift_updates.arn
  source_type      = "parameter-group"
  source_ids       = [aws_redshift_parameter_group.example.id]
  severity         = "INFO"

  event_categories = [
    "configuration",
    "management"
  ]
}

# Outputs
