To provision an Amazon Redshift cluster with a custom parameter group and an event subscription for SNS notifications, we need to define the SNS topic, the parameter group, the cluster itself (associating it with the group), and the event subscription filtered by the "parameter-group" source type.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create an SNS Topic for Redshift events
resource "aws_sns_topic" "redshift_events_topic" {
  name = "redshift-parameter-event-notifications"
}

# 2. Create a Redshift Parameter Group
resource "aws_redshift_parameter_group" "custom_redshift_params" {
  name   = "custom-params"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"
    value = "true"
  }

  parameter {
    name  = "enable_user_activity_logging"
    value = "true"
  }
}

# 3. Provision the Redshift Cluster
resource "aws_redshift_cluster" "example_cluster" {
  cluster_identifier         = "terraform-redshift-cluster"
  database_name              = "exampledb"
  master_username            = "adminuser"
  master_password            = "MustBe8Characters1!" # Use a secrets manager in production
  node_type                  = "dc2.large"
  cluster_type               = "single-node"
  cluster_parameter_group_name = aws_redshift_parameter_group.custom_redshift_params.name
  skip_final_snapshot        = true
}

# 4. Create Redshift Event Subscription
# This routes parameter-group-related events to the SNS topic
resource "aws_redshift_event_subscription" "param_group_subscription" {
  name             = "redshift-parameter-group-events"
  sns_topic_arn    = aws_sns_topic.redshift_events_topic.arn
  source_type      = "parameter-group"
  source_ids       = [aws_redshift_parameter_group.custom_redshift_params.id]

  # Severity levels and categories can be filtered
  severity         = "INFO"
  event_categories = ["configuration", "management"]

  tags = {
    Environment = "Dev"
  }
}

# Outputs for reference
output "redshift_endpoint" {
  value = aws_redshift_cluster.example_cluster.endpoint
}

output "sns_topic_arn" {
  value = aws_sns_topic.redshift_events_topic.arn
}
```

