1.  `aws_iam_group`: To create the logical container for the users.
2.  `aws_iam_user`: To create the individual user identities.
3.  `aws_iam_group_membership`: To associate the users with the group.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the IAM Group
resource "aws_iam_group" "developers" {
  name = "developer-group"
  path = "/users/"
}

# 2. Create the IAM Users
resource "aws_iam_user" "user_one" {
  name = "alice-developer"
  path = "/users/"
  tags = {
