2.  The `aws_iam_user_ssh_key` resource to upload the public key and associate it with the user.
3.  The public key string itself (usually provided as a variable).

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define the IAM User
resource "aws_iam_user" "example_user" {
  name = "developer-ssh-user"
  path = "/system/"

  tags = {
    Environment = "Dev"
  }
}

# 2. Upload the SSH Public Key and associate it with the User
# Note: encoding must be SSH public key format (e.g., "ssh-rsa AAAAB3N...")
resource "aws_iam_user_ssh_key" "example_ssh_key" {
  username   = aws_iam_user.example_user.name
  encoding   = "SSH"
  public_key = "ssh-rsa  user@example.com"
  status     = "Active"
}

# 3. Output the SSH Key ID (Required for CodeCommit or other services)
output "ssh_key_id" {
  value       = aws_iam_user_ssh_key.example_ssh_key.ssh_public_key_id
  description = "The ID of the SSH Public Key, used as the SSH Username for AWS services."
}

