# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Define a random suffix to ensure bucket name uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Create the S3 Bucket
resource "aws_s3_bucket" "example_bucket" {
  bucket = "my-sample-terraform-bucket-${random_id" "bucket_suffix".hex}"

  tags = {
    Name        "Example Bucket"
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Set Ownership Controls for the bucket
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.example_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Block all public access (Security Best Practice)
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.example_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Output the bucket name and ARN
output "s3_bucket_name" {
  value       = aws_s3_bucket.example_bucket.id
  description = "The name of the S3 bucket"
}

output "s3_bucket_arn" {
  value       = aws_s3_bucket.example_bucket.arn
  description = "The ARN of the S3 bucket"
}

response:
To set up an Amazon S3 bucket, we first need to configure the AWS provider. Then, we define the `aws_s3_bucket` resource. It is also a best practice to include a resource for bucket ownership controls and public access blocks to ensure the bucket remains private by default.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Define a random suffix to ensure bucket name uniqueness
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Create the S3 Bucket
resource "aws_s3_bucket" "example_bucket" {
  bucket = "my-sample-terraform-bucket-${random_id" "bucket_suffix".hex}"

  tags = {
    Name        "Example Bucket"
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Set Ownership Controls for the bucket
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.example_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Block all public access (Security Best Practice)
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.example_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Output the bucket name and ARN
output "s3_bucket_name" {
  value       = aws_s3_bucket.example_bucket.id
  description = "The name of the S3 bucket"
}

output "s3_bucket_arn" {
  value       = aws_s3_bucket.example_bucket.arn
  description = "The ARN of the S3 bucket"
}
```

