  description                       = "Allow CloudFront to access S3 images"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 4. Create the CloudFront Distribution to serve images
resource "aws_cloudfront_distribution" "image_cdn" {
  origin {
    domain_name              = aws_s3_bucket.website_images.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
    origin_id                = "S3-WebsiteImages"
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "CDN for website images"
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-WebsiteImages"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Environment = "Production"
  }
}

# 5. S3 Bucket Policy to allow CloudFront to read files
resource "aws_s3_bucket_policy" "allow_cloudfront_access" {
  bucket = aws_s3_bucket.website_images.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCloudFrontServicePrincipalReadOnly"
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.website_images.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.image_cdn.arn
          }
        }
      }
    ]
  })
}

# Outputs
output "s3_bucket_name" {
  value = aws_s3_bucket.website_images.id
}

output "cloudfront_domain_name" {
  description = "Use this domain to serve your images (e.g., https://[domain]/image.jpg)"
  value       = aws_cloudfront_distribution.image_cdn.domain_name
}

response:
To set up an AWS service for storing and serving images for a website, the industry standard is to use **Amazon S3** for storage and **Amazon CloudFront** as a Content Delivery Network (CDN) to serve those images globally with low latency.

Here is the step-by-step logic applied in the configuration:
1.  **S3 Bucket**: Created with a unique name to store the image files.
2.  **Public Access Block**: Configured to keep the bucket private from the public internet (best practice).
3.  **Origin Access Control (OAC)**: Allows CloudFront to securely access the private S3 bucket.
4.  **CloudFront Distribution**: Acts as the edge cache to serve your images via HTTPS.
5.  **Bucket Policy**: Specifically allows only the CloudFront distribution to read objects from the bucket.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket for image storage
resource "aws_s3_bucket" "website_images" {
  bucket = "my-website-images-storage-99" # Ensure this is globally unique

  tags = {
    Name        = "Website Images"
    Environment = "Production"
  }
}

# 2. Block all public access to the S3 bucket (Best Practice)
resource "aws_s3_bucket_public_access_block" "images_access" {
  bucket = aws_s3_bucket.website_images.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 3. Create CloudFront Origin Access Control (OAC) to talk to S3
resource "aws_cloudfront_origin_access_control" "oac" {
  name                              = "s3_oac"
  description                       = "Allow CloudFront to access S3 images"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 4. Create the CloudFront Distribution to serve images
resource "aws_cloudfront_distribution" "image_cdn" {
  origin {
    domain_name              = aws_s3_bucket.website_images.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.oac.id
    origin_id                = "S3-WebsiteImages"
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "CDN for website images"
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-WebsiteImages"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Environment = "Production"
  }
}

# 5. S3 Bucket Policy to allow CloudFront to read files
resource "aws_s3_bucket_policy" "allow_cloudfront_access" {
  bucket = aws_s3_bucket.website_images.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowCloudFrontServicePrincipalReadOnly"
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.website_images.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.image_cdn.arn
          }
        }
      }
    ]
  })
}

# Outputs
output "s3_bucket_name" {
  value = aws_s3_bucket.website_images.id
}

output "cloudfront_domain_name" {
  description = "Use this domain to serve your images (e.g., https://[domain]/image.jpg)"
  value       = aws_cloudfront_distribution.image_cdn.domain_name
}
```

