# 1. Provision the S3 bucket
resource "aws_s3_bucket" "my_bucket" {
  bucket = "mybucket"

  tags = {
    Name        = "MyBucket"
    Environment = "Dev"
  }
}

# 2. Configure Ownership Controls
# Setting to "BucketOwnerPreferred" is required to continue using ACLs 
# in many AWS regions where Bucket Owner Enforced is the new default.
resource "aws_s3_bucket_ownership_controls" "my_bucket_oc" {
  bucket = aws_s3_bucket.my_bucket.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Define the Private ACL
# This resource references the bucket object and explicitly depends on ownership controls
resource "aws_s3_bucket_acl" "my_bucket_acl" {
  depends_on = [aws_s3_bucket_ownership_controls.my_bucket_oc]

  bucket = aws_s3_bucket.my_bucket.id
  acl    = "private"
}

