        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })
}

# 4. The Inventory Configuration
resource "aws_s3_bucket_inventory" "weekly_inventory" {
  bucket = aws_s3_bucket.source_bucket.id
  name   = "WeeklyFullInventory"

  included_object_versions = "All" # Track every current (and non-current) version

  schedule {
    frequency = "Weekly"
  }

  destination {
    bucket {
      format     = "CSV"
      bucket_arn = aws_s3_bucket.inventory_destination.arn
      prefix     = "inventory-reports"
    }
  }

  # Options for additional metadata in the CSV
  optional_fields = ["Size", "LastModifiedDate", "StorageClass", "ETag"]
}

# Data source to get current AWS Account ID for the policy
data "aws_caller_identity" "current" {}
```

