  source = "assets/test.pdf"
}

response:
To host and upload a PDF file in AWS, the most appropriate service is Amazon S3. We will need to create an S3 bucket, configure it for public access (or use a policy if public viewing is intended), and use the `aws_s3_object` resource to upload the file.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a unique S3 bucket to host the PDF
resource "aws_s3_bucket" "pdf_storage" {
  bucket_prefix = "pdf-hosting-bucket-"
  force_destroy = true
}

# 2. Configure Public Access Block (Required for modern buckets to allow public reads)
resource "aws_s3_bucket_public_access_block" "pdf_storage_access" {
  bucket = aws_s3_bucket.pdf_storage.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 3. Create a bucket policy to allow public read access to the PDF
resource "aws_s3_bucket_policy" "allow_public_read" {
  bucket = aws_s3_bucket.pdf_storage.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.pdf_storage.arn}/*"
      },
    ]
  })

  # Ensure public access block is removed before applying policy
  depends_on = [aws_s3_bucket_public_access_block.pdf_storage_access]
}

# 4. Upload the PDF file from the local assets directory
resource "aws_s3_object" "pdf_file" {
  bucket       = aws_s3_bucket.pdf_storage.id
  key          = "test.pdf"
  source       = "${path.module}/assets/test.pdf"
  content_type = "application/pdf"

  # The etag will trigger an update if the file content changes
  etag = filemd5("${path.module}/assets/test.pdf")
}

# Output the URL of the hosted PDF
output "pdf_url" {
  value       = "https://${aws_s3_bucket.pdf_storage.bucket_domain_name}/${aws_s3_object.pdf_file.key}"
  description = "The public URL to access the uploaded PDF"
}
```

