  description             = "KMS key for S3 bucket server-side encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name        = "s3-encryption-key"
    Environment = "Dev"
  }
}

# 2. Create an alias for the KMS key
resource "aws_kms_alias" "s3_kms_key_alias" {
  name          = "alias/s3-storage-key"
  target_key_id = aws_kms_key.s3_kms_key.key_id
}

# 3. Provision the S3 Bucket
resource "aws_s3_bucket" "encrypted_bucket" {
  bucket        = "terraform-kms-encrypted-storage-12345" # Ensure this is globally unique
  force_destroy = true

  tags = {
    Name        = "Encrypted Bucket"
    Environment = "Dev"
  }
}

