resource "aws_s3_bucket_cors_configuration" "example_cors" {
  bucket = aws_s3_bucket.example_bucket.id

  cors_rule {
    # Mandatory: Specifies which headers are allowed in a pre-flight request
    allowed_headers = ["*"]

    # Mandatory: Specifies which HTTP methods are allowed
    allowed_methods = ["PUT", "POST", "GET", "DELETE"]

    # Mandatory: Specifies which origins can access the bucket
    allowed_origins = ["https://s3-website-test.hashicorp.com", "http://localhost:3000"]

    # Optional: Specifies which headers are exposed to the browser
    expose_headers  = ["ETag"]

    # Optional: Specifies how long the browser should cache the pre-flight response (in seconds)
    max_age_seconds = 3000
  }
}

