terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Provide a unique name for the S3 bucket
resource "aws_s3_bucket" "static_website" {
  bucket = "my-terraform-static-website-12345" # Ensure this is globally unique
}

# 2. Configure Ownership Controls (Required for public access policies)
resource "aws_s3_bucket_ownership_controls" "example" {
  bucket = aws_s3_bucket.static_website.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# 3. Disable "Block Public Access" settings to allow the website to be public
resource "aws_s3_bucket_public_access_block" "example" {
  bucket = aws_s3_bucket.static_website.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 4. Configure the bucket for static website hosting
resource "aws_s3_bucket_website_configuration" "website_config" {
  bucket = aws_s3_bucket.static_website.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# 5. Define a Bucket Policy to allow public read access (GetObject)
resource "aws_s3_bucket_policy" "allow_public_access" {
  bucket = aws_s3_bucket.static_website.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.static_website.arn}/*"
      },
    ]
  })

  # Ensure public access settings are applied before the policy
  depends_on = [aws_s3_bucket_public_access_block.example]
}

# 6. Upload a sample index.html file
resource "aws_s3_object" "index" {
  bucket       = aws_s3_bucket.static_website.id
  key          = "index.html"
  content      = "<html><body><h1>Hello from Terraform AI</h1></body></html>"
  content_type = "text/html"
}

# 7. Upload a sample error.html file
