  request_payer = "BucketOwner"

  tags = {
    Name        = "OwnerPaysBucket"
    Environment = "Dev"
  }
}

# 2. Enforce Bucket Owner Ownership
# This ensures that even if other accounts upload objects, the bucket owner owns them.
resource "aws_s3_bucket_ownership_controls" "owner_controls" {
  bucket = aws_s3_bucket.owner_pays_bucket.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

# 3. Enable Versioning
resource "aws_s3_bucket_versioning" "versioning" {
  bucket = aws_s3_bucket.owner_pays_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 4. Enable Default Server-Side Encryption (AES256)
resource "aws_s3_bucket_server_side_encryption_configuration" "encryption" {
  bucket = aws_s3_bucket.owner_pays_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# 5. Block all Public Access (Best Practice)
resource "aws_s3_bucket_public_access_block" "public_access" {
  bucket = aws_s3_bucket.owner_pays_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

output "bucket_name" {
  value       = aws_s3_bucket.owner_pays_bucket.id
  description = "The name of the S3 bucket."
}

output "request_payer_setting" {
  value       = aws_s3_bucket.owner_pays_bucket.request_payer
  description = "The Request Payer configuration for the bucket."
}

