  bucket = "my-infrastructure-logs-destination-unique-id"
}

# Ensure the destination bucket has the appropriate ACL for logging
# Note: Modern S3 usage often prefers Bucket Policies, but log delivery 
# traditionally uses the LogDelivery write permission.
resource "aws_s3_bucket_ownership_controls" "log_bucket_oc" {
  bucket = aws_s3_bucket.log_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
