# Terraform configuration for an AWS-based Autograding System

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket to store grading results and logs
resource "aws_s3_bucket" "grading_artifacts" {
  bucket        = "cs-course-autograder-results-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 2. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# 3. IAM Policy for Logging and S3 access
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.grading_artifacts.arn,
          "${aws_s3_bucket.grading_artifacts.arn}/*"
        ]
      }
    ]
  })
}

# 4. GitHub Connection (Requires a Personal Access Token created in GitHub)
# Note: In a production environment, use a variable for the token.
resource "aws_codebuild_source_credential" "github_auth" {
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  server_type = "GITHUB"
  token       = "REPLACE_WITH_YOUR_GITHUB_PAT"
}

# 5. CodeBuild Project for Grading
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder-system"
  description   = "Automated grading system for CS coursework"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.grading_artifacts.name
    name     = "grading-output"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0" # Supports Python, Java, Node.js, C++
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_ENV"
      value = "production"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo-template.git"
    git_clone_depth = 1

    # This defines how the tests are run. 
    # Usually, you would have a 'buildspec.yml' in the repo, 
    # but we can override it here to ensure students don't tamper with the grading logic.
    buildspec = <<-EOF
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.11
          commands:
            - echo Installing test dependencies...
            - pip install pytest
        pre_build:
          commands:
            - echo Validating student submission structure...
        build:
          commands:
            - echo Starting Autograder...
            - pytest grading_tests/ --junitxml=results.xml
        post_build:
          commands:
            - echo Grading completed on `date`
      artifacts:
        files:
          - results.xml
          - grading_output.log
    EOF
  }

  # Enable Webhooks to trigger grading on every Push to GitHub
  source_version = "main"
}

# 6. Webhook for automatic grading on Pull Request or Push
resource "aws_codebuild_webhook" "github_webhook" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH, PULL_REQUEST_CREATED, PULL_REQUEST_UPDATED"
    }
  }
}

output "s3_bucket_name" {
  value = aws_s3_bucket.grading_artifacts.id
}

output "codebuild_project_arn" {
  value = aws_codebuild_project.autograder.arn
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-bucket-"
}

resource "aws_codebuild_project" "autograder_build" {
  name         = "autograder_build"
  service_role = aws_iam_role.autograder_build_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.artifact_bucket.arn
    name     = "results.zip" # include this
  }

  environment { # arguments required, exact value not specified
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0-24.10.29"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    git_clone_depth = 1 # good to have, not required
    location        = "github.com/source-location"
  }
}

resource "aws_iam_role" "autograder_build_role" {
  assume_role_policy = data.aws_iam_policy_document.autograder_build_policy_assume.json
}

data "aws_iam_policy_document" "autograder_build_policy_assume" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }

}

data "aws_iam_policy_document" "autograder_build_policy" {
  statement {
    effect = "Allow"
    actions = [
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeVpcs"
    ]
    resources = [
      "*"
    ]
  }
}

resource "aws_iam_policy" "autograder_build_policy" {
  name        = "lambda_policy"
  description = "Grants permissions to Lambda to describe vpc, subnet, security group"

  policy = data.aws_iam_policy_document.autograder_build_policy.json
}

resource "aws_iam_role_policy_attachment" "lambda_policy_attach" {
  role       = aws_iam_role.autograder_build_role.name
  policy_arn = aws_iam_policy.autograder_build_policy.arn
}

response:
To set up an AWS CodeBuild-based autograding system, we need to configure:
1.  **CodeBuild Project**: The engine that pulls GitHub code, runs the test scripts, and generates the grade.
