version: 0.2
phases:
  install:
    commands:
      - echo Installing test dependencies...
      - pip install pytest
  build:
    commands:
      - echo Running Student Submission Tests...
      - pytest tests/ --junitxml=results.xml
  post_build:
    commands:
      - echo Grading completed on `date`
artifacts:
  files:
    - results.xml
    - feedback.txt
EOF
  }

  source_version = "main"
}

# 5. Webhook to trigger autograding on every GitHub push
resource "aws_codebuild_webhook" "github_trigger" {
  project_name = aws_codebuild_project.autograder.name
  build_type   = "BUILD"

  filter_group {
    filter {
      type    = "EVENT"
      pattern = "PUSH"
    }
    filter {
      type    = "HEAD_REF"
      pattern = "^refs/heads/main$"
    }
  }
}

# Outputs
output "s3_bucket_name" {
  value = aws_s3_bucket.grading_outputs.id
}

output "codebuild_project_arn" {
  value = aws_codebuild_project.autograder.arn
}
