# Terraform configuration for a Secure Autograding System

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Isolation - VPC with no Internet Gateway
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "autograder-isolated-vpc" }
}

resource "aws_subnet" "private_grading_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = { Name = "autograder-private-subnet" }
}

# 2. Security Group for CodeBuild
resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Block all egress to internet"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow internal communication if needed, but no outbound 0.0.0.0/0
  # CodeBuild requires egress to reach VPC Endpoints
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
  }
}

# 3. VPC Endpoints (Allow CodeBuild to upload logs/artifacts without Internet)
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"
  route_table_ids = [aws_vpc.autograder_vpc.main_route_table_id]
}

resource "aws_vpc_endpoint" "logs" {
  vpc_id             = aws_vpc.autograder_vpc.id
  service_name       = "com.amazonaws.us-east-1.logs"
  vpc_endpoint_type  = "Interface"
  subnet_ids         = [aws_subnet.private_grading_subnet.id]
  security_group_ids = [aws_security_group.codebuild_sg.id]
  private_dns_enabled = true
}

# 4. Storage for Grading Results
resource "aws_s3_bucket" "grading_results" {
  bucket        = "cs-autograder-results-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 5. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "codebuild.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "s3:PutObject",
          "s3:GetObject",
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

# 6. CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name           = "student-submission-autograder"
  description    = "Executes student code in an isolated VPC environment"
  service_role   = aws_iam_role.codebuild_role.arn
  build_timeout  = "5"

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_results.bucket
    packaging = "NONE"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    # Ensure student code cannot access metadata service
    environment_variable {
      name  = "GRADING_MODE"
      value = "STRICT"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-repo-template.git" # Placeholder
    git_clone_depth = 1
    buildspec       = "buildspec.yml" # This file in the repo defines the test execution
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.private_grading_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = {
    Environment = "Production"
    Purpose     = "Autograding"
  }
}

