    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Layer: Strict Isolation
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags                 = { Name = "autograder-vpc" }
}

resource "aws_subnet" "isolated_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags              = { Name = "autograder-isolated-subnet" }
}

# Security Group: Allow no outbound/inbound traffic during execution
resource "aws_security_group" "codebuild_sg" {
  name        = "autograder-codebuild-sg"
  description = "Block all internet access for student code"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress rules defined = Default Deny All.
  # This ensures the running code cannot reach the internet.
}

# VPC Endpoints: Required for CodeBuild to talk to S3 and Logging without an IGW
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_vpc.autograder_vpc.main_route_table_id]
}

# 2. Storage: S3 Buckets for Resources and Results
resource "aws_s3_bucket" "grading_assets" {
  bucket        = "cs-course-autograder-assets-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 3. IAM: Execution Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action    = "sts:AssumeRole"
      Effect    = "Allow"
      Principal = { Service = "codebuild.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "*"
      },
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.grading_assets.arn,
          "${aws_s3_bucket.grading_assets.arn}/*"
        ]
      },
      {
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

# 4. CodeBuild: The Grading Engine
resource "aws_codebuild_project" "autograder" {
  name          = "student-submission-autograder"
  description   = "Executes student code in a VPC-isolated environment"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_OUTPUT_BUCKET"
      value = aws_s3_bucket.grading_assets.bucket
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/student-repo.git" # Placeholder
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        install:
          commands:
            - echo "Setup grading environment"
        build:
          commands:
            - echo "Running student tests..."
            - # Integration: run grading script and output to results.json
            - python3 grade_submission.py > results.json || true
        post_build:
          commands:
            - aws s3 cp results.json s3://$GRADING_OUTPUT_BUCKET/results/$CODEBUILD_BUILD_ID.json
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.isolated_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-logs"
      stream_name = "grading-execution"
    }
  }
}

# Output the bucket name for results
output "results_bucket" {
  value = aws_s3_bucket.grading_assets.id
}

