# Terraform configuration for a secure Computer Science Autograding System

provider "aws" {
  region = "us-east-1"
}

# 1. Network Isolation - VPC and Private Subnet
resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "autograder-vpc" }
}

resource "aws_subnet" "private_grading_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = { Name = "autograder-private-subnet" }
}

# 2. Security Group - Deny all outbound traffic to block internet access
resource "aws_security_group" "grading_sg" {
  name        = "student-code-isolation-sg"
  description = "Block all egress to prevent data exfiltration"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No egress (outbound) rules defined = Default Deny All
  # Only ingress as required for internal management (optional)
  tags = { Name = "autograder-isolation-sg" }
}

# 3. Storage - S3 Bucket for submission logs and grading results
resource "aws_s3_bucket" "grading_results" {
  bucket = "cs-course-autograder-results-${random_id.id.hex}"
}

resource "random_id" "id" {
  byte_length = 4
}

# 4. IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = { Service = "codebuild.amazonaws.com" }
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.grading_results.arn,
          "${aws_s3_bucket.grading_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

# 5. CodeBuild Project - The grading engine
resource "aws_codebuild_project" "autograder" {
  name           = "student-submission-grader"
  description    = "Executes student code in an isolated environment"
  service_role   = aws_iam_role.codebuild_role.arn
  build_timeout  = "5" # Short timeout to prevent infinite loops

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.grading_results.name
    name     = "grading-artifacts"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0" # Contains Python, Java, GCC
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_MODE"
      value = "STRICT"
    }
  }

  # Strategic link to GitHub (requires manual OAuth/Connection setup in Console or via aws_codebuild_source_credential)
  source {
    type            = "GITHUB"
    location        = "https://github.com/your-org/student-submissions-repo.git"
    git_clone_depth = 1
    buildspec       = "buildspec.yml" # This file in the repo defines the grading commands
  }

  # VPC Configuration to pull compute into our isolated subnet
  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.private_grading_subnet.id]
    security_group_ids = [aws_security_group.grading_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "autograder-logs"
      status      = "ENABLED"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.grading_results.id}/build-log"
    }
  }
}

# VPC Endpoints (Required)
# Since the VPC has no internet access, CodeBuild needs endpoints to talk to S3 and CloudWatch Logs
resource "aws_vpc_endpoint" "s3" {
  vpc_id       = aws_vpc.autograder_vpc.id
  service_name = "com.amazonaws.us-east-1.s3"
  route_table_ids = [aws_vpc.autograder_vpc.main_route_table_id]
}

output "s3_bucket_name" {
  value = aws_s3_bucket.grading_results.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

