# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Cat Images
resource "aws_s3_bucket" "cat_storage" {
  bucket        = "cat-images-app-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# Public access block for the bucket (adjust based on security needs)
resource "aws_s3_bucket_public_access_block" "cat_storage_access" {
  bucket = aws_s3_bucket.cat_storage.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# 2. IAM Role for API Gateway to write to/read from S3
resource "aws_iam_role" "api_gateway_s3_role" {
  name = "api-gateway-s3-cat-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "apigateway.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "s3_access" {
  name = "APIGatewayS3CatPolicy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["s3:PutObject", "s3:GetObject", "s3:ListBucket"]
        Effect   = "Allow"
        Resource = [
          "${aws_s3_bucket.cat_storage.arn}",
          "${aws_s3_bucket.cat_storage.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "api_s3_attach" {
  role       = aws_iam_role.api_gateway_s3_role.name
  policy_arn = aws_iam_policy.s3_access.arn
}

# 3. API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatPhotoAPI"
  description = "API to upload and retrieve cat photos"

  binary_media_types = ["image/jpeg", "image/png", "image/gif"]
}

# Resource: /upload/{filename}
resource "aws_api_gateway_resource" "upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

resource "aws_api_gateway_resource" "file_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_resource.upload_resource.id
  path_part   = "{item}"
}

# METHOD: PUT (Upload)
resource "aws_api_gateway_method" "put_cat" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.file_resource.id
  http_method   = "PUT"
  authorization = "NONE"
  request_parameters = {
    "method.request.path.item" = true
  }
}

resource "aws_api_gateway_integration" "s3_upload_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.file_resource.id
  http_method             = aws_api_gateway_method.put_cat.http_method
  type                    = "AWS"
  integration_http_method = "PUT"
  uri                     = "arn:aws:apigateway:us-east-1:s3:path/${aws_s3_bucket.cat_storage.id}/{item}"
  credentials             = aws_iam_role.api_gateway_s3_role.arn

  request_parameters = {
    "integration.request.path.item" = "method.request.path.item"
  }
}

resource "aws_api_gateway_method_response" "put_200" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.file_resource.id
  http_method = aws_api_gateway_method.put_cat.http_method
  status_code = "200"
}

resource "aws_api_gateway_integration_response" "put_s3_response" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.file_resource.id
  http_method = aws_api_gateway_method.put_cat.http_method
  status_code = aws_api_gateway_method_response.put_200.status_code

  depends_on = [aws_api_gateway_integration.s3_upload_integration]
}

# Resource: /random
resource "aws_api_gateway_resource" "random_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# METHOD: GET (Retrieve)
# Note: For a true "random" photo from S3 without Lambda, we map a specific path 
# or use a redirect. Here we create the GET integration to S3.
resource "aws_api_gateway_method" "get_cat" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random_resource.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "s3_get_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.random_resource.id
  http_method             = aws_api_gateway_method.get_cat.http_method
  type                    = "AWS"
  integration_http_method = "GET"
  # In a production scenario, you would use a Lambda to pick a random key.
  # Here we proxy to a specific "latest-cat.jpg" or similar naming convention for simplicity.
  uri                     = "arn:aws:apigateway:us-east-1:s3:path/${aws_s3_bucket.cat_storage.id}/random-cat.jpg"
  credentials             = aws_iam_role.api_gateway_s3_role.arn
}

resource "aws_api_gateway_method_response" "get_200" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random_resource.id
  http_method = aws_api_gateway_method.get_cat.http_method
  status_code = "200"
  response_parameters = {
    "method.response.header.Content-Type" = true
  }
}

resource "aws_api_gateway_integration_response" "get_s3_response" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.random_resource.id
  http_method = aws_api_gateway_method.get_cat.http_method
  status_code = aws_api_gateway_method_response.get_200.status_code

  response_parameters = {
    "method.response.header.Content-Type" = "integration.response.header.Content-Type"
  }

  depends_on = [aws_api_gateway_integration.s3_get_integration]
}

# 4. Deployment
resource "aws_api_gateway_deployment" "cat_api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  depends_on = [
    aws_api_gateway_integration.s3_upload_integration,
    aws_api_gateway_integration.s3_get_integration
  ]
}

resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_api_deployment.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

# Outputs
output "api_url" {
  value       = "${aws_api_gateway_stage.prod.invoke_url}/upload/{filename}"
  description = "URL to upload cat images (Use PUT)"
}

output "random_cat_url" {
  value       = "${aws_api_gateway_stage.prod.invoke_url}/random"
  description = "URL to fetch a cat image"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_storage.bucket
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_dynamodb_table" "caas" {
  name           = "cat_names"
  hash_key       = "name"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "name"
    type = "S"
  }
}

resource "aws_s3_bucket" "caas" {
  bucket_prefix = "cat-image"
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_api_gateway_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name   = "lambda_policy"
  role   = aws_iam_role.lambda_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.caas.arn}/*"
      },
      {
        Action = [
          "dynamodb:PutItem"
        ]
        Effect   = "Allow"
        Resource = aws_dynamodb_table.caas.arn
      }
    ]
  })
}

resource "aws_api_gateway_rest_api" "caas" {
  name = "caas"
}

resource "aws_api_gateway_resource" "caas_cat" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  parent_id   = aws_api_gateway_rest_api.caas.root_resource_id
  path_part   = "cat"
}

resource "aws_api_gateway_method" "caas_cat_get" {
