# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Cat Images
resource "aws_s3_bucket" "cat_images" {
  bucket        = "cat-images-storage-${random_id.suffix.hex}"
  force_destroy = true
}

resource "random_id" "suffix" {
  byte_length = 4
}

# 2. IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "cat_api_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# IAM Policy for S3 access and Logging
resource "aws_iam_role_policy" "lambda_policy" {
  role = aws_iam_role.lambda_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["s3:PutObject", "s3:GetObject", "s3:ListBucket"]
        Effect   = "Allow"
        Resource = ["${aws_s3_bucket.cat_images.arn}", "${aws_s3_bucket.cat_images.arn}/*"]
      },
      {
        Action   = ["logs:CreateLogGroup", "logs:CreateLogStream", "logs:PutLogEvents"]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# 3. Lambda Function
# Note: This assumes a file named "lambda_function_payload.zip" exists containing your logic.
resource "aws_lambda_function" "cat_api_handler" {
  filename      = "lambda_function_payload.zip"
  function_name = "cat_api_handler"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
    }
  }
}

# 4. API Gateway (HTTP API)
resource "aws_apigatewayv2_api" "cat_api" {
  name          = "cat-image-api"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_stage" "default" {
  api_id      = aws_apigatewayv2_api.cat_api.id
  name        = "$default"
  auto_deploy = true
}

# Integration between API Gateway and Lambda
resource "aws_apigatewayv2_integration" "lambda_integration" {
  api_id             = aws_apigatewayv2_api.cat_api.id
  integration_type   = "AWS_PROXY"
  integration_method = "POST"
  integration_uri    = aws_lambda_function.cat_api_handler.invoke_arn
}

# 5. API Routes
# POST /upload for uploading images
resource "aws_apigatewayv2_route" "upload" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "POST /upload"
  target    = "integrations/${aws_apigatewayv2_integration.lambda_integration.id}"
}

# GET /random for getting a random image
resource "aws_apigatewayv2_route" "random" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "GET /random"
  target    = "integrations/${aws_apigatewayv2_integration.lambda_integration.id}"
}

# Lambda permission to allow API Gateway invocation
resource "aws_lambda_permission" "api_gw" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_api_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cat_api.execution_arn}/*/*"
}

# Outputs
output "api_endpoint" {
  value       = aws_apigatewayv2_api.cat_api.api_endpoint
  description = "The base URL of the Cat API Gateway"
}

output "s3_bucket_name" {
  value = aws_s3_bucket.cat_images.id
}

