provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Cat Images
resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-image-storage-unique-id-12345"
}

# 2. DynamoDB Table for Metadata
resource "aws_dynamodb_table" "cat_metadata" {
  name           = "CatImagesMetadata"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "ImageId"

  attribute {
    name = "ImageId"
    type = "S"
  }
}

# 3. IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "cat_service_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name = "cat_service_policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:PutObject",
          "s3:GetObject"
        ]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.cat_images.arn}/*"
      },
      {
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:Scan"
        ]
        Effect   = "Allow"
        Resource = aws_dynamodb_table.cat_metadata.arn
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# 4. Lambda Function
resource "aws_lambda_function" "cat_handler" {
  filename      = "lambda_function_payload.zip" # Assumes local zip exists
  function_name = "cat_service_handler"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.id
      TABLE_NAME  = aws_dynamodb_table.cat_metadata.name
    }
  }
}

# 5. API Gateway (REST API)
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatServiceAPI"
  description = "API for uploading and retrieving cat images"
}

resource "aws_api_gateway_resource" "cat_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "cats"
}

resource "aws_api_gateway_method" "cat_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.cat_resource.id
  http_method   = "ANY"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "lambda_integration" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.cat_resource.id
  http_method             = aws_api_gateway_method.cat_method.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_handler.invoke_arn
}

# 6. Lambda Permission for API Gateway
resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_handler.function_name
  principal     = "apigateway.amazonaws.com"
