# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC and Subnet for the EC2 Instance
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
}

# 2. Create the EC2 Instance
# We apply a tag "Backup" = "Daily" which the Backup Plan will use to identify the resource
resource "aws_instance" "app_server" {
  ami           = "ami-0c101f26f147fa7fd" # Amazon Linux 2023 in us-east-1
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.subnet.id

  tags = {
    Name   = "Terraform-EC2-Instance"
    Backup = "Daily"
  }
}

# 3. Create a Backup Vault
resource "aws_backup_vault" "daily_vault" {
  name = "daily_ec2_backup_vault"
}

# 4. Define the IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws_backup_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy_attachment" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 5. Create the Backup Plan (Scheduled for 12:00 AM Daily)
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily_ec2_backup_plan"

  rule {
    rule_name         = "daily_midnight_rule"
    target_vault_name = aws_backup_vault.daily_vault.name
    schedule          = "cron(0 0 * * ? *)" # 12:00 AM daily

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# 6. Assign the EC2 Instance to the Backup Plan via Tags
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2_backup_selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "Daily"
  }
}

