  tags = { Name = "backup-demo-vpc" }
}

resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = { Name = "backup-demo-subnet" }
}

# 2. Launch the EC2 Instance
# We apply a specific tag "Backup" = "Daily" which the backup plan will look for
