  ami           = "ami-0c101f26f147fa7fd" # Amazon Linux 2023 AMI (check region)
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.public.id

  tags = {
    Name   = "Production-App-Server"
    Backup = "Daily"
  }
}

# 3. Create an AWS Backup Vault
resource "aws_backup_vault" "ec2_backup_vault" {
  name = "daily-ec2-backup-vault"
}

# 4. Create an AWS Backup Plan
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-ec2-backup-plan"

  rule {
