# 7. AWS Backup Selection (Assignment)
# This assigns any resource with the tag Backup=Daily to the plan
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily-ec2-selection"
  plan_id      = aws_backup_plan.daily_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "Daily"
  }
}

# Output the Instance ID and Key
output "instance_id" {
  value = aws_instance.web_server.id
}

output "private_key_pem" {
  value     = tls_private_key.example_key.private_key_pem
  sensitive = true
}

