response:
To implement an EC2 instance with a daily backup schedule using AWS Backup, we need to configure the compute layer (Instance and Key Pair), the backup storage (Vault), the schedule (Plan), and the IAM permissions that allow the AWS Backup service to interact with EC2.

The following configuration includes:
1.  **AWS Provider and Data Sources**: For region and availability zone management.
2.  **EC2 Key Pair**: Generates a TLS private key and stores it as an AWS Key Pair.
3.  **EC2 Instance**: A basic T3.micro instance (Amazon Linux 2023).
4.  **AWS Backup Vault**: Secure storage for the recovery points.
5.  **AWS Backup Plan**: Logic for the daily backup at 00:00 UTC with a 30-day retention.
6.  **IAM Role & Selection**: Assigns the instance to the backup plan using tags.

```hcl
# 1. Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 2. Key Pair Generation
resource "tls_private_key" "example_key" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

resource "aws_key_pair" "generated_key" {
  key_name   = "server-backup-key"
  public_key = tls_private_key.example_key.public_key_openssh
}

# 3. EC2 Instance
resource "aws_instance" "web_server" {
  ami           = "ami-0ebfd141b224c8c73" # Amazon Linux 2023 AMI in us-east-1
  instance_type = "t3.micro"
  key_name      = aws_key_pair.generated_key.key_name

  tags = {
    Name   = "BackupDemoInstance"
    Backup = "Daily"
  }
}

# 4. AWS Backup Vault
resource "aws_backup_vault" "daily_vault" {
  name = "ec2-daily-backup-vault"
}

# 5. AWS Backup Plan
resource "aws_backup_plan" "daily_plan" {
  name = "daily-ec2-backup-plan"

  rule {
    rule_name         = "daily-midnight-rule"
    target_vault_name = aws_backup_vault.daily_vault.name
    # Cron: 00:00 AM daily
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 30 # Retain backups for 30 days
    }
  }
}

# 6. IAM Role for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_policy" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup_role.name
}

# 7. AWS Backup Selection (Assignment)
# This assigns any resource with the tag Backup=Daily to the plan
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "daily-ec2-selection"
  plan_id      = aws_backup_plan.daily_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "Daily"
  }
}

# Output the Instance ID and Key
output "instance_id" {
  value = aws_instance.web_server.id
}

output "private_key_pem" {
  value     = tls_private_key.example_key.private_key_pem
  sensitive = true
}
```

