# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lambda execution
resource "aws_iam_role" "lambda_exec_role" {
  name = "daily_job_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic execution policy to the role
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. The Lambda Function (The "Code")
resource "aws_lambda_function" "scheduled_task" {
  filename      = "function.zip" # Placeholder for your actual deployment package
  function_name = "daily_0700_task"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      ENVIRONMENT = "production"
    }
  }
}

# 3. EventBridge Rule (The Scheduler)
# Cron format: (Minutes Hours Day-of-month Month Day-of-week Year)
resource "aws_cloudwatch_event_rule" "daily_seven_am" {
  name                = "execute-daily-at-0700"
  description         = "Trigger lambda every day at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# 4. EventBridge Target (Connecting Rule to Lambda)
resource "aws_cloudwatch_event_target" "invoke_lambda_daily" {
  rule      = aws_cloudwatch_event_rule.daily_seven_am.name
  target_id = "SendToLambda"
  arn       = aws_lambda_function.scheduled_task.arn
}

# 5. Permission for EventBridge to call Lambda
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_task.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_seven_am.arn
}

