response:
To implement a daily scheduled execution at 07:00 UTC using Amazon EventBridge and AWS Lambda, we need to configure:
1.  An **IAM Role** for the Lambda function with basic execution permissions.
2.  The **Lambda Function** itself containing the logic.
3.  An **EventBridge Rule** defined with a cron expression (`0 7 * * ? *`).
4.  A **Lambda Permission** to allow EventBridge to trigger the function.
5.  An **EventBridge Target** to link the rule to the Lambda function.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. IAM Role for Lambda
resource "aws_iam_role" "lambda_exec_role" {
  name = "daily_job_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Sid    = ""
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# Attach basic execution policy (CloudWatch Logs)
resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# 2. Lambda Function
# Note: For production, provide the 'filename' to a local .zip or 's3_bucket'
resource "aws_lambda_function" "daily_task" {
  filename      = "lambda_function_payload.zip" # Placeholder for your deployment package
  function_name = "daily_scheduled_job"
  role          = aws_iam_role.lambda_exec_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      JOB_NAME = "DailyMorningSync"
    }
  }
}

# 3. EventBridge Rule (Cron: 07:00 UTC daily)
# Cron Format: Minutes Hours Day-of-month Month Day-of-week Year
resource "aws_cloudwatch_event_rule" "daily_seven_am" {
  name                = "execute-daily-at-0700"
  description         = "Triggers the Lambda function every day at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# 4. Permission for EventBridge to invoke Lambda
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_task.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_seven_am.arn
}

# 5. EventBridge Target
resource "aws_cloudwatch_event_target" "run_lambda_daily" {
  rule      = aws_cloudwatch_event_rule.daily_seven_am.name
  target_id = "TriggerLambda"
  arn       = aws_lambda_function.daily_task.arn
}

# Output the Lambda ARN
output "lambda_function_arn" {
  value = aws_lambda_function.daily_task.arn
}
```

