To implement this infrastructure, we need to define the Lambda function, the IAM role it requires to execute, the EventBridge rule with the specified cron schedule, the target to link the rule to the Lambda, and finally the permission allowing EventBridge to invoke that specific function.

```hcl
# IAM Role for Lambda execution
resource "aws_iam_role" "lambda_exec" {
  name = "cron-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# AWS Lambda Function
resource "aws_lambda_function" "cron" {
  function_name = "cron-lambda-function"
  filename      = "./supplement/lambda_func.zip"
  handler       = "lambda_func.lambda_handler"
  runtime       = "python3.12"
  role          = aws_iam_role.lambda_exec.arn
}

# EventBridge Rule (Cron for 07:00 UTC daily)
resource "aws_cloudwatch_event_rule" "cron" {
  name                = "cron"
  description         = "Trigger daily at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# EventBridge Target linking rule to Lambda
resource "aws_cloudwatch_event_target" "cron_target" {
  rule      = aws_cloudwatch_event_rule.cron.name
  target_id = "TriggerCronLambda"
  arn       = aws_lambda_function.cron.arn
}

# Lambda Permission to allow EventBridge invocation
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cron.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.cron.arn
}
