response:
To design a globally distributed video streaming platform, we need to implement the following:
1.  **Amazon S3**: To store the raw video files and HLS/DASH segments securely.
2.  **Amazon CloudFront**: To act as the Content Delivery Network (CDN) for low-latency global edge delivery. 
3.  **Origin Access Control (OAC)**: To ensure the S3 bucket is private and only accessible via CloudFront.
4.  **Amazon Route 53**: To manage DNS and route traffic to the CloudFront distribution via a custom domain.
5.  **AWS Shield & WAF (Optional but recommended)**: To protect against DDoS and common web exploits.

```hcl
# Terraform Configuration for a Global Video Streaming Platform

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. S3 Bucket for Video Content
resource "aws_s3_bucket" "video_assets" {
  bucket        = "global-video-streaming-assets-prod"
  force_destroy = true
}

# Block public access to the bucket
resource "aws_s3_bucket_public_access_block" "video_assets_block" {
  bucket = aws_s3_bucket.video_assets.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 2. CloudFront Origin Access Control (OAC)
resource "aws_cloudfront_origin_access_control" "default" {
  name                              = "s3-video-oac"
  description                       = "OAC for Video Streaming S3 bucket"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# 3. CloudFront Distribution
resource "aws_cloudfront_distribution" "video_cdn" {
  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global Video Delivery Network"
  default_root_object = "index.html"

  origin {
    domain_name              = aws_s3_bucket.video_assets.bucket_regional_domain_name
    origin_id                = "S3-VideoOrigin"
    origin_access_control_id = aws_cloudfront_origin_access_control.default.id
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-VideoOrigin"

    forwarded_values {
      query_string = false
      headers      = ["Origin", "Access-Control-Request-Headers", "Access-Control-Request-Method"]
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
    compress               = true
  }

  # Optimized for Global distribution (All Edge Locations)
  price_class = "PriceClass_All"

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

# 4. S3 Bucket Policy to allow CloudFront access via OAC
resource "aws_s3_bucket_policy" "allow_cloudfront_oac" {
  bucket = aws_s3_bucket.video_assets.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "s3:GetObject"
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.video_assets.arn}/*"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_cdn.arn
          }
        }
      }
    ]
  })
}

# 5. Route 53 DNS Record (Assuming a hosted zone exists)
data "aws_route53_zone" "selected" {
  name         = "example.com."
  private_zone = false
}

resource "aws_route53_record" "stream_dns" {
  zone_id = data.aws_route53_zone.selected.zone_id
  name    = "stream.${data.aws_route53_zone.selected.name}"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_cdn.domain_name
    zone_id                = aws_cloudfront_distribution.video_cdn.hosted_zone_id
    evaluate_target_health = false
  }
}

# Outputs
output "cloudfront_domain_name" {
  value       = aws_cloudfront_distribution.video_cdn.domain_name
  description = "The domain name of the CloudFront distribution"
}

output "video_bucket_name" {
  value       = aws_s3_bucket.video_assets.id
  description = "The S3 bucket name for video storage"
}
```

