response:
To build a resilient video streaming platform on AWS, we need a Virtual Private Cloud (VPC) with public subnets for the Load Balancer and private subnets for the streaming servers. We will use an Application Load Balancer (ALB) to handle incoming traffic and an Auto Scaling Group (ASG) to manage a fleet of EC2 instances.

```hcl
# Terraform configuration for a Multi-Server Video Streaming Architecture

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure
resource "aws_vpc" "streaming_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = { Name = "streaming-vpc" }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.streaming_vpc.id
}

resource "aws_subnet" "public" {
  count                   = 2
  vpc_id                  = aws_vpc.streaming_vpc.id
  cidr_block              = "10.0.${count.index}.0/24"
  availability_zone       = count.index == 0 ? "us-east-1a" : "us-east-1b"
  map_public_ip_on_launch = true
  tags = { Name = "streaming-public-${count.index}" }
}

# 2. Security Groups
resource "aws_security_group" "alb_sg" {
  name        = "streaming-alb-sg"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "server_sg" {
  name        = "streaming-server-sg"
  vpc_id      = aws_vpc.streaming_vpc.id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Load Balancer Configuration
resource "aws_lb" "streaming_alb" {
  name               = "streaming-platform-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id
}

resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-servers-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.streaming_vpc.id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# 4. Auto Scaling Group & Launch Template
resource "aws_launch_template" "streaming_lt" {
  name_prefix   = "streaming-server-"
  image_id      = "ami-0c101f26f147fa7fd" # Amazon Linux 2023 AMI
  instance_type = "t3.medium"

  network_interfaces {
    associate_public_ip_address = true
    security_groups             = [aws_security_group.server_sg.id]
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Video Streaming Server: $(hostname -f)</h1>" > /var/www/html/index.html
              EOF
  )
}

resource "aws_autoscaling_group" "streaming_asg" {
  desired_capacity    = 2
  max_size            = 4
  min_size            = 2
  target_group_arns   = [aws_lb_target_group.streaming_tg.arn]
  vpc_zone_identifier = aws_subnet.public[*].id

  launch_template {
    id      = aws_launch_template.streaming_lt.id
    version = "$Latest"
  }

  tag {
    key                 = "Name"
    value               = "streaming-instance"
    propagate_at_launch = true
  }
}

# Outputs
output "alb_dns_name" {
  value       = aws_lb.streaming_alb.dns_name
  description = "The domain name of the load balancer to access the streaming platform."
}
```

extracted_code:
# Terraform Configuration for a Video Streaming Platform Architecture

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. VPC Module for Network Isolation
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.0.0"

  name = "streaming-platform-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b", "us-east-1c"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24", "10.0.103.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true

  tags = {
    Environment = "Production"
    Project     = "VideoStreaming"
  }
}

# 2. Security Groups
resource "aws_security_group" "alb_sg" {
  name        = "alb-sg"
  vpc_id      = module.vpc.vpc_id
  description = "Allow HTTP traffic"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "ec2_sg" {
  name        = "ec2-streaming-sg"
  vpc_id      = module.vpc.vpc_id
  description = "Allow traffic from ALB"

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. S3 Bucket for Video Assets
resource "aws_s3_bucket" "video_assets" {
  bucket = "my-streaming-platform-assets-unique-id"
}

# 4. EC2 Launch Template & Auto Scaling Group (Traffic Distribution)
resource "aws_launch_template" "streaming_app" {
  name_prefix   = "streaming-server"
  image_id      = "ami-0cff7528ff583bf9a" # Amazon Linux 2
  instance_type = "t3.medium"

  network_interfaces {
    associate_public_ip_address = false
    security_groups             = [aws_security_group.ec2_sg.id]
  }

  user_data = base64encode(<<-EOF
              #!/bin/bash
              yum update -y
              amazon-linux-extras install nginx1 -y
              systemctl start nginx
              systemctl enable nginx
              echo "<h1>Streaming Node: $(hostname)</h1>" > /usr/share/nginx/html/index.html
              EOF
  )
}

resource "aws_autoscaling_group" "streaming_asg" {
  desired_capacity    = 3
  max_size            = 6
  min_size            = 2
  target_group_arns   = [aws_lb_target_group.streaming_tg.arn]
  vpc_zone_identifier = module.vpc.private_subnets

  launch_template {
    id      = aws_launch_template.streaming_app.id
    version = "$Latest"
  }
}

# 5. Application Load Balancer
resource "aws_lb" "streaming_alb" {
  name               = "streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets
}

resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-app-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path = "/"
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# 6. Route 53 DNS Configuration
resource "aws_route53_zone" "primary" {
  name = "example-streaming.com"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.example-streaming.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_alb.dns_name
    zone_id                = aws_lb.streaming_alb.zone_id
    evaluate_target_health = true
  }
}

# 7. CloudFront for Content Delivery (Recommended for Video)
resource "aws_cloudfront_distribution" "s3_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_assets.bucket_regional_domain_name
    origin_id   = "S3-StreamingAssets"
  }

  enabled         = true
  is_ipv6_enabled = true

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-StreamingAssets"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

output "alb_dns_name" {
  value = aws_lb.streaming_alb.dns_name
}

output "cloudfront_domain" {
  value = aws_cloudfront_distribution.s3_distribution.domain_name
}

