# --- Networking ---
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = { Name = "rds-protected-vpc" }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags              = { Name = "rds-private-1a" }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags              = { Name = "rds-private-1b" }
}

resource "aws_db_subnet_group" "db_net_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = { Name = "Main DB Subnet Group" }
}

# --- Security & Encryption ---
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Restrict to VPC internal traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS storage encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

# --- RDS Configuration ---
resource "aws_db_parameter_group" "postgresql_params" {
  name   = "custom-postgres15-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }
}

resource "aws_db_instance" "protected_db" {
  identifier        = "protected-postgresql-instance"
  engine            = "postgres"
  engine_version    = "15.4"
  instance_class    = "db.t3.medium"
  allocated_storage = 50
  storage_type      = "gp3"

  # High Availability & Network
  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.db_net_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  # Parameters & Credentials
  db_name              = "protected_db"
  username             = "dbadmin"
  password             = "Password123!" # In production, use Sensitive Variables or Secrets Manager
  parameter_group_name = aws_db_parameter_group.postgresql_params.name

  # Encryption & Protection
  storage_encrypted   = true
  kms_key_id          = aws_kms_key.rds_key.arn
  deletion_protection = true
  skip_final_snapshot = false
  final_snapshot_identifier = "final-snapshot-protected-db"

  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "Mon:04:30-Mon:05:30"

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}
