To implement a protected, high-availability PostgreSQL RDS instance on AWS, we need to define the VPC networking components (subnets and security groups), a KMS key for encryption at rest, a custom parameter group for database tuning, and the RDS instance itself.

The following configuration sets up a Multi-AZ deployment with encryption and a 7-day backup retention period as requested.

```hcl
# Terraform configuration for a protected PostgreSQL RDS instance

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. KMS Key for RDS Encryption at rest
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS PostgreSQL encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "rds-postgres-kms-key"
  }
}

# 2. RDS Subnet Group (Assumes existing VPC subnets)
# Replace subnet IDs with your actual private subnet IDs
resource "aws_db_subnet_group" "postgres_subnet_group" {
  name       = "postgres-main-subnet-group"
  subnet_ids = ["subnet-xxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyy"]

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# 3. Security Group for Database access control
resource "aws_security_group" "rds_sg" {
  name        = "rds-postgresql-sg"
  description = "Allow inbound traffic to PostgreSQL"
  vpc_id      = "vpc-xxxxxxxxxxxxxx" # Replace with your VPC ID

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to VPC CIDR or specific app subnets
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-security-group"
  }
}

# 4. Custom DB Parameter Group
resource "aws_db_parameter_group" "postgres_params" {
  name   = "postgres15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  tags = {
    Name = "postgres15-parameter-group"
  }
}

# 5. RDS PostgreSQL Instance
resource "aws_db_instance" "postgres_instance" {
  identifier        = "protected-postgres-db"
  engine            = "postgres"
  engine_version    = "15.3"
  instance_class    = "db.t3.micro"
  allocated_storage = 20
  storage_type      = "gp3"

  # Credentials (Use secrets manager/variables in production)
