  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "rds-private-b"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "main-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "RDS Private Subnet Group"
  }
}

# 2. Security & Encryption
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS storage encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-access-control"
  description = "Allow inbound PostgreSQL traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Restricted to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. DB Parameter Group
resource "aws_db_parameter_group" "postgres_custom" {
  name   = "custom-pg15-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }
}

# 4. RDS PostgreSQL Instance
resource "aws_db_instance" "protected_db" {
  identifier        = "protected-postgres-db"
  engine            = "postgres"
  engine_version    = "15.4"
  instance_class    = "db.t3.medium"
  allocated_storage = 20
  storage_type      = "gp3"

  # High Availability & Network
  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  # Encryption
  storage_encrypted = true
  kms_key_id        = aws_kms_key.rds_key.arn

  # Database Credentials
  db_name  = "myappdb"
  username = "dbadmin"
  password = "SensitivePassword123!" # In production, use AWS Secrets Manager

  # Configuration & Snapshots
  parameter_group_name    = aws_db_parameter_group.postgres_custom.name
  skip_final_snapshot     = false
  final_snapshot_identifier = "pgsnapshot"

  backup_retention_period = 7
  deletion_protection     = true

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

