  backup_retention_period = 7
  maintenance_window      = "Mon:00:00-Mon:03:00"

  tags = {
    Environment = "Testing"
    Project     = "AirbyteConnectorTest"
  }
}

output "db_endpoint" {
  value = aws_db_instance.postgresql.endpoint
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 500
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
To provision a managed PostgreSQL 15 instance on AWS suitable for Airbyte connector testing with 500GB of storage, we will configure a VPC, public subnets, an internet gateway, and the RDS instance with the appropriate security groups.

1.  **Network Setup**: We create a VPC with two public subnets across different Availability Zones (required for RDS subnet groups).
2.  **Security**: We create a Security Group that allows inbound traffic on port 5432. For testing, we will enable `publicly_accessible = true`.
3.  **Database**: We use the `aws_db_instance` resource specifying engine version `15`, `gp3` storage (500GB), and `publicly_accessible`.

```hcl
# Terraform configuration for AWS RDS PostgreSQL 15 for Airbyte Testing

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# --- Networking ---

resource "aws_vpc" "airbyte_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "airbyte-test-vpc"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.airbyte_vpc.id
}

resource "aws_subnet" "public_a" {
  vpc_id                  = aws_vpc.airbyte_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
}

resource "aws_subnet" "public_b" {
  vpc_id                  = aws_vpc.airbyte_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
}

resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.airbyte_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public_a.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.public_b.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_db_subnet_group" "airbyte_sng" {
  name       = "airbyte-test-sng"
  subnet_ids = [aws_subnet.public_a.id, aws_subnet.public_b.id]

  tags = {
    Name = "Airbyte Test Subnet Group"
  }
}

# --- Security ---

resource "aws_security_group" "rds_sg" {
  name        = "airbyte-rds-sg"
  description = "Allow access to PostgreSQL"
  vpc_id      = aws_vpc.airbyte_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Caution: In production, limit this to specific IPs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# --- RDS PostgreSQL Instance ---

resource "aws_db_instance" "postgresql" {
  identifier            = "airbyte-test-db"
  engine                = "postgres"
  engine_version        = "15" # Version 15 as requested
  instance_class        = "db.t3.medium"
  allocated_storage     = 500 # 500GB as requested
  storage_type          = "gp3"
  db_name               = "airbyte_test"
  username              = "airbyte_admin"
  password              = "ChangeMe12345!" # Use a secret manager in real scenarios
  db_subnet_group_name  = aws_db_subnet_group.airbyte_sng.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  # Configuration for accessibility and management
  publicly_accessible    = true
  skip_final_snapshot    = true
  deletion_protection    = false

  # Automated backups for operational ease (fully managed)
  backup_retention_period = 7
  maintenance_window      = "Mon:00:00-Mon:03:00"

  tags = {
    Environment = "Testing"
    Project     = "AirbyteConnectorTest"
  }
}

output "db_endpoint" {
  value = aws_db_instance.postgresql.endpoint
}
```

