    cidr_blocks = ["0.0.0.0/0"] # Caution: Opens to the world. In production, restrict to specific IPs.
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 7. Provision the RDS MySQL Instance
resource "aws_db_instance" "mysql_instance" {
  allocated_storage      = 20
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  db_name                = "mydb"
