}

# 1. Network Infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "rds-custom-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "rds-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "rds-subnet-b"
  }
}

# RDS requires a subnet group spanning at least two AZs
resource "aws_db_subnet_group" "postgresql_group" {
  name       = "pg-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# 2. Security Group
resource "aws_security_group" "rds_sg" {
  name        = "allow_postgresql"
  description = "Allow inbound traffic for PostgreSQL"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block] # Restrict to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. PostgreSQL Database Instance
resource "aws_db_instance" "postgresql_db" {
  identifier           = "custom-postgres-instance"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro"

  # Storage Configuration
  allocated_storage     = 5
  max_allocated_storage = 50 # Enables Storage Autoscaling
  storage_type          = "gp3"

  # Database Credentials
  db_name              = "myappdb"
  username             = "dbadmin"
  password             = "Password123!" # In production, use a Secret Manager or Variable
  port                 = 5432

  # Networking
  db_subnet_group_name   = aws_db_subnet_group.postgresql_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = false

  # Maintenance Window (Monday 12:00 AM to 03:00 AM UTC)
  # Format: ddd:hh24:mi-ddd:hh24:mi
  maintenance_window      = "mon:00:00-mon:03:00"
  backup_window           = "21:00-23:00"
  backup_retention_period = 7

  # Settings
  skip_final_snapshot = true
  deletion_protection  = false

  tags = {
    Environment = "Development"
  }
}

output "db_endpoint" {
  value       = aws_db_instance.postgresql_db.endpoint
  description = "The connection endpoint for the database"
}
```

