# Standard Terraform provider and version configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Networking Infrastructure
resource "aws_vpc" "db_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
  tags                 = { Name = "aurora-proxy-vpc" }
}

resource "aws_subnet" "private" {
  count             = 2
  vpc_id            = aws_vpc.db_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = data.aws_availability_zones.available.names[count.index]
  tags              = { Name = "db-private-subnet-${count.index}" }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group"
  subnet_ids = aws_subnet.private[*].id
}

# 2. Security Groups
resource "aws_security_group" "db_sg" {
  name        = "aurora-db-sg"
  description = "Security group for Aurora cluster"
  vpc_id      = aws_vpc.db_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.db_vpc.cidr_block]
  }
}

# 3. Credentials Management (Secrets Manager)
resource "aws_secretsmanager_secret" "db_credentials" {
  name        = "aurora-db-credentials-v3"
  description = "Aurora MySQL database credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials_val" {
  secret_id     = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = "SuperSecurePassword123!" # In production, use a random_password resource
    engine   = "mysql"
    host     = aws_rds_cluster.mysql_cluster.endpoint
    port     = 3306
