  })
}

# 4. Aurora MySQL Cluster
resource "aws_rds_cluster" "mysql_cluster" {
  cluster_identifier      = "aurora-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  database_name           = "myapp"
  master_username         = "admin"
  master_password         = "SuperSecurePassword123!"
  db_subnet_group_name    = aws_db_subnet_group.aurora.name
  vpc_security_group_ids  = [aws_security_group.db_sg.id]
  skip_final_snapshot     = true
}

resource "aws_rds_cluster_instance" "cluster_instances" {
  count              = 2
  identifier         = "aurora-mysql-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.mysql_cluster.id
  instance_class     = "db.t3.medium"
  engine             = aws_rds_cluster.mysql_cluster.engine
  engine_version     = aws_rds_cluster.mysql_cluster.engine_version
}

# 5. RDS Proxy IAM Role
resource "aws_iam_role" "proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = { Service = "rds.amazonaws.com" }
    }]
  })
}

resource "aws_iam_policy" "proxy_policy" {
  name = "rds-proxy-policy"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["secretsmanager:GetSecretValue", "secretsmanager:DescribeSecret"]
        Effect   = "Allow"
        Resource = [aws_secretsmanager_secret.db_credentials.arn]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "proxy_attach" {
  role       = aws_iam_role.proxy_role.name
  policy_arn = aws_iam_policy.proxy_policy.arn
}

# 6. RDS Proxy
resource "aws_db_proxy" "db_proxy" {
  name                   = "aurora-mysql-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.proxy_role.arn
  vpc_security_group_ids = [aws_security_group.db_sg.id]
  vpc_subnet_ids         = aws_subnet.private[*].id

  auth {
    auth_scheme = "SECRETS"
    description = "aurora-credentials"
    iam_auth    = "DISABLED"
    secret_arn  = aws_secretsmanager_secret.db_credentials.arn
  }
}

resource "aws_db_proxy_default_target_group" "proxy_target_group" {
  db_proxy_name = aws_db_proxy.db_proxy.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    max_connections_percent      = 100
    max_idle_connections_percent = 50
  }
}

resource "aws_db_proxy_target" "proxy_target" {
  db_proxy_name         = aws_db_proxy.db_proxy.name
  target_group_name     = aws_db_proxy_default_target_group.proxy_target_group.name
  db_cluster_identifier = aws_rds_cluster.mysql_cluster.id
}

# Outputs
output "proxy_endpoint" {
  value = aws_db_proxy.db_proxy.endpoint
}

output "cluster_endpoint" {
  value = aws_rds_cluster.mysql_cluster.endpoint
}

