response:
To create a simple Amazon Lightsail setup, we need to define the provider, an instance, and potentially a static IP to ensure the address doesn't change on reboot. We will use a standard blueprint (such as Amazon Linux 2) and a bundle (the instance size).

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a Lightsail Instance
# Blueprint IDs can be found via AWS CLI: aws lightsail get-blueprints
# Bundle IDs (sizes) can be found via: aws lightsail get-bundles
resource "aws_lightsail_instance" "example_instance" {
  name              = "terraform-lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0" # This is usually the $3.50/mo tier

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# 2. Allocate a Static IP for the instance
resource "aws_lightsail_static_ip" "example_static_ip" {
  name = "terraform-static-ip"
}

# 3. Attach the Static IP to the Instance
resource "aws_lightsail_static_ip_attachment" "example_attachment" {
  static_ip_name = aws_lightsail_static_ip.example_static_ip.name
  instance_name  = aws_lightsail_instance.example_instance.name
}

# 4. Open Port 80 (HTTP) in the instance firewall
resource "aws_lightsail_instance_public_ports" "example_ports" {
  instance_name = aws_lightsail_instance.example_instance.name

  port_info {
    protocol  = "tcp"
    from_port = 80
    to_port   = 80
  }

  port_info {
    protocol  = "tcp"
    from_port = 22
    to_port   = 22
  }
}

# Output the Public IP address
output "public_ip" {
  value       = aws_lightsail_static_ip.example_static_ip.ip_address
  description = "The static public IP of the Lightsail instance"
}
```

