response:
To set up an Amazon Lightsail instance with a static IPv4 address, we need to define three primary resources:
1.  **`aws_lightsail_instance`**: This defines the virtual private server, specifying the blueprint (OS), bundle (hardware spec), and availability zone.
2.  **`aws_lightsail_static_ip`**: This allocates a dedicated static IPv4 address in the AWS cloud.
3.  **`aws_lightsail_static_ip_attachment`**: This links the static IP to the specific instance created.

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create a Lightsail Instance
resource "aws_lightsail_instance" "app_server" {
  name              = "my-web-server"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2" # Amazon Linux 2 OS
  bundle_id         = "nano_2_0"       # Minimum tier: 512MB RAM, 1 vCPU, 20GB SSD

  tags = {
    Environment = "Dev"
  }
}

# 2. Allocate a Static IP Address
resource "aws_lightsail_static_ip" "app_static_ip" {
  name = "app-static-ip"
}

# 3. Attach the Static IP to the Instance
resource "aws_lightsail_static_ip_attachment" "app_static_ip_attach" {
  static_ip_name = aws_lightsail_static_ip.app_static_ip.id
  instance_name  = aws_lightsail_instance.app_server.id
}

# Output the assigned IP
output "static_ip_address" {
  value       = aws_lightsail_static_ip.app_static_ip.ip_address
  description = "The static IP address assigned to the Lightsail instance"
}
