response:
To set up an Amazon Lightsail instance with a custom SSH key pair using Terraform, we need to define the `aws_lightsail_key_pair` resource first. This key pair is then associated with the `aws_lightsail_instance` during its creation.

The following configuration performs these steps:
1. Generates a local RSA private key.
2. Creates an AWS Lightsail key pair using the generated public key.
3. Provisions a Lightsail instance (using Amazon Linux 2023) and assigns the created key pair to it.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Generate a new Resource for the SSH Key Pair
# This creates a local private key to be used for the Lightsail Key Pair
resource "tls_private_key" "lightsail_key" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# 2. Create the Lightsail Key Pair in AWS
resource "aws_lightsail_key_pair" "custom_key_pair" {
  name       = "my-lightsail-ssh-key"
  public_key = tls_private_key.lightsail_key.public_key_openssh
}

# 3. Create the Lightsail Instance
resource "aws_lightsail_instance" "web_server" {
  name              = "terraform-lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2023" # ID for Amazon Linux 2023
  bundle_id         = "nano_3_0"           # The smallest instance plan
  key_pair_name     = aws_lightsail_key_pair.custom_key_pair.name

  tags = {
    Environment = "Dev"
    Project     = "LightSailDemo"
  }
}

# Output the private key (sensitive) to be used for SSH access
output "private_key_pem" {
  value     = tls_private_key.lightsail_key.private_key_pem
  sensitive = true
}

# Output the public IP of the instance
output "instance_public_ip" {
  value = aws_lightsail_instance.web_server.public_ip_address
}
```

