# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a Lightsail Static IP (Optional but recommended for DBs)
resource "aws_lightsail_static_ip" "db_static_ip" {
  name = "mysql-static-ip"
}

resource "aws_lightsail_static_ip_attachment" "db_attachment" {
  static_ip_name = aws_lightsail_static_ip.db_static_ip.name
  instance_name  = aws_lightsail_instance.mysql_db.name
}

# Create the Lightsail Instance
resource "aws_lightsail_instance" "mysql_db" {
  name              = "mysql-database-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "ubuntu_22_04" # Using Ubuntu OS
  bundle_id         = "micro_2_0"     # Instance size (change as needed)

  # User data script to install MySQL Server
  user_data = <<-EOF
              #!/bin/bash
              apt-get update -y
              export DEBIAN_FRONTEND=noninteractive
              apt-get install -y mysql-server

              # Start and Enable MySQL
              systemctl start mysql
              systemctl enable mysql

              # Basic Security: Allow remote connections (Optional)
              # Note: For production, keep bind-address to 127.0.0.1
              sed -i 's/127.0.0.1/0.0.0.0/' /etc/mysql/mysql.conf.d/mysqld.cnf
              systemctl restart mysql
              EOF

  tags = {
    Environment = "Development"
    Role        = "Database"
  }
}

# Define Firewall Rules to allow MySQL traffic (Port 3306)
resource "aws_lightsail_instance_public_ports" "mysql_firewall" {
  instance_name = aws_lightsail_instance.mysql_db.name

  port_info {
    protocol  = "tcp"
    from_port = 3306
    to_port   = 3306
    cidrs     = ["0.0.0.0/0"] # Restrict this to your IP in production!
  }

  port_info {
    protocol  = "tcp"
    from_port = 22
    to_port   = 22
  }
}

# Output the Public IP address
output "mysql_instance_public_ip" {
  value       = aws_lightsail_static_ip.db_static_ip.ip_address
  description = "The public IP address of the MySQL Lightsail instance"
}

