response:
To allow an AWS Lightsail instance to access an S3 bucket, we need to create the S3 bucket, an IAM user with a specific policy for that bucket, and generate access keys that can be injected into the Lightsail instance (typically via a `user_data` script). Unlike EC2, Lightsail does not support IAM Roles/Instance Profiles directly, so IAM User credentials are the standard approach.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket
resource "aws_s3_bucket" "lightsail_bucket" {
  bucket = "my-lightsail-data-storage-unique-id"
}

# 2. Create an IAM User for the Lightsail Instance
resource "aws_iam_user" "lightsail_user" {
  name = "lightsail-s3-accessor"
}

# 3. Create IAM Access Keys for the user
resource "aws_iam_access_key" "lightsail_key" {
  user = aws_iam_user.lightsail_user.name
}

# 4. Create a Policy allowing access to the specific bucket
resource "aws_iam_user_policy" "lightsail_s3_policy" {
  name = "LightsailS3AccessPolicy"
  user = aws_iam_user.lightsail_user.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.lightsail_bucket.arn,
          "${aws_s3_bucket.lightsail_bucket.arn}/*"
        ]
      }
    ]
  })
}

# 5. Create the Lightsail Instance
# The user_data script configures the AWS CLI with the IAM credentials
resource "aws_lightsail_instance" "app_server" {
  name              = "s3-enabled-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0"

  user_data = <<-EOF
    #!/bin/bash
    # Install AWS CLI
    yum update -y
    yum install aws-cli -y

    # Configure AWS CLI credentials for the root user
    mkdir -p /root/.aws
    cat <<EOT > /root/.aws/credentials
    [default]
    aws_access_key_id = ${aws_iam_access_key.lightsail_key.id}
    aws_secret_access_key = ${aws_iam_access_key.lightsail_key.secret}
    EOT

    cat <<EOT > /root/.aws/config
    [default]
    region = us-east-1
    EOT
  EOF

  tags = {
    Environment = "Dev"
  }
}

# Outputs for convenience
output "lightsail_ip" {
  value = aws_lightsail_instance.app_server.public_ip_address
}

output "s3_bucket_name" {
  value = aws_s3_bucket.lightsail_bucket.id
}
