To manage an AWS Lightsail Distribution with an S3 bucket origin, we need to create three main components: the Lightsail Bucket itself, the Lightsail Distribution, and the necessary permissions to allow the distribution to pull content from the bucket.

Note: Lightsail Distributions use a specific "Origin" configuration. When using a Lightsail bucket, the origin name must follow a specific naming convention defined by AWS.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1" # Lightsail Distribution configuration is often global/region specific
}

# 1. Create the Lightsail Bucket
resource "aws_lightsail_bucket" "static_assets" {
  name      = "my-static-assets-bucket"
  bundle_id = "small_1_0" # Choose appropriate bundle (small, medium, etc.)
}

# 2. Create the Lightsail Distribution
resource "aws_lightsail_distribution" "cdn" {
  name       = "my-lightsail-cdn"
  bundle_id  = "small_1_0" # Distribution bundle (defines transfer limits/cost)
  is_enabled = true

  # Define the Origin (The S3 Bucket)
  origin {
    name        = "my-bucket-origin"
    region_name = aws_lightsail_bucket.static_assets.region
    bucket_name = aws_lightsail_bucket.static_assets.name
  }

  # Default Cache Behavior
  default_cache_behavior {
    behavior = "cache"
  }

  # Optional: Cache Behavior Overrides
  cache_behavior {
    path_pattern = "images/*.jpg"
    behavior     = "cache"
  }

  # Set the cache settings
  cache_settings {
    default_ttl = 86400
    maximum_ttl = 31536000
    minimum_ttl = 0

    forwarded_headers {
      option = "none"
    }

    forwarded_cookies {
      option = "none"
    }

    forwarded_query_strings {
      option = "false"
    }
  }
}

# 3. Grant the Distribution access to the Bucket
# This resource attaches the distribution to the bucket to allow private access
resource "aws_lightsail_bucket_resource_access" "dist_access" {
  bucket_name   = aws_lightsail_bucket.static_assets.name
  resource_name = aws_lightsail_distribution.cdn.name
}

# Outputs
output "distribution_url" {
  value       = aws_lightsail_distribution.cdn.domain_name
  description = "The public URL of the Lightsail Distribution"
}

output "bucket_url" {
  value       = aws_lightsail_bucket.static_assets.url
  description = "The direct URL of the Lightsail Bucket"
}
```

