# 3. Create the Lightsail Distribution
resource "aws_lightsail_distribution" "cdn" {
  name      = "main-distribution"
  bundle_id = "small_1_0" # Data transfer quota bundle (e.g., 50 GB)

  # Define the origin (the Lightsail Instance created above)
  origin {
    name             = "origin-config"
    region_name      = aws_lightsail_instance.origin_server.availability_zone
    instance_name    = aws_lightsail_instance.origin_server.name
    protocol_policy  = "http-only" # Change to "https-only" if instance has SSL
  }

  # Default cache behavior
  default_cache_behavior {
    behavior = "cache"
  }

  # Optional: Specific cache behavior for static assets
  cache_behavior {
    path_pattern = "static/*"
    behavior     = "cache"
  }

  # Enable the distribution
  is_enabled = true

  tags = {
    Project = "Lightsail-CDN"
  }
}

# Outputs
output "instance_public_ip" {
  value = aws_lightsail_static_ip.origin_static_ip.ip_address
}

output "distribution_domain_name" {
  value = aws_lightsail_distribution.cdn.domain_name
}

