response:
To administer an AWS Lightsail Distribution with an instance origin, we need to define three primary resources:
1.  **aws_lightsail_instance**: The origin server (e.g., a web server).
2.  **aws_lightsail_static_ip**: To ensure the instance has a persistent IP address that the distribution can reliably point to.
3.  **aws_lightsail_distribution**: The Content Delivery Network (CDN) layer that caches content and provides an SSL/TLS endpoint.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a Lightsail Instance to act as the origin
resource "aws_lightsail_instance" "origin_server" {
  name              = "web-origin-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"
  bundle_id         = "nano_2_0" # Lowest tier for cost efficiency

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Hello from Lightsail Origin</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Environment = "Production"
  }
}

# 2. Assign a Static IP to the instance so the distribution origin remains constant
resource "aws_lightsail_static_ip" "origin_static_ip" {
  name = "static-ip-for-cdn"
}

resource "aws_lightsail_static_ip_attachment" "origin_attachment" {
  static_ip_name = aws_lightsail_static_ip.origin_static_ip.name
  instance_name  = aws_lightsail_instance.origin_server.name
}

# 3. Create the Lightsail Distribution
resource "aws_lightsail_distribution" "cdn" {
  name      = "main-distribution"
  bundle_id = "small_1_0" # Data transfer quota bundle (e.g., 50 GB)

  # Define the origin (the Lightsail Instance created above)
  origin {
    name             = "origin-config"
    region_name      = aws_lightsail_instance.origin_server.availability_zone
    instance_name    = aws_lightsail_instance.origin_server.name
    protocol_policy  = "http-only" # Change to "https-only" if instance has SSL
  }

  # Default cache behavior
  default_cache_behavior {
    behavior = "cache"
  }

  # Optional: Specific cache behavior for static assets
  cache_behavior {
    path_pattern = "static/*"
    behavior     = "cache"
  }

  # Enable the distribution
  is_enabled = true

  tags = {
    Project = "Lightsail-CDN"
  }
}

# Outputs
output "instance_public_ip" {
  value = aws_lightsail_static_ip.origin_static_ip.ip_address
}

output "distribution_domain_name" {
  value = aws_lightsail_distribution.cdn.domain_name
}
```

