To create an Amazon S3 Glacier Vault, we need to define the AWS provider and the `aws_glacier_vault` resource. Optionally, we can include an access policy to manage permissions and a notification block to alert an SNS topic when archiving jobs are complete.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create an SNS topic for Glacier notifications (Optional but recommended)
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-updates"
}

# Create the Amazon S3 Glacier Vault
resource "aws_glacier_vault" "my_archive_vault" {
  name = "my-long-term-storage-vault"

  # Optional: Configure notifications for archive events
  notification {
    events   = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
    sns_topic = aws_sns_topic.glacier_notifications.arn
  }

  tags = {
    Environment = "Production"
    Purpose     = "LongTermComplianceStorage"
    ManagedBy   = "Terraform"
  }
}

# Optional: Vault Lock Policy (Example: Deny deletion of archives)
# Note: Once a vault lock is "Locked", it cannot be changed. 
# This resource represents the policy logic before or during the locking process.
resource "aws_glacier_vault_lock" "example" {
  vault_name    = aws_glacier_vault.my_archive_vault.name
  complete_lock = false # Set to true only when ready to permanently enforce compliance
  policy        = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "ReadOnlyAccess",
      "Effect": "Allow",
      "Principal": "*",
      "Action": "glacier:Get*",
      "Resource": "${aws_glacier_vault.my_archive_vault.arn}"
    }
  ]
}
EOF
}

# Output the Vault ARN and URI
output "vault_arn" {
  value       = aws_glacier_vault.my_archive_vault.arn
  description = "The ARN of the Glacier Vault"
}

output "vault_location" {
  value       = aws_glacier_vault.my_archive_vault.location
  description = "The URI of the Glacier Vault"
}
```

