# Terraform configuration for AWS Long-term Data Retention & Backup Storage

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. KMS Key for Server-Side Encryption
resource "aws_kms_key" "backup_kms_key" {
  description             = "KMS key for encrypting long-term backup data"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

# 2. S3 Bucket for Backups
resource "aws_s3_bucket" "backup_storage" {
  bucket = "company-long-term-backups-${data.aws_caller_identity.current.account_id}"

  # Prevents accidental deletion of the bucket
  lifecycle {
    prevent_destroy = true
  }
}

# 3. Enable Versioning (Crucial for backup recovery)
resource "aws_s3_bucket_versioning" "backup_versioning" {
  bucket = aws_s3_bucket.backup_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

# 4. Enable Default Encryption using KMS
resource "aws_s3_bucket_server_side_encryption_configuration" "backup_encryption" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.backup_kms_key.arn
      sse_algorithm     = "aws:kms"
    }
  }
}

# 5. Public Access Block (Security best practice)
resource "aws_s3_bucket_public_access_block" "backup_access_block" {
  bucket = aws_s3_bucket.backup_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# 6. Lifecycle Rules for Long-term retention
# Transitions data to Glacier after 30 days and Deep Archive after 90 days.
# Deletes non-current versions after 7 years (2555 days).
resource "aws_s3_bucket_lifecycle_configuration" "backup_lifecycle" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    id     = "archive-and-retention-policy"
    status = "Enabled"

    # Transition current versions
    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    transition {
      days          = 90
      storage_class = "DEEP_ARCHIVE"
    }

    # Clean up old versions of files
    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "GLACIER"
    }

    noncurrent_version_expiration {
      noncurrent_days = 2555 # 7 years retention
    }

    # Clean up failed multi-part uploads to save costs
    abort_incomplete_multipart_upload {
      days_after_initiation = 7
    }
  }
}

# 7. S3 Object Lock (Optional compliance - makes data immutable)
resource "aws_s3_bucket_object_lock_configuration" "backup_lock" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    default_retention {
      mode = "COMPLIANCE"
      days = 365
    }
  }
}

# Data source for account ID to ensure unique bucket naming
data "aws_caller_identity" "current" {}

output "backup_bucket_name" {
  value       = aws_s3_bucket.backup_storage.id
  description = "The name of the S3 bucket created for backups."
}

output "kms_key_arn" {
  value       = aws_kms_key.backup_kms_key.arn
  description = "The ARN of the KMS key used for encryption."
}

reference:
