# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the Amazon S3 Glacier Vault
resource "aws_glacier_vault" "archive_vault" {
  name = "company-data-archive"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Environment = "Production"
    Service     = "DataArchiving"
  }
}

# 2. Create an SNS Topic for Glacier Notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-updates"
}

# 3. Create IAM Role for Data Lifecycle Manager (DLM)
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

# 4. Attach Policy to DLM Role to allow management of snapshots and lifecycle actions
resource "aws_iam_role_policy" "dlm_lifecycle_policy" {
  name = "dlm-lifecycle-policy"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:CreateSnapshots",
          "ec2:DeleteSnapshot",
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots",
          "ec2:CreateTags",
          "glacier:UploadArchive",
          "glacier:DeleteArchive",
          "glacier:DescribeVault"
        ]
        Resource = "*"
      }
    ]
  })
}

# 5. Define a DLM Lifecycle Policy 
# Note: This example shows a standard snapshot policy which is the primary use for DLM.
# For direct S3-to-Glacier transitions, S3 Lifecycle Rules are typically used.
resource "aws_dlm_lifecycle_policy" "example_lifecycle" {
  description        = "Daily snapshots for volumes tagged for Glacier archival"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "DailySnapshots"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["23:45"]
      }

      retain_rule {
        count = 7
      }

      copy_tags = true
    }

    target_tags = {
      SnapshotToArchive = "true"
    }
  }
}

# 6. Glacier Vault Lock (Optional: Enforce compliance)
resource "aws_glacier_vault_lock" "vault_compliance" {
  vault_name = aws_glacier_vault.archive_vault.name

  # Policy that prevents deletion of archives for 365 days
  complete_lock = false
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "RestrictDeletionToYearly"
        Effect = "Deny"
        Principal = "*"
        Action   = "glacier:DeleteArchive"
        Resource = aws_glacier_vault.archive_vault.arn
        Condition = {
          NumericLessThan = {
            "glacier:ArchiveAgeInDays" = "365"
          }
        }
      }
    ]
  })
}

