  name = "company-data-archive"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Environment = "Production"
    Service     = "DataArchiving"
  }
}

# 2. Create an SNS Topic for Glacier Notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-updates"
}

# 3. Create IAM Role for Data Lifecycle Manager (DLM)
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

# 4. Attach Policy to DLM Role to allow management of snapshots and lifecycle actions
resource "aws_iam_role_policy" "dlm_lifecycle_policy" {
