}

# 5. Define a DLM Lifecycle Policy 
# Note: This example shows a standard snapshot policy which is the primary use for DLM.
# For direct S3-to-Glacier transitions, S3 Lifecycle Rules are typically used.
resource "aws_dlm_lifecycle_policy" "example_lifecycle" {
  description        = "Daily snapshots for volumes tagged for Glacier archival"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
