            "aws:SourceArn" = "arn:aws:glacier:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:vaults/my-archive-vault"
          }
        }
      }
    ]
  })
}

# Data sources to get Account ID and Region for the policy
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# 3. Create the S3 Glacier Vault
resource "aws_glacier_vault" "my_archive_vault" {
  name = "my-archive-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Environment = "Production"
    Service     = "Glacier"
  }

  # Ensure policy is in place before vault tries to send notifications
