To create an Amazon S3 Glacier vault with an access policy using Terraform, we need to define the `aws_glacier_vault` resource and then apply an `aws_glacier_vault_lock` or a `aws_glacier_vault_policy`. For standard access control, the `aws_glacier_vault_policy` resource is used to attach a JSON policy document that defines who can interact with the vault.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a Glacier Vault
resource "aws_glacier_vault" "my_archive_vault" {
  name = "my-secure-glacier-vault"

  tags = {
    Environment = "Production"
    Department  = "Compliance"
  }

  # Notification configuration (Optional)
  # notification {
  #   sns_topic = "arn:aws:sns:us-east-1:123456789012:mytopic"
  #   events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  # }
}

# Define the Access Policy in IAM Policy Document format
data "aws_iam_policy_document" "vault_access_policy" {
  statement {
    sid    = "AllowSpecificUserFullAccess"
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = ["*"] # In production, replace "*" with a specific IAM ARN
    }

    actions = [
      "glacier:DescribeVault",
      "glacier:GetDataRetrievalPolicy",
      "glacier:GetVaultNotifications",
      "glacier:ListJobs",
      "glacier:ListMultipartUploads",
      "glacier:ListTagsForVault"
    ]

    resources = [
      aws_glacier_vault.my_archive_vault.arn
    ]
  }
}

# Apply the Access Policy to the Glacier Vault
resource "aws_glacier_vault_policy" "vault_access" {
  vault_name = aws_glacier_vault.my_archive_vault.name
  policy     = data.aws_iam_policy_document.vault_access_policy.json
}

# Output the Vault ARN
output "vault_arn" {
  value       = aws_glacier_vault.my_archive_vault.arn
  description = "The Amazon Resource Name of the Glacier Vault"
}
```

