response:
To create an Amazon S3 Glacier vault with a Vault Lock policy, we will use the `aws_glacier_vault` resource to define the storage container and the `aws_glacier_vault_lock` resource to apply a compliance lock. The Vault Lock process involves two steps in Terraform: defining the policy and setting `complete_lock = true`. Note that once a lock is completed and the 24-hour testing period passes, it becomes immutable.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create the S3 Glacier Vault
resource "aws_glacier_vault" "my_archive_vault" {
  name = "my-secure-compliance-vault"

  tags = {
    Environment = "Production"
    Purpose     = "Data Retention"
  }
}

# Define the Vault Lock Policy (JSON)
data "aws_iam_policy_document" "vault_lock_policy" {
  statement {
    sid    = "DenyDeleteUntilRetained"
    effect = "Deny"
    principals {
      type        = "AWS"
      identifiers = ["*"]
    }
    actions = [
      "glacier:DeleteArchive",
      "glacier:DeleteVault"
    ]
    resources = [
      aws_glacier_vault.my_archive_vault.arn
    ]
    condition {
      test     = "NumericLessThanSatisfyAny"
      variable = "glacier:ArchiveAgeInDays"
      values   = ["365"]
    }
  }
}

# Apply the Vault Lock
# Set complete_lock to true to finalize the lock. 
# Once finalized, the policy cannot be changed or deleted.
resource "aws_glacier_vault_lock" "my_vault_lock" {
  vault_name    = aws_glacier_vault.my_archive_vault.name
  complete_lock = true
  policy        = data.aws_iam_policy_document.vault_lock_policy.json

  # Optional: ignore_deletion_error is useful during dev/test if you need to tear down 
  # infrastructure, as locked vaults cannot be deleted normally.
  # ignore_deletion_error = true
}

# Outputs
output "vault_arn" {
  value       = aws_glacier_vault.my_archive_vault.arn
  description = "The ARN of the Glacier Vault"
}

output "vault_lock_id" {
  value       = aws_glacier_vault_lock.my_vault_lock.id
  description = "The ID of the Vault Lock"
}
```

