# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Glacier Vault
resource "aws_glacier_vault" "archive_vault" {
  name = "my-secure-archive-vault"

  tags = {
    Environment = "Production"
    Purpose     = "Compliance-Storage"
  }
}

# 2. Define the Access Policy via data source
# This policy allows root account full access but can be customized to 
# restrict permissions as required by compliance.
data "aws_iam_policy_document" "vault_access_policy" {
  statement {
    sid    = "DefineVaultAccess"
    effect = "Allow"

    principals {
      type        = "AWS"
      identifiers = ["*"] # Adjust this to specific IAM ARNs for production
    }

    actions   = ["glacier:DescribeVault", "glacier:GetDataRetrievalPolicy"]
    resources = [aws_glacier_vault.archive_vault.arn]
  }
}

# 3. Enforce the Policy with aws_glacier_vault_lock
# The lock can be "complete" or "not complete". 
# complete_lock = true makes the policy irreversible after the locking process.
resource "aws_glacier_vault_lock" "vault_compliance_lock" {
  vault_name    = aws_glacier_vault.archive_vault.name
  policy        = data.aws_iam_policy_document.vault_access_policy.json
  complete_lock = false # Set to true only when you are certain, as it cannot be changed easily.

  # This ignore_changes block is often recommended for vault locks to prevent 
  # Terraform from trying to overwrite the lock state once it is in place.
  lifecycle {
    ignore_changes = [complete_lock]
  }
}

# Output the Vault ARN
output "glacier_vault_arn" {
  value       = aws_glacier_vault.archive_vault.arn
  description = "The ARN of the Glacier Vault"
}

