# 2. Create an SNS Topic Policy to allow Glacier to publish to this topic
resource "aws_sns_topic_policy" "default" {
  arn = aws_sns_topic.glacier_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowGlacierToPublish"
        Effect = "Allow"
        Principal = {
          Service = "glacier.amazonaws.com"
        }
        Action   = "sns:Publish"
        Resource = aws_sns_topic.glacier_notifications.arn
        Condition = {
          ArnLike = {
            "aws:SourceArn" = "arn:aws:glacier:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:vaults/*"
          }
        }
      }
    ]
  })
}

# Data sources to get Account ID and Region for the policy
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# 3. Create the S3 Glacier Vault with the notification configuration
resource "aws_glacier_vault" "my_archive_vault" {
  name = "my-secure-glacier-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Environment = "Production"
    ManagedBy   = "Terraform"
  }
}

# Output the Vault ARN and SNS Topic ARN
output "vault_arn" {
  value       = aws_glacier_vault.my_archive_vault.arn
  description = "The ARN of the Glacier Vault"
}

output "sns_topic_arn" {
  value       = aws_sns_topic.glacier_notifications.arn
  description = "The ARN of the SNS topic receiving notifications"
}

