response:
To provision a Network Load Balancer (NLB) linked to a `t2.micro` EC2 instance, we need to define the provider, a VPC with public subnets, a Security Group (though NLBs don't strictly require them for transit, the instance does), the EC2 instance, a Target Group, the Load Balancer itself, and a Listener.

The following configuration sets up this infrastructure in the `us-east-1` region.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "terraform-nlb-vpc"
  }
}

# 2. Create a Public Subnet
resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "nlb-subnet"
  }
}

# 3. Internet Gateway for connectivity
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "rt" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.rt.id
}

# 4. Security Group for the EC2 Instance (Allowing TCP 80)
resource "aws_security_group" "instance_sg" {
  name        = "instance-sg"
  description = "Allow inbound traffic from NLB"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 5. Provision the t2.micro EC2 Instance
resource "aws_instance" "web_server" {
  ami                    = "ami-0c101f26f147fa7fd" # Amazon Linux 2023 AMI (us-east-1)
  instance_type          = "t2.micro"
  subnet_id              = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.instance_sg.id]

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              echo "<h1>Hello from Terraform NLB Server</h1>" > /var/www/html/index.html
              EOF

  tags = {
    Name = "nlb-target-instance"
  }
}

# 6. Create the Network Load Balancer (NLB)
resource "aws_lb" "nlb" {
  name               = "terraform-nlb"
  internal           = false
  load_balancer_type = "network"
  subnets            = [aws_subnet.public.id]

  enable_deletion_protection = false
}

# 7. Create the NLB Target Group
resource "aws_lb_target_group" "tg" {
  name     = "nlb-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id

  health_check {
    protocol = "TCP"
    port     = "80"
  }
}

# 8. Register the EC2 instance with the Target Group
resource "aws_lb_target_group_attachment" "tg_attachment" {
  target_group_arn = aws_lb_target_group.tg.arn
  target_id        = aws_instance.web_server.id
  port             = 80
}

# 9. Create the NLB Listener
resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

# Output the DNS name of the Load Balancer
output "nlb_dns_name" {
  value       = aws_lb.nlb.dns_name
  description = "The DNS name of the Network Load Balancer"
}
```

