provider "aws" {
  region = "us-east-1"
}

# 1. Create a Security Group for the Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "test-lb-sg"
  description = "Allow HTTP inbound traffic"

  ingress {
    description      = "HTTP from anywhere"
    from_port        = 80
    to_port          = 80
    protocol         = "tcp"
    cidr_blocks      = ["0.0.0.0/0"]
  }

  egress {
    from_port        = 0
    to_port          = 0
    protocol         = "-1"
    cidr_blocks      = ["0.0.0.0/0"]
  }

  tags = {
    Name = "test-lb-sg"
  }
}

# 2. Reference existing subnets or define new ones 
# (Using data sources for existing infrastructure or defining resources for a complete demo)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "public" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# 3. Create the Application Load Balancer
resource "aws_lb" "test_lb" {
  name               = "test-lb-tf"
  internal           = false # Set to false for External/Internet-facing
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = data.aws_subnets.public.ids

  # Requirement: Turn on deletion protection
  enable_deletion_protection = true

  tags = {
    Environment = "test"
    ManagedBy   = "Terraform"
  }
}

# 4. Optional: Add a listener to make the LB functional
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.test_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type = "fixed-response"

    fixed_response {
      content_type = "text/plain"
      message_body = "Fixed response content"
      status_code  = "200"
    }
  }
}

# Outputs
output "lb_dns_name" {
