response:
To create an AWS Application Load Balancer (ALB) that uses specific Elastic IP addresses (EIPs), the ALB must be **Internal-facing is not an option**; it must be **Network Load Balancer (NLB)**. Standard Application Load Balancers (ALBs) do not support assigned Static IPs directly; they use DNS. NLBs, however, allow you to map one Elastic IP per subnet.

Here is the complete Terraform configuration to provision two Elastic IPs and attach them to a public Network Load Balancer.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

# 2. Create Public Subnets in different AZs
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 3. Allocate two Elastic IPs
resource "aws_eip" "lb_eip_a" {
  domain = "vpc"
  tags = {
    Name = "nlb-eip-1a"
  }
}

resource "aws_eip" "lb_eip_b" {
  domain = "vpc"
  tags = {
    Name = "nlb-eip-1b"
  }
}

# 4. Create the Network Load Balancer with Static IPs
# Note: At least one subnet mapping is required. 
# For internet-facing NLBs using EIPs, use 'allocation_id'.
resource "aws_lb" "static_lb" {
  name               = "static-ip-lb"
  load_balancer_type = "network"
  internal           = false

  subnet_mapping {
    subnet_id     = aws_subnet.subnet_a.id
    allocation_id = aws_eip.lb_eip_a.id
  }

  subnet_mapping {
    subnet_id     = aws_subnet.subnet_b.id
    allocation_id = aws_eip.lb_eip_b.id
  }

  tags = {
    Environment = "production"
  }
}

# 5. Define a Target Group
resource "aws_lb_target_group" "tg" {
  name     = "nbl-target-group"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id
}

# 6. Define a Listener
resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.static_lb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

# Outputs to verify the IPs
output "load_balancer_dns" {
  value = aws_lb.static_lb.dns_name
}

output "fixed_ips" {
  value = [aws_eip.lb_eip_a.public_ip, aws_eip.lb_eip_b.public_ip]
}
```

