To create an internal load balancer with specific private IP addresses, we will use AWS as the provider. The configuration involves setting up a VPC, subnets, and an Application Load Balancer (ALB) with the `internal` flag set to `true`. To assign specific private IPs, we use the `subnet_mapping` block instead of the standard `subnets` list.

Step-by-step logic:
1. Define the AWS provider and VPC.
2. Create two private subnets in different Availability Zones (required for ALB).
3. Create a Security Group to allow internal traffic.
4. Create the `aws_lb` resource with `load_balancer_type = "application"` and `internal = true`.
5. Use `subnet_mapping` to map each subnet ID to a specific `private_ipv4_address`.

```hcl
# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Network Infrastructure
resource "aws_vpc" "internal_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "internal-service-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.internal_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.internal_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Security Group for the Internal Load Balancer
resource "aws_security_group" "lb_sg" {
  name        = "internal-lb-sg"
  description = "Allow internal traffic"
  vpc_id      = aws_vpc.internal_vpc.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Internal Application Load Balancer with Specific Private IPs
resource "aws_lb" "internal_alb" {
  name               = "specific-ip-internal-alb"
  internal           = true
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]

  # Assigning specific private IP addresses per subnet
  subnet_mapping {
    subnet_id            = aws_subnet.subnet_a.id
    private_ipv4_address = "10.0.1.50"
  }

  subnet_mapping {
    subnet_id            = aws_subnet.subnet_b.id
    private_ipv4_address = "10.0.2.50"
  }

  tags = {
    Environment = "production"
    Type        = "internal"
  }
}

# Target Group for the Load Balancer
resource "aws_lb_target_group" "internal_tg" {
  name     = "internal-app-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.internal_vpc.id
}

# Listener for the Load Balancer
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.internal_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.internal_tg.arn
  }
}

# Output the DNS name (though IPs are fixed, DNS is the standard access method)
output "lb_dns_name" {
  value = aws_lb.internal_alb.dns_name
}
