To implement a configuration where an Application Load Balancer (ALB) routes traffic to a Network Load Balancer (NLB), we use the ALB's ability to target an IP address. Since the NLB provides static IP addresses (one per subnet), we register these IPs as targets for the ALB.

This pattern is often used to handle specific protocol requirements or to integrate legacy systems with modern web routing.

```hcl
# Configure AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. VPC and Networking
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "public_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 2. Security Groups
resource "aws_security_group" "alb_sg" {
  name   = "alb-sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Network Load Balancer (The Backend LB)
resource "aws_lb" "nlb" {
  name               = "backend-nlb"
  internal           = true
  load_balancer_type = "network"
  subnets            = [aws_subnet.public_a.id, aws_subnet.public_b.id]
}

resource "aws_lb_target_group" "nlb_target_group" {
  name     = "nlb-targets"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id
  # This targets actual EC2 instances or IP addresses behind the NLB
  target_type = "instance"
}

resource "aws_lb_listener" "nlb_listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.nlb_target_group.arn
  }
}

# 4. Application Load Balancer (The Frontend LB)
resource "aws_lb" "alb" {
  name               = "frontend-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = [aws_subnet.public_a.id, aws_subnet.public_b.id]
}

# Target Group for ALB that points to NLB IP addresses
resource "aws_lb_target_group" "alb_to_nlb_tg" {
  name        = "alb-to-nlb-tg"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip" # ALB must target the NLB by IP
}

# 5. Data lookup to get NLB ENI IPs (Advanced) or manual static assignment
# In a real-world scenario, you would use a Lambda or PrivateLink.
# For this example, we associate the ALB to the NLB's interface IPs.
data "aws_network_interface" "nlb_interface" {
  for_each = toset([aws_subnet.public_a.id, aws_subnet.public_b.id])

  filter {
    name   = "description"
    values = ["ELB ${aws_lb.nlb.arn_suffix}"]
  }

  filter {
    name   = "subnet-id"
    values = [each.value]
  }
}

resource "aws_lb_target_group_attachment" "alb_to_nlb" {
  for_each         = data.aws_network_interface.nlb_interface
  target_group_arn = aws_lb_target_group.alb_to_nlb_tg.arn
  target_id        = each.value.private_ip
  port             = 80
}

# ALB Listener
resource "aws_lb_listener" "alb_listener" {
  load_balancer_arn = aws_lb.alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.alb_to_nlb_tg.arn
  }
}

# Outputs
output "alb_dns" {
  value = aws_lb.alb.dns_name
}

output "nlb_dns" {
  value = aws_lb.nlb.dns_name
}
