# Terraform configuration for AWS ALB with OIDC Authentication

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure (VPC, Subnets, Security Groups)
resource "aws_vpc" "main" {
  cipher_block = "10.0.0.0/16"
}

resource "aws_subnet" "public" {
  count             = 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = "us-east-1a" # In production, use multiple AZs
}

resource "aws_security_group" "alb_sg" {
  name   = "alb-oidc-sg"
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 2. Application Load Balancer
resource "aws_lb" "oidc_lb" {
  name               = "auth-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = aws_subnet.public[*].id
}

# 3. Target Group (The backend application)
resource "aws_lb_target_group" "app_tg" {
  name     = "app-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id
}

# 4. HTTPS Listener with OIDC Authentication Action
# Note: SSL Certificate is required for HTTPS/OIDC
resource "aws_lb_listener" "https_listener" {
  load_balancer_arn = aws_lb.oidc_lb.arn
  port              = "443"
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = "arn:aws:acm:us-east-1:123456789012:certificate/uuid" # Replace with valid ACM Cert ARN

  default_action {
    type = "authenticate-oidc"

    authenticate_oidc {
      authorization_endpoint     = "https://example.okta.com/oauth2/v1/authorize"
      client_id                  = "0oa123456789"
      client_secret              = "your_client_secret_stored_in_secrets_manager"
      issuer                     = "https://example.okta.com"
      token_endpoint             = "https://example.okta.com/oauth2/v1/token"
      user_info_endpoint         = "https://example.okta.com/oauth2/v1/userinfo"

      # Sessions settings
      session_cookie_name        = "AWSELBAuthSessionCookie"
      session_timeout            = 3600
      on_unauthenticated_request = "authenticate" # or "deny" or "allow"
    }
  }

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app_tg.arn
  }
}

# 5. Optional: Specific rule for a path requiring OIDC (if default is different)
resource "aws_lb_listener_rule" "oidc_rule" {
  listener_arn = aws_lb_listener.https_listener.arn
  priority     = 10

  action {
    type = "authenticate-oidc"
    authenticate_oidc {
      authorization_endpoint = "https://example.auth0.com/authorize"
      client_id              = "CLIENT_ID"
      client_secret          = "CLIENT_SECRET"
      issuer                 = "https://example.auth0.com/"
      token_endpoint         = "https://example.auth0.com/oauth/token"
      user_info_endpoint     = "https://example.auth0.com/userinfo"
    }
  }

  action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.app_tg.arn
  }

  condition {
    path_pattern {
      values = ["/secure/*"]
    }
  }
}

