  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.gwlb_tg.arn
  }
}

# 6. Create a Gateway Load Balancer Endpoint Service 
# (This allows VPC Endpoint interfaces in other VPCs to connect to this GWLB)
resource "aws_vpc_endpoint_service" "gwlb_service" {
