response:
To create a standard Application Load Balancer (ALB) with an associated Target Group on AWS, we need to define the following resources:
1.  **VPC & Subnets**: A network environment to host the load balancer (assumed existing or using default for this example).
2.  **Security Group**: To allow incoming traffic (HTTP on port 80).
3.  **Application Load Balancer**: The external-facing entry point.
4.  **Target Group**: To define where traffic should be routed (e.g., EC2 instances).
5.  **Listener**: To connect the Load Balancer to the Target Group by listening for specific traffic.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Data source to fetch default VPC and Subnets (standard for quick setups)
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# 1. Create a Security Group for the Load Balancer
resource "aws_security_group" "alb_sg" {
  name        = "allow_http_alb"
  description = "Allow HTTP inbound traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "HTTP from everywhere"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-security-group"
  }
}

# 2. Create the Application Load Balancer
resource "aws_lb" "main_alb" {
  name               = "main-app-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = data.aws_subnets.default.ids

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

# 3. Create the Target Group
resource "aws_lb_target_group" "main_tg" {
  name     = "app-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = data.aws_vpc.default.id

  health_check {
    enabled             = true
    interval            = 30
    path                = "/"
    port                = "traffic-port"
    healthy_threshold   = 3
    unhealthy_threshold = 3
    timeout             = 5
    protocol            = "HTTP"
    matcher             = "200"
  }
}

# 4. Create the Listener to route traffic from LB to Target Group
resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.main_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main_tg.arn
  }
}

# Output the DNS name of the ALB
output "alb_dns_name" {
  value       = aws_lb.main_alb.dns_name
  description = "The domain name of the load balancer"
}
```

