response:
To create a functional Application Load Balancer (ALB) setup on AWS, we need to define several interconnected resources:
1.  **VPC & Subnets**: A base network where the LB will reside (using default for this example).
2.  **Security Group**: To allow inbound HTTP traffic (Port 80).
3.  **Application Load Balancer**: The external-facing entry point.
4.  **Target Group**: The logical grouping of backend instances/containers.
5.  **Listener**: The rule that connects the Load Balancer to the Target Group by listening for incoming traffic.

```hcl
# Shared Provider Configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Fetch Default VPC and Subnets
data "aws_vpc" "default" {
  default = true
}

data "aws_subnets" "default" {
  filter {
    name   = "vpc-id"
    values = [data.aws_vpc.default.id]
  }
}

# 2. Security Group for the Load Balancer
resource "aws_security_group" "alb_sg" {
  name        = "terraform-alb-sg"
  description = "Allow HTTP inbound traffic"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Application Load Balancer
resource "aws_lb" "main" {
  name               = "main-load-balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = data.aws_subnets.default.ids

  tags = {
    Environment = "production"
  }
}

# 4. Target Group
resource "aws_lb_target_group" "main_tg" {
  name        = "main-target-group"
  port        = 80
  protocol    = "HTTP"
  vpc_id      = data.aws_vpc.default.id
  target_type = "instance"

  health_check {
    enabled             = true
    interval            = 30
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    timeout             = 5
    healthy_threshold   = 3
    unhealthy_threshold = 3
  }
}

# 5. Listener (Associates LB with Target Group)
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main_tg.arn
  }
}

# Output the DNS name of the Load Balancer
output "lb_dns_name" {
  value       = aws_lb.main.dns_name
  description = "The domain name of the load balancer"
}
```

