To set up a simple SQL database on AWS using Terraform, we need to define the provider, a Virtual Private Cloud (VPC) with public and private subnets, a security group to allow database traffic, and finally the RDS instance itself. For this example, we will use MySQL.

Thinking process:
1.  **Provider Selection**: Configure the AWS provider and region.
2.  **Network Setup**: Create a VPC and DB Subnet Group. RDS instances require a subnet group covering at least two availability zones for high availability readiness.
3.  **Security**: Create a Security Group to allow traffic on port 3306.
4.  **Database Instance**: Define the `aws_db_instance` resource with basic parameters (engine, instance class, storage, credentials).

```hcl
# AWS Provider configuration
provider "aws" {
  region = "us-east-1"
}

# 1. Create a VPC for the database
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "sql-database-vpc"
  }
}

# 2. Create subnets in different Availability Zones (Required for RDS Subnet Group)
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 3. Create the DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "sql-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "My DB subnet group"
  }
}

# 4. Create a Security Group to allow MySQL traffic
resource "aws_security_group" "rds_sg" {
  name        = "allow_mysql"
  description = "Allow MySQL inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    description      = "MySQL from VPC"
    from_port        = 3306
    to_port          = 3306
    protocol         = "tcp"
    cidr_blocks      = ["0.0.0.0/0"] # Note: In production, limit this to your app's IP
  }

  egress {
    from_port        = 0
    to_port          = 0
    protocol         = "-1"
    cidr_blocks      = ["0.0.0.0/0"]
  }
}

# 5. Create the RDS MySQL Instance
resource "aws_db_instance" "mysql_db" {
  allocated_storage    = 20
  db_name              = "mydb"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro" # Free tier eligible
