# Terraform configuration for AWS PostgreSQL RDS Instance (db.t4g.large)

provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "postgresql-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 2. DB Subnet Group (Required for RDS)
resource "aws_db_subnet_group" "default" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Postgres DB subnet group"
  }
}

# 3. Security Group
resource "aws_security_group" "rds_sg" {
  name        = "allow_postgresql"
  description = "Allow inbound traffic on port 5432"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. PostgreSQL RDS Instance
resource "aws_db_instance" "postgres" {
  allocated_storage      = 20
  max_allocated_storage  = 100
  db_name                = "mydb"
  engine                 = "postgres"
  engine_version         = "15.4" # Or latest supported
  instance_class         = "db.t4g.large" # Graviton instance
  username               = "dbadmin"
  password               = "ChangeMe123!" # Use a secret manager in production
  parameter_group_name   = "default.postgres15"
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot    = true
  publicly_accessible    = false

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

output "db_endpoint" {
  value = aws_db_instance.postgres.endpoint
}

response:
To set up an AWS PostgreSQL instance using the `db.t4g.large` class, we need to define the network infrastructure (VPC, Subnets, and Security Groups) and the RDS instance itself.

Step-by-step logic:
1. **Provider Configuration**: Set up the AWS provider and region.
2. **Network Setup**: Create a VPC and two private subnets in different Availability Zones (required for RDS Subnet Groups).
3. **Security Group**: Open port 5432 for PostgreSQL access.
4. **DB Subnet Group**: Group the subnets to tell RDS where it can be deployed.
5. **RDS Instance**: Define the engine (Postgres), version, instance class (`db.t4g.large`), storage, and credentials.

```hcl
# Terraform configuration for AWS PostgreSQL RDS Instance (db.t4g.large)

provider "aws" {
  region = "us-east-1"
}

# 1. Network Infrastructure
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "postgresql-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# 2. DB Subnet Group (Required for RDS)
resource "aws_db_subnet_group" "default" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Postgres DB subnet group"
  }
}

# 3. Security Group
resource "aws_security_group" "rds_sg" {
  name        = "allow_postgresql"
  description = "Allow inbound traffic on port 5432"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Restricted to internal VPC traffic
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 4. PostgreSQL RDS Instance
resource "aws_db_instance" "postgres" {
  allocated_storage      = 20
  max_allocated_storage  = 100
  db_name                = "mydb"
  engine                 = "postgres"
  engine_version         = "15.4" # Or latest supported
  instance_class         = "db.t4g.large" # Graviton instance
  username               = "dbadmin"
  password               = "ChangeMe123!" # Use a secret manager in production
  parameter_group_name   = "default.postgres15"
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  skip_final_snapshot    = true
  publicly_accessible    = false

  tags = {
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

output "db_endpoint" {
  value = aws_db_instance.postgres.endpoint
}
```

