# Terraform configuration for a memory-optimized (minimal footprint) PostgreSQL RDS instance

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define the Parameter Group to override memory-heavy defaults
resource "aws_db_parameter_group" "low_memory_pg" {
  name   = "low-memory-postgres-config"
  family = "postgres15"

  # shared_buffers: Default is usually 25% of RAM. Reducing to ~128MB for minimal usage.
  parameter {
    name  = "shared_buffers"
    value = "16384" # Units are 8KB blocks. 16384 * 8KB = 128MB.
  }

  # work_mem: Memory used for internal sort operations. Reducing to 1MB per operation.
  parameter {
    name  = "work_mem"
    value = "1024" # KB
  }

  # maintenance_work_mem: Used for VACUUM, CREATE INDEX, etc.
  parameter {
    name  = "maintenance_work_mem"
    value = "32768" # 32MB
  }

  # max_connections: Every connection consumes RAM. Reducing to a small pool.
  parameter {
    name  = "max_connections"
    value = "20"
  }

  # autovacuum_max_workers: Reducing background workers to save process overhead.
  parameter {
    name  = "autovacuum_max_workers"
    value = "2"
  }

  # logical_decoding_work_mem: Minimum value to save memory during replication.
  parameter {
    name  = "logical_decoding_work_mem"
    value = "64" # KB
  }
}

# 2. Deploy the RDS instance using the optimized parameters
resource "aws_db_instance" "minimal_postgresql" {
  identifier           = "minimal-mem-db"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro" # Smallest available instance to match the requirement
  allocated_storage     = 20
  storage_type         = "gp3"
  username             = "adminuser"
  password             = "AvoidPlaintextPasswords123!" # Use secrets manager in production
  parameter_group_name = aws_db_parameter_group.low_memory_pg.name

  # Disable features that consume extra memory/CPU
  performance_insights_enabled = false
  monitoring_interval          = 0
  skip_final_snapshot          = true
  publicly_accessible          = false

  tags = {
    Name        = "MinimalMemoryPostgres"
    Environment = "Dev"
  }
}

output "db_endpoint" {
  value = aws_db_instance.minimal_postgresql.endpoint
}

response:
To set up a PostgreSQL configuration optimized for minimal memory usage, we focus on reducing buffers, workers, and connection overhead. In this example, I will use the **AWS RDS** provider as it is the most common way to manage PostgreSQL via Terraform. 

We will create a custom `aws_db_parameter_group` to tune the following parameters:
1.  **shared_buffers**: Reduced to a very low value (e.g., 64MB-128MB).
2.  **work_mem**: Lowered to limit memory per-sort/hash operation.
3.  **max_connections**: Lowered to reduce the memory overhead of connection processes.
4.  **maintenance_work_mem**: Reduced for background tasks.
5.  **Performance Insights**: Disabled to save monitoring overhead.

```hcl
# Terraform configuration for a memory-optimized (minimal footprint) PostgreSQL RDS instance

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Define the Parameter Group to override memory-heavy defaults
resource "aws_db_parameter_group" "low_memory_pg" {
  name   = "low-memory-postgres-config"
  family = "postgres15"

  # shared_buffers: Default is usually 25% of RAM. Reducing to ~128MB for minimal usage.
  parameter {
    name  = "shared_buffers"
    value = "16384" # Units are 8KB blocks. 16384 * 8KB = 128MB.
  }

  # work_mem: Memory used for internal sort operations. Reducing to 1MB per operation.
  parameter {
    name  = "work_mem"
    value = "1024" # KB
  }

  # maintenance_work_mem: Used for VACUUM, CREATE INDEX, etc.
  parameter {
    name  = "maintenance_work_mem"
    value = "32768" # 32MB
  }

  # max_connections: Every connection consumes RAM. Reducing to a small pool.
  parameter {
    name  = "max_connections"
    value = "20"
  }

  # autovacuum_max_workers: Reducing background workers to save process overhead.
  parameter {
    name  = "autovacuum_max_workers"
    value = "2"
  }

  # logical_decoding_work_mem: Minimum value to save memory during replication.
  parameter {
    name  = "logical_decoding_work_mem"
    value = "64" # KB
  }
}

# 2. Deploy the RDS instance using the optimized parameters
resource "aws_db_instance" "minimal_postgresql" {
  identifier           = "minimal-mem-db"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro" # Smallest available instance to match the requirement
  allocated_storage     = 20
  storage_type         = "gp3"
  username             = "adminuser"
  password             = "AvoidPlaintextPasswords123!" # Use secrets manager in production
  parameter_group_name = aws_db_parameter_group.low_memory_pg.name

  # Disable features that consume extra memory/CPU
  performance_insights_enabled = false
  monitoring_interval          = 0
  skip_final_snapshot          = true
  publicly_accessible          = false

  tags = {
    Name        = "MinimalMemoryPostgres"
    Environment = "Dev"
  }
}

output "db_endpoint" {
  value = aws_db_instance.minimal_postgresql.endpoint
}
```

