# Terraform configuration for Amazon RDS with gp3 storage

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Fetch the default VPC and Subnets for networking
resource "aws_default_vpc" "default" {}

resource "aws_default_subnet" "default_az1" {
  availability_zone = "us-east-1a"
}

resource "aws_default_subnet" "default_az2" {
  availability_zone = "us-east-1b"
}

# Database Subnet Group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_default_subnet.default_az1.id, aws_default_subnet.default_az2.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Security Group to allow inbound traffic (Defaulting to Port 5432 for Postgres)
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  vpc_id      = aws_default_vpc.default.id
  description = "Allow inbound traffic to RDS"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # NOTE: In production, restrict this to your IP/VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Instance with gp3 Storage
resource "aws_db_instance" "postgres_gp3" {
  identifier           = "mydb-instance"
  allocated_storage    = 20
  storage_type         = "gp3"        # Specifying GP3 storage
  engine               = "postgres"
  engine_version       = "15.3"
  instance_class       = "db.t4g.micro"
  db_name              = "mydb"
  username             = "dbadmin"
  password             = "Password123!" # In production, use Sensitive Variables or AWS Secrets Manager
  parameter_group_name = "default.postgres15"

  # Network & Security
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true         # Set to false for internal databases

  # Maintenance and Backups
  skip_final_snapshot     = true
  backup_retention_period = 7

  # gp3 specific setting: provisioned throughput (optional, default is 125 MiB/s)
  iops = 3000                           # Minimum IOPS for gp3 is 3000

  tags = {
    Environment = "Dev"
    StorageType = "gp3"
  }
}

output "db_endpoint" {
  value       = aws_db_instance.postgres_gp3.endpoint
  description = "The connection endpoint for the RDS instance"
}

response:
To set up a simple Amazon RDS instance using `gp3` storage, we need to define the VPC (or use the default), create a security group to allow traffic, and define the `aws_db_instance` resource with the `storage_type` attribute set to `"gp3"`.

```hcl
# Terraform configuration for Amazon RDS with gp3 storage

terraform {
  required_version = ">= 1.0.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Fetch the default VPC and Subnets for networking
resource "aws_default_vpc" "default" {}

resource "aws_default_subnet" "default_az1" {
  availability_zone = "us-east-1a"
}

resource "aws_default_subnet" "default_az2" {
  availability_zone = "us-east-1b"
}

# Database Subnet Group
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_default_subnet.default_az1.id, aws_default_subnet.default_az2.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Security Group to allow inbound traffic (Defaulting to Port 5432 for Postgres)
resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  vpc_id      = aws_default_vpc.default.id
  description = "Allow inbound traffic to RDS"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # NOTE: In production, restrict this to your IP/VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Instance with gp3 Storage
resource "aws_db_instance" "postgres_gp3" {
  identifier           = "mydb-instance"
  allocated_storage    = 20
  storage_type         = "gp3"        # Specifying GP3 storage
  engine               = "postgres"
  engine_version       = "15.3"
  instance_class       = "db.t4g.micro"
  db_name              = "mydb"
  username             = "dbadmin"
  password             = "Password123!" # In production, use Sensitive Variables or AWS Secrets Manager
  parameter_group_name = "default.postgres15"

  # Network & Security
  db_subnet_group_name   = aws_db_subnet_group.db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true         # Set to false for internal databases

  # Maintenance and Backups
  skip_final_snapshot     = true
  backup_retention_period = 7

  # gp3 specific setting: provisioned throughput (optional, default is 125 MiB/s)
  iops = 3000                           # Minimum IOPS for gp3 is 3000

  tags = {
    Environment = "Dev"
    StorageType = "gp3"
  }
}

output "db_endpoint" {
  value       = aws_db_instance.postgres_gp3.endpoint
  description = "The connection endpoint for the RDS instance"
}
```

