# Terraform configuration for an Amazon RDS instance with io1 storage

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a VPC and networking components for the RDS instance
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# RDS requires a DB Subnet Group spanning at least two Availability Zones
resource "aws_db_subnet_group" "main" {
  name       = "main-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]

  tags = {
    Name = "Main DB Subnet Group"
  }
}

# Security Group to allow database traffic
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

# Provision the RDS Instance with io1 storage
resource "aws_db_instance" "example" {
  identifier           = "example-io1-db"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.medium"

  # Storage Configuration for io1
  storage_type         = "io1"
  allocated_storage    = 100    # Minimum for io1 is often 100GB depending on engine
  iops                 = 1000   # Provisioned IOPS must be specified for io1

  db_name              = "mydb"
  username             = "dbadmin"
  password             = "Password123!" # In production, use secrets management (e.g. AWS Secrets Manager)

  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  skip_final_snapshot  = true
  publicly_accessible  = false

  tags = {
    Name = "ExampleIO1Instance"
  }
}

