# Provider configuration
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Create the S3 Bucket where the backup file resides
resource "aws_s3_bucket" "db_backup_bucket" {
  bucket = "my-db-restore-bucket-12345"
}

# 2. IAM Role to allow RDS to access S3
resource "aws_iam_role" "rds_s3_role" {
  name = "rds-s3-integration-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "rds_s3_policy" {
  name = "rds-s3-policy"
  role = aws_iam_role.rds_s3_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Effect   = "Allow"
        Resource = [
          aws_s3_bucket.db_backup_bucket.arn,
          "${aws_s3_bucket.db_backup_bucket.arn}/*"
        ]
      }
    ]
  })
}

# 3. DB Option Group to enable S3 Integration (Example: SQL Server)
resource "aws_db_option_group" "s3_option_group" {
  name                     = "sqlserver-s3-option-group"
  engine_name              = "sqlserver-ex"
  major_engine_version     = "15.00"

  option {
    option_name = "SQLSERVER_BACKUP_RESTORE"

    option_settings {
      name  = "IAM_ROLE_ARN"
      value = aws_iam_role.rds_s3_role.arn
    }
  }
}

# 4. RDS Instance linked to the Option Group
resource "aws_db_instance" "restored_db" {
  allocated_storage    = 20
  identifier           = "restored-db-instance"
  engine               = "sqlserver-ex"
  engine_version       = "15.00.4073.23.v1"
  instance_class       = "db.t3.micro"
  username             = "admin"
  password             = "SecurePassword123!" # Use a secret manager in production
  skip_final_snapshot  = true
  option_group_name    = aws_db_option_group.s3_option_group.name

  publicly_accessible  = false
}

# 5. Associate the IAM Role with the DB Instance (Required for S3 features)
resource "aws_db_instance_role_association" "example" {
  db_instance_identifier = aws_db_instance.restored_db.identifier
  feature_name           = "S3_INTEGRATION"
  role_arn               = aws_iam_role.rds_s3_role.arn
}

output "s3_bucket_name" {
  value = aws_s3_bucket.db_backup_bucket.id
}

output "rds_endpoint" {
  value = aws_db_instance.restored_db.endpoint
}

