# 5. Associate the IAM Role with the DB Instance (Required for S3 features)
resource "aws_db_instance_role_association" "example" {
  db_instance_identifier = aws_db_instance.restored_db.identifier
  feature_name           = "S3_INTEGRATION"
  role_arn               = aws_iam_role.rds_s3_role.arn
}

