# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the database
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "database-vpc"
  }
}

# Create Subnets in different AZs (RDS requires at least 2 for a subnet group)
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "My DB subnet group"
  }
}

# Security Group to allow database access
resource "aws_security_group" "db_sg" {
  name        = "allow_db_traffic"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

# RDS Instance with Automatic Storage Scaling
resource "aws_db_instance" "scaled_db" {
  identifier           = "autoscaling-db-instance"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  db_name              = "myappdb"
  username             = "admin"
  password             = "Password123!" # In production, use a secret manager or variable
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true

  # Storage Configuration
  allocated_storage     = 20    # Initial storage in GB

  # STORAGE AUTOSCALING: 
  # Setting this value enables storage autoscaling. 
  # Must be greater than or equal to allocated_storage.
  max_allocated_storage = 100   

  storage_type           = "gp2"
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]

  tags = {
    Environment = "production"
    Name        = "Autoscaling-Database"
  }
}

output "db_endpoint" {
  value = aws_db_instance.scaled_db.endpoint
}

response:
To set up an AWS RDS database with automatic storage scaling (Storage Autoscaling), we need to configure an `aws_db_instance` resource and specifically define the `max_allocated_storage` attribute. In Terraform, if `max_allocated_storage` is set to a value greater than `allocated_storage`, AWS will automatically scale the disk space as needed up to that limit.

The following configuration includes:
1.  A VPC and public subnets (simplified for the example).
2.  A DB subnet group.
3.  A Security Group allowing MySQL traffic.
4.  The RDS instance with **Storage Autoscaling** enabled.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the database
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  tags = {
    Name = "database-vpc"
  }
}

# Create Subnets in different AZs (RDS requires at least 2 for a subnet group)
resource "aws_subnet" "subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# DB Subnet Group
resource "aws_db_subnet_group" "default" {
  name       = "main-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_1.id, aws_subnet.subnet_2.id]

  tags = {
    Name = "My DB subnet group"
  }
}

# Security Group to allow database access
resource "aws_security_group" "db_sg" {
  name        = "allow_db_traffic"
  description = "Allow inbound traffic to RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }
}

# RDS Instance with Automatic Storage Scaling
resource "aws_db_instance" "scaled_db" {
  identifier           = "autoscaling-db-instance"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t3.micro"
  db_name              = "myappdb"
  username             = "admin"
  password             = "Password123!" # In production, use a secret manager or variable
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true

  # Storage Configuration
  allocated_storage     = 20    # Initial storage in GB

  # STORAGE AUTOSCALING: 
  # Setting this value enables storage autoscaling. 
  # Must be greater than or equal to allocated_storage.
  max_allocated_storage = 100   

  storage_type           = "gp2"
  db_subnet_group_name   = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.db_sg.id]

  tags = {
    Environment = "production"
    Name        = "Autoscaling-Database"
  }
}

output "db_endpoint" {
  value = aws_db_instance.scaled_db.endpoint
}
```

