  cidr_block = "10.0.0.0/16"
}

# Create a Subnet Group
resource "aws_db_subnet_group" "default" {
  name        = "main"
  subnet_ids = [aws_subnet.az1.id, aws_subnet.az2.id]

  tags = {
    Name = "My DB subnet group"
  }
}

resource "aws_subnet" "az1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "az2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

# Create the RDS Instance with Secrets Manager integration
resource "aws_db_instance" "default" {
  allocated_storage    = 20
  db_name              = "mydb"
  engine               = "postgres"
  engine_version       = "15"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  db_subnet_group_name = aws_db_subnet_group.default.name
  skip_final_snapshot  = true

  # This block enables AWS Secrets Manager to manage the password
  # Leaving it empty defaults to the "aws/secretsmanager" KMS key
  manage_master_user_password = true

  # Optional: Explicitly link to the default KMS key (though usually implicit)
