  tags = {
    Environment = "production"
  }
}

# Output the Secret ARN so you can find it in the AWS Console
output "db_secret_arn" {
  value       = aws_db_instance.default.master_user_secret[0].secret_arn
  description = "The ARN of the secret that holds the master user password"
}
