To set up an Amazon EFS (Elastic File System), we need to define the provider, the EFS resource itself, and optionally lifecycle policies or backup configurations. Below is the complete Terraform configuration to create an EFS file system with encryption enabled and custom tags.

```hcl
# Configure the AWS Provider
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Create a KMS key for EFS encryption
resource "aws_kms_key" "efs_key" {
  description             = "KMS key for EFS encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  tags = {
    Name        = "efs-encryption-key"
    Environment = "Dev"
  }
}

# Create the Amazon EFS File System
resource "aws_efs_file_system" "main" {
  creation_token = "my-efs-token"
  encrypted      = true
  kms_key_id     = aws_kms_key.efs_key.arn

  # Define the Performance and Throughput modes
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"

  # Lifecycle policy to transition files to Infrequent Access (IA) storage
  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  # Apply the requested tags
  tags = {
    Name        = "MainFileSystem"
    Project     = "TerraformAI-Demo"
    Environment = "Dev"
    ManagedBy   = "Terraform"
  }
}

# Output the File System ID and DNS Name
output "efs_id" {
  value       = aws_efs_file_system.main.id
  description = "The ID of the EFS File System"
}

output "efs_dns_name" {
  value       = aws_efs_file_system.main.dns_name
  description = "The DNS name of the EFS File System"
}
```

