To set up an AWS Elastic File System (EFS) with a lifecycle policy, we need to define the EFS resource itself and configure the `lifecycle_policy` block. This block allows for automatic data transition to the Infrequent Access (IA) storage class or Archive storage class to save costs.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Create a VPC for the EFS to reside in (Simplified example)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "efs-vpc"
  }
}

# Create a subnet
resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

# Create a Security Group for EFS to allow inbound NFS traffic
resource "aws_security_group" "efs_sg" {
  name        = "allow_nfs"
  description = "Allow NFS traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Define the AWS EFS File System
resource "aws_efs_file_system" "example_efs" {
  creation_token = "my-efs-token"
  encrypted      = true

  # Lifecycle policy to transition files to IA storage after 30 days of inactivity
  lifecycle_policy {
    transition_to_ia = "AFTER_30_DAYS"
  }

  # Lifecycle policy to transition files from IA back to primary storage on access
  lifecycle_policy {
    transition_to_primary_storage_class = "AFTER_1_ACCESS"
  }

  tags = {
    Name        = "MyEFSFileSystem"
    Environment = "Dev"
  }
}

# Create Mount Targets (one for each availability zone/subnet)
resource "aws_efs_mount_target" "mount_a" {
  file_system_id  = aws_efs_file_system.example_efs.id
  subnet_id       = aws_subnet.subnet_a.id
  security_groups = [aws_security_group.efs_sg.id]
}

# Output the DNS name of the EFS for mounting purposes
output "efs_dns_name" {
  value       = aws_efs_file_system.example_efs.dns_name
  description = "The DNS name of the EFS File System"
}
