# Configure the Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Create the EFS File System
resource "aws_efs_file_system" "main" {
  creation_token = "my-efs-token"
  encrypted      = true

  tags = {
    Name = "MySecureFileSystem"
  }
}

# 2. Define the Resource-Based Policy
# This policy enforces that all clients must use TLS to connect to the EFS
resource "aws_efs_file_system_policy" "policy" {
  file_system_id = aws_efs_file_system.main.id

  policy = jsonencode({
    Version = "2012-10-17"
    Id      = "EFSResourcePolicy"
    Statement = [
      {
        Sid    = "EnforceTLS"
        Effect = "Deny"
        Principal = {
          AWS = "*"
        }
        Action = "*"
        Resource = aws_efs_file_system.main.arn
        Condition = {
          Bool = {
            "aws:SecureTransport" = "false"
          }
        }
      },
      {
        Sid    = "AllowFullAccessToRoot"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite",
          "elasticfilesystem:ClientRootAccess"
        ]
        Resource = aws_efs_file_system.main.arn
      }
    ]
  })
}

# 3. Create Mount Targets (Optional but typical for usage)
# Note: This requires an existing VPC and Subnet
resource "aws_efs_mount_target" "mount" {
  file_system_id  = aws_efs_file_system.main.id
  subnet_id       = "subnet-12345678" # Replace with your actual subnet ID
  security_groups = ["sg-12345678"]  # Replace with your actual security group ID
}

# Outputs
output "efs_id" {
  value = aws_efs_file_system.main.id
}

output "efs_arn" {
  value = aws_efs_file_system.main.arn
}

