  encrypted      = true

  tags = {
    Name = "MyEFSFileSystem"
  }
}

# 2. Create a Security Group for the EFS Mount Target
# This allows inbound traffic on port 2049 (NFS)
resource "aws_security_group" "efs_sg" {
  name        = "efs-mount-sg"
  description = "Allow NFS traffic for EFS"
  vpc_id      = "vpc-xxxxxxxx" # Replace with your VPC ID

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Replace with your VPC CIDR or specific subnet CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# 3. Create the Mount Target
