response:
To create a dedicated-tenancy VPC with the specified features, we will define the AWS provider, a variable for resource naming, and then provision the VPC, Internet Gateway, and Route Table. We will also create a Route Table Association (though optional for the VPC itself, it's standard practice) and ensure the VPC attributes allow for DNS hostnames and resolution. 

Here is the complete Terraform configuration:

```hcl
# Define the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# Variable for resource tagging
variable "resource_name" {
  description = "The name to be used for tagging resources"
  type        = string
  default     = "dedicated-infra-hcl"
}

# 1. Create the VPC with dedicated tenancy and DNS support
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  instance_tenancy     = "dedicated"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = var.resource_name
  }
}

# 2. Create the Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "${var.resource_name}-igw"
  }
}

# 3. Create a Route Table for internet egress
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "${var.resource_name}-rt"
  }
}

# 4. (Optional) Main Route Table Association
# This ensures the VPC's main route table is the one we just created
resource "aws_main_route_table_association" "main_assoc" {
  vpc_id         = aws_vpc.main.id
  route_table_id = aws_route_table.public_rt.id
}

# Output the VPC ID for reference
output "vpc_id" {
  value = aws_vpc.main.id
}
```

