To set up an AWS VPC in the `us-east-2` region with the specified CIDR block and an Internet Gateway, we will follow these steps:
1.  **Provider Configuration**: Define the AWS provider and set the region to `us-east-2`.
2.  **VPC Resource**: Create the `aws_vpc` resource with the `10.0.0.0/16` CIDR block.
3.  **Internet Gateway Resource**: Create the `aws_internet_gateway` resource and associate it with the VPC created in the previous step.

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-2"
}

# Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Create the Internet Gateway and attach it to the VPC
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

# Output the VPC ID for reference
output "vpc_id" {
  value       = aws_vpc.main.id
  description = "The ID of the VPC"
}

# Output the Internet Gateway ID for reference
output "internet_gateway_id" {
  value       = aws_internet_gateway.gw.id
  description = "The ID of the Internet Gateway"
}
```

