provider "aws" {
  region = "us-east-1"
}

# 1. Create the VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Custom DHCP Options Set
resource "aws_vpc_dhcp_options" "windows_dhcp" {
  domain_name          = "windomain.local"
  domain_name_servers  = ["192.168.56.102", "8.8.8.8"]
  netbios_name_servers = ["192.168.56.102"]
  netbios_node_type    = 2

  tags = {
    Name = "windows-dhcp-options"
  }
}

# 3. Associate the DHCP Options Set with the VPC
resource "aws_vpc_dhcp_options_association" "dns_resolver" {
  vpc_id          = aws_vpc.main.id
  dhcp_options_id = aws_vpc_dhcp_options.windows_dhcp.id
}

# Output the VPC ID for reference
output "vpc_id" {
  value       = aws_vpc.main.id
  description = "The ID of the created VPC"
