}

variable "subnet_id" {
  description = "The Subnet ID in which to place the NAT Gateway (must be a public subnet)"
  type        = string
}

variable "tags" {
  description = "A map of tags to assign to the resource"
  type        = map(string)
  default = {
    Name        = "MainNATGateway"
    Environment = "Production"
  }
}

resource "aws_nat_gateway" "this" {
  # The Allocation ID of the Elastic IP address
  allocation_id = var.allocation_id

  # The Subnet ID of the subnet in which to place the gateway
  subnet_id     = var.subnet_id

  # Ensures the NAT Gateway is public (connectivity_type defaults to "public")
  connectivity_type = "public"

  tags = var.tags

  # Best practice: NAT Gateways rely on an Internet Gateway being present 
  # in the VPC to function. If managing the IGW in the same module, 
  # add a depends_on here.
}

output "nat_gateway_id" {
  description = "The ID of the NAT Gateway"
  value       = aws_nat_gateway.this.id
}

output "public_ip" {
  description = "The public IP address of the NAT Gateway"
  value       = aws_nat_gateway.this.public_ip
}

