# 4. Configure Peering Options to enable DNS resolution (shared network feel)
# Requester side (base)
resource "aws_vpc_peering_connection_options" "requester" {
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id

  requester {
    allow_remote_vpc_dns_resolution = true
  }
}

# Accepter side (peer)
resource "aws_vpc_peering_connection_options" "accepter" {
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id

  accepter {
    allow_remote_vpc_dns_resolution = true
  }
}

# Note: In a real-world scenario, you would also need to add routes 
# in the route tables of both VPCs pointing to the peering connection ID.

