To create a VPC peering connection between two AWS VPCs named "base" and "peer", we need to define the VPC resources, establish the peering connection, and configure the accepter/requester options to ensure seamless private communication.

Here is the complete Terraform configuration:

```hcl
# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"
}

# 1. Define the 'base' VPC
resource "aws_vpc" "base" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "base"
  }
}

# 2. Define the 'peer' VPC
resource "aws_vpc" "peer" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "peer"
  }
}

# 3. Create the VPC Peering Connection named 'pike'
resource "aws_vpc_peering_connection" "pike" {
  vpc_id        = aws_vpc.base.id
  peer_vpc_id   = aws_vpc.peer.id
  auto_accept   = true

  tags = {
    Name = "pike"
    pike = "permissions"
  }
}

# 4. Configure Peering Options to enable DNS resolution (shared network feel)
# Requester side (base)
resource "aws_vpc_peering_connection_options" "requester" {
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id

  requester {
    allow_remote_vpc_dns_resolution = true
  }
}

# Accepter side (peer)
resource "aws_vpc_peering_connection_options" "accepter" {
  vpc_peering_connection_id = aws_vpc_peering_connection.pike.id

  accepter {
    allow_remote_vpc_dns_resolution = true
  }
}

# Note: In a real-world scenario, you would also need to add routes 
# in the route tables of both VPCs pointing to the peering connection ID.
```

