# Terraform configuration to create an AWS Network ACL allowing all traffic

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# 1. Provide a VPC where the NACL will reside
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# 2. Create the Network ACL
resource "aws_network_acl" "allow_all" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "allow-all-nacl"
  }
}

# 3. Create Inbound Rule: Allow all traffic from any source
resource "aws_network_acl_rule" "inbound_allow_all" {
  network_acl_id = aws_network_acl.allow_all.id
  rule_number    = 100
  egress         = false
  protocol       = "-1" # -1 means all protocols
  rule_action    = "allow"
  cidr_block     = "0.0.0.0/0"
  from_port      = 0
  to_port        = 0
}

# 4. Create Outbound Rule: Allow all traffic to any destination
resource "aws_network_acl_rule" "outbound_allow_all" {
  network_acl_id = aws_network_acl.allow_all.id
  rule_number    = 100
  egress         = true
  protocol       = "-1" # -1 means all protocols
  rule_action    = "allow"
  cidr_block     = "0.0.0.0/0"
  from_port      = 0
  to_port        = 0
}

