    cidr_block = "0.0.0.0/0"
    from_port  = 80
    to_port    = 80
  }

  # Inbound Rule: Allow HTTPS (TCP 443)
  ingress {
    protocol   = "tcp"
    rule_no    = 110
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 443
    to_port    = 443
  }

  # Inbound Rule: Allow Ephemeral ports (TCP 1024-65535) 
  # Necessary for receiving responses to outbound requests
  ingress {
    protocol   = "tcp"
    rule_no    = 120
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 1024
    to_port    = 65535
  }

  # Outbound Rule: Allow all TCP traffic
  egress {
    protocol   = "tcp"
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 65535
  }

  tags = {
    Name = "main-nacl"
  }
}

# Output the VPC ID and NACL ID
output "vpc_id" {
  value = aws_vpc.main_vpc.id
}

output "nacl_id" {
  value = aws_network_acl.main_nacl.id
}

